-- Poems batch 348
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6ad34f32-bbba-4c10-aabe-7603ca25f717','夜風雨聲甚惡','晁說之','宋','宋诗','song-poetry','','[]','上元燈火胡塵裏，寒食田園野草生。',64,'全唐诗/poet.song.68000.json','["上元燈火胡塵裏，寒食田園野草生。", "文武墜來唯不寐，精神耗後更多情。", "片雲忽作幾日雨，衆恨添號半夜聲。", "從此無煩問春色，市無過客漫荒城。"]'),
('e316cf4e-0252-4b4e-b6bc-8881aff69cc3','海陵寒食','晁說之','宋','宋诗','song-poetry','','[]','忽逢羣盜到江津，驚若奔魚跳此身。',64,'全唐诗/poet.song.68000.json','["忽逢羣盜到江津，驚若奔魚跳此身。", "烟焰幾爲新節鬼，風塵敢憶故鄉人。", "幾家有物蒸嘗在，到處無時哭泣頻。", "日日凄風兼苦雨，要知寒食客愁真。"]'),
('8115c23a-9f46-4043-8256-5cacce5f6cd8','式微','晁說之','宋','宋诗','song-poetry','','[]','暮雲朝翼與心飛，白首何堪客子衣。',64,'全唐诗/poet.song.68000.json','["暮雲朝翼與心飛，白首何堪客子衣。", "潮去潮來無遠邇，江南江北有從違。", "廟堂慎用太平策，畎畝先知禍亂機。", "一唱式微腸九斷，微乎微乎我同歸。"]'),
('f58afa77-6aae-4959-b25e-f8b9dfb84857','高二承宣與蘇二左司唱和春雨詩遠蒙見寄依韻和之  其一','晁說之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','太乙池中艦，洞庭湖上篷。',24,'全唐诗/poet.song.68000.json','["太乙池中艦，洞庭湖上篷。", "問誰今得樂，宇宙釣絲中。"]'),
('418e5c8a-a1c3-4e69-8868-c9fc0bf71d2d','高二承宣與蘇二左司唱和春雨詩遠蒙見寄依韻和之  其二','晁說之','宋','宋诗','song-poetry','','[]','公子與王孫，何須更問耕。',24,'全唐诗/poet.song.68000.json','["公子與王孫，何須更問耕。", "春心爲花雨，梅杏尚難平。"]'),
('d24aacb6-c648-409e-9475-2299da641a5d','海陵閒居','晁說之','宋','宋诗','song-poetry','','[]','春色海邊雖到晚，幽居亦且得徘徊。',64,'全唐诗/poet.song.68000.json','["春色海邊雖到晚，幽居亦且得徘徊。", "風輕花影閒閒去，人静棋聲揭揭來。", "莫話艱難催白髮，從教顛倒長青苔。", "明朝此興如能在，夢到梁王舊吹臺。"]'),
('1f9b28f8-f8d2-42da-ae1f-44216f805ed7','泰州人自徐神翁後多以奉道爲事即今有周高唐三先生皆足以動衆得名因作長句','晁說之','宋','宋诗','song-poetry','','[]','沉沉方文與蓬萊，桃李聞從海上開。',64,'全唐诗/poet.song.68000.json','["沉沉方文與蓬萊，桃李聞從海上開。", "愁外烟波徒縹緲，夢中鄉俗獨徘徊。", "不同下俚暫時醉，自約高真定命盃。", "可笑神仙今古異，今言先分古先材。"]'),
('d699589d-ac75-4973-a702-bc8826daaa8d','三月二日大風','晁說之','宋','宋诗','song-poetry','','[]','數日寒暄不得常，一朝風伯擅乾綱。',64,'全唐诗/poet.song.68000.json','["數日寒暄不得常，一朝風伯擅乾綱。", "浪飄石去魚龍鬭，屋落瓦來雞犬藏。", "誰敢揚舲窺北渚，便當弭節奉東皇。", "穆如聲振中興業，萬國弦歌走未央。"]'),
('51766a70-be32-4e4f-93f2-7abcd50ba9a7','大風絕句二首  其一','晁說之','宋','宋诗','song-poetry','','[]','何事東風日又狂，後庭花要鬭新粧。',32,'全唐诗/poet.song.68000.json','["何事東風日又狂，後庭花要鬭新粧。", "中興功業在清浄，王謝清談未易忘。"]'),
('ba8d2f4b-1a44-425d-bcfb-1dc2cdaef26b','大風絕句二首  其二','晁說之','宋','宋诗','song-poetry','','[]','揚州桃葉能留客，任是東風江上狂。',32,'全唐诗/poet.song.68000.json','["揚州桃葉能留客，任是東風江上狂。", "南北人情亦相似，六軍不肯過咸陽。"]'),
('8883e52e-17bc-47fe-b321-bbc7b1d1e7dc','遠歎','晁說之','宋','宋诗','song-poetry','','[]','白髮飄零遠可嗟，百年居屋在京華。',32,'全唐诗/poet.song.68000.json','["白髮飄零遠可嗟，百年居屋在京華。", "海涯更比天涯遠，星斗沈沈入海涯。"]'),
('5a79ebc8-1b09-4b06-8a14-9257046bf148','奈我','晁說之','宋','宋诗','song-poetry','','[]','奈我所安何，無煩問所過。',48,'全唐诗/poet.song.68000.json','["奈我所安何，無煩問所過。", "潮聲雲外散，花色醉中多。", "京國昨宵夢，邊城幾日歌。", "功名悞男子，必使愧雲蘿。"]'),
('c3f60a43-0709-4ec2-bbff-c1bac029a3c8','題公震小景','晁說之','宋','宋诗','song-poetry','','[]','萬古興亡歸白鷺，一時舒慘在青山。',32,'全唐诗/poet.song.68000.json','["萬古興亡歸白鷺，一時舒慘在青山。", "與君都下太平日，豈料思君鼙鼓間。"]'),
('07c776ad-f24d-49b0-9b8e-813ca9d21c0f','四顧','晁說之','宋','宋诗','song-poetry','','[]','四顧荒荒孰我容，百爲深省亦何從。',64,'全唐诗/poet.song.68000.json','["四顧荒荒孰我容，百爲深省亦何從。", "江山風雨愁皆滿，天地波濤恨未窮。", "寧使衰容添白髮，難将世態入青嵩。", "飄然已作東游計，康樂繙經待厥終。"]'),
('88bd682e-640e-4919-bdf3-66ba6345915f','懷舊','晁說之','宋','宋诗','song-poetry','','[]','伊昔升平事，中州見最先。',48,'全唐诗/poet.song.68000.json','["伊昔升平事，中州見最先。", "洛花凝曉月，鞏樹靄寒烟。", "相業歸貂寵，胡塵溺漢天。", "幾多垂白叟，涕淚日潸然。"]'),
('6d8beb76-288f-4125-9787-7c8b46126de7','贈京師少年在海陵者','晁說之','宋','宋诗','song-poetry','','[]','夷門子弟逞豪華，不忿西京穀雨花。',32,'全唐诗/poet.song.68000.json','["夷門子弟逞豪華，不忿西京穀雨花。", "走馬城東玉仙醉，着身海角敢咨嗟。"]'),
('369fb5fa-d496-4f73-a857-d44166e9cc62','海陵書事','晁說之','宋','宋诗','song-poetry','','[]','今古悠悠嘉上同，徒令客子恨無窮。',64,'全唐诗/poet.song.68000.json','["今古悠悠嘉上同，徒令客子恨無窮。", "竹椽泥壓清虚節，葦爨香殊忠厚風。", "騰倚百年麋鹿外，波瀾一日鳯皇中。", "可憐仙馭頻來往，從此相傳第幾翁。"]'),
('5f53cc1d-cbf7-455c-9902-a95ad3766556','愁','晁說之','宋','宋诗','song-poetry','','[]','揚州枉矢何時弭，涿野蚩尤尚未俘。',32,'全唐诗/poet.song.68000.json','["揚州枉矢何時弭，涿野蚩尤尚未俘。", "底處愁城能著我，風爲愁騎雨愁車。"]'),
('5773ced4-37c4-4d4f-92c8-8033827479c0','高二承宣以長句餉新茶輒次韻爲謝  其一','晁說之','宋','宋诗','song-poetry','','[]','春風伴我到僧家，嘆息無名供佛花。',64,'全唐诗/poet.song.68000.json','["春風伴我到僧家，嘆息無名供佛花。", "劉子枕糟非枕酒，陸生論水不論茶。", "少多何必求玄鵠，一二唯當較白沙。", "更恨老年難得睡，因君茗粥恨無涯。"]'),
('259c8afa-5d42-4732-8227-35e3cab2d63b','高二承宣以長句餉新茶輒次韻爲謝  其二','晁說之','宋','宋诗','song-poetry','','[]','信美江山非我家，興亡忍問後庭花。',64,'全唐诗/poet.song.68000.json','["信美江山非我家，興亡忍問後庭花。", "明時不見來求女，儉德唯聞罷貢茶。", "鷁首千重能破浪，馬蹄萬里正便沙。", "煩君識取人才盡，白首飄零漫海涯。"]'),
('9919481c-6949-4752-a41b-f670aa1b6cc4','爲客','晁說之','宋','宋诗','song-poetry','','[]','爲客淮南望上京，祥烟不遠恨峥嶸。',64,'全唐诗/poet.song.68000.json','["爲客淮南望上京，祥烟不遠恨峥嶸。", "居人避濕開門晚，宿鳥眠寒擇木驚。", "波浪無時潮失信，關河有盜夢非情。", "不知歸計何從得，碧潁青嵩畫未成。"]'),
('a817cee3-8103-44d8-979c-0a0f68e01a44','感舊','晁說之','宋','宋诗','song-poetry','','[]','田園幾畝豆苗新，卒歲閒居百慮真。',64,'全唐诗/poet.song.68000.json','["田園幾畝豆苗新，卒歲閒居百慮真。", "不日頻逢中酒客，何時曾禁折花人。", "誰誇玉帛奔侯服，自喜樵蘇入帝闉。", "回首龍蛇紛起陸，却垂涕淚問胡塵。"]'),
('9e1e50b7-627e-42c6-a636-919be38dc0de','謝徐師川寄江茶四小瓶','晁說之','宋','宋诗','song-poetry','','[]','舉世卑陬鬭小車，若人何處逞豪華。',64,'全唐诗/poet.song.68000.json','["舉世卑陬鬭小車，若人何處逞豪華。", "夢魂恨着後庭樹，詩句清餘雙井茶。", "默默嘲雄舒錦綉，申申罵屈雜龍虵。", "不煩更籍韋弦力，望出河東性不奢。"]'),
('e5d8a9f6-e6b5-4d9a-abc1-9208dcc8946d','依韻和高二承宣歙墨長句','晁說之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','妙句之來墨妙同，信知吾道未全窮。',64,'全唐诗/poet.song.68000.json','["妙句之來墨妙同，信知吾道未全窮。", "豈容短棹千年恨，不貯長江五月風。", "眷戀孔鸞嗟嘆外，磨研膠漆笑歌中。", "爲予留取滄浪道，使挈兒童學釣翁。"]'),
('342e2faf-3ef2-4ceb-81fb-813fccf91952','池頭','晁說之','宋','宋诗','song-poetry','','[]','長夏悠悠百計非，可憐北客製南衣。',32,'全唐诗/poet.song.68000.json','["長夏悠悠百計非，可憐北客製南衣。", "池頭風晚萍根合，何處楊花不得歸。"]'),
('858cf8a5-3a7c-410b-b33d-b11a082d6f79','視藴文','晁說之','宋','宋诗','song-poetry','','[]','飄零海角悟平生，豈料王孫肯遠行。',64,'全唐诗/poet.song.68000.json','["飄零海角悟平生，豈料王孫肯遠行。", "遲日待君游化國，淒風要我到愁城。", "詩書灰燼寧無夢，翰墨馨香尚有情。", "聞道東京已返蹕，箕雲緱月得秋耕。"]'),
('926656c7-064c-4ce0-82ce-ba3afe9c65cf','觀逋翁執花曲作','晁說之','宋','宋诗','song-poetry','','[]','萬國歸隨盡細侯，阿𡡉只解愛揚州。',32,'全唐诗/poet.song.68000.json','["萬國歸隨盡細侯，阿𡡉只解愛揚州。", "錦帆明日知何處，不得龍門洛水游。"]'),
('c311c536-0ad8-435b-be96-53c6bce43139','次韻師川郎中寄墨長句','晁說之','宋','宋诗','song-poetry','','[]','人人垂首相公前，獨子低眉古簡編。',64,'全唐诗/poet.song.68000.json','["人人垂首相公前，獨子低眉古簡編。", "江上新吟何慷慨，世間舊恨細窮研。", "故知小子能封國，亦信長人解說天。", "寄墨虞卿著書喜，不教茶到恐妨眠。"]'),
('c815972a-9411-411c-b200-6c5287671fc5','夜坐','晁說之','宋','宋诗','song-poetry','','[]','氛濁暑伏嘆，夜久神宇清。',48,'全唐诗/poet.song.68000.json','["氛濁暑伏嘆，夜久神宇清。", "魚躍遠池響，螢飛深竹明。", "揚州妙歌舞，駐蹕盛公卿。", "植杖看牛斗，今年當太平。"]'),
('46869059-6742-4008-84d5-1432720d13f5','日暮池上','晁說之','宋','宋诗','song-poetry','','[]','客子難爲夏，池塘眼暫開。',48,'全唐诗/poet.song.68000.json','["客子難爲夏，池塘眼暫開。", "蓮房隨月倚，萍陣信風來。", "自喜親茶杓，無煩問酒杯。", "故人行在樂，獻納有雲臺。"]'),
('4f42fb59-b200-4ba1-a67f-215560a504ae','秋嘆','晁說之','宋','宋诗','song-poetry','','[]','爲起秋風有所懷，江頭秋色信多哉。',64,'全唐诗/poet.song.68000.json','["爲起秋風有所懷，江頭秋色信多哉。", "孔明何歲荆州去，樂毅即時燕國來。", "今古悠悠共涕淚，江山寂寂盡塵埃。", "麒麟閣上功名士，聞道其中有不才。"]'),
('05d8fe4e-1df8-4db9-9a51-c04b0b108152','閒居','晁說之','宋','宋诗','song-poetry','','[]','閒居豈無事，一動百艱難。',48,'全唐诗/poet.song.68000.json','["閒居豈無事，一動百艱難。", "水爲齋僧惜，花因供佛殘。", "喜聞多死士，厭話小長安。", "香火同緣客，饑腸先永嘆。"]'),
('9206abf7-96fa-42c2-a5ba-1a1d70762060','何意','晁說之','宋','宋诗','song-poetry','','[]','何意此閒居，逋亡且漫如。',48,'全唐诗/poet.song.68000.json','["何意此閒居，逋亡且漫如。", "日高雞在樹，風静鴈抛蘆。", "雨露傳新令，兒童說故都。", "秋光金甲上，幾日正王誅。"]'),
('e0672ef3-e1fc-451d-9c01-18b997311ff5','立秋前六言','晁說之','宋','宋诗','song-poetry','','[]','今日自須欣喜，明朝池上秋風。',28,'全唐诗/poet.song.68000.json','["今日自須欣喜，明朝池上秋風。", "聽雨如聽古樂，得書似得良朋。"]'),
('f7b3560d-af45-416b-b9c1-367b9cecb32d','感時二首  其一','晁說之','宋','宋诗','song-poetry','','[]','衣冠迷魯衛，食飲歎荆揚。',48,'全唐诗/poet.song.68000.json','["衣冠迷魯衛，食飲歎荆揚。", "夜雨思鄉近，秋風客夢長。", "莫言遊帝所，要且狩河陽。", "丞相如求士，當求張子房。"]'),
('515e5106-ceed-4988-94cd-b086deb95539','感時二首  其二','晁說之','宋','宋诗','song-poetry','','[]','黄埃迷馬市，白帝問魚梁。',48,'全唐诗/poet.song.68000.json','["黄埃迷馬市，白帝問魚梁。", "松竹秋聲早，江湖客夢長。", "易衣欺賊眼，辟穀信仙方。", "尚有叩閽志，其如病在床。"]'),
('1b582cd3-96b3-4f14-82b6-4d285fa6a735','三歲','晁說之','宋','宋诗','song-poetry','','[]','羈離已三歲，幾處幸容身。',48,'全唐诗/poet.song.68000.json','["羈離已三歲，幾處幸容身。", "有夢延秋雨，無言問戰塵。", "傷今多難日，憶我太平人。", "雨露隨行在，公卿幾番新。"]'),
('ca809abd-1616-467f-9317-50654883c2fe','予筆多葦管近又得竹筆匣因作絕句','晁說之','宋','宋诗','song-poetry','','[]','竹匳葦管可幽居，前日曾藏萬卷書。',32,'全唐诗/poet.song.68000.json','["竹匳葦管可幽居，前日曾藏萬卷書。", "烽火不知南北渡，祝兹微物莫愁予。"]'),
('fa27e9c3-b8e2-4ac4-a499-47f254e2c978','欲爲金陵之行而未果','晁說之','宋','宋诗','song-poetry','','[]','舊有山川舊夕陽，新秋新淚兩茫茫。',64,'全唐诗/poet.song.68000.json','["舊有山川舊夕陽，新秋新淚兩茫茫。", "金陵王氣知何在，玉樹後庭聞已芳。", "情到義山能發問，事經小杜亦多傷。", "未須便作揚舲計，即見元戎浄八荒。"]'),
('a7917665-7970-404b-b6cb-c4a1b3ae953e','秋感','晁說之','宋','宋诗','song-poetry','','[]','又作此秋飄泊客，茫茫誰是北歸人。',64,'全唐诗/poet.song.68000.json','["又作此秋飄泊客，茫茫誰是北歸人。", "庭前雨過鵝羣浴，池上風來螢火新。", "戰馬不肥淮甸草，屬車思輾洛陽塵。", "如聞胡虜渡河去，緱月箕雲待老身。"]'),
('f856dbb7-7b47-40ee-91fa-0fadab5f89c7','海陵聞角','晁說之','宋','宋诗','song-poetry','','[]','秋風入角蹙山城，更覺淮南秋思清。',32,'全唐诗/poet.song.68000.json','["秋風入角蹙山城，更覺淮南秋思清。", "慣聽邊威雷鼓裏，梅花争發斗峥嶸。"]'),
('eb2af945-6354-4108-ab6b-0b86a092b12e','簡沙頭李山伯','晁說之','宋','宋诗','song-poetry','','[]','坎離交養日需沙，君向沙頭好泊家。',32,'全唐诗/poet.song.68000.json','["坎離交養日需沙，君向沙頭好泊家。", "鷗鷺若來尋舊隱，爲言直上有烟霞。"]'),
('cb4b15b3-da34-4de8-a7dc-d7b7f56cc546','行藏','晁說之','宋','宋诗','song-poetry','','[]','行藏本自迷，秋興更淒淒。',48,'全唐诗/poet.song.68000.json','["行藏本自迷，秋興更淒淒。", "風急蛩饒響，雨來雞誤啼。", "魚溪青靄散，蓮蕩白雲齊。", "却惜安閒地，逋亡志願暌。"]'),
('5827a2e0-ee36-4678-ab06-f7caa09ba4b7','聞富季申遷校書郎','晁說之','宋','宋诗','song-poetry','','[]','小富秋來慰所望，青衫敘進校書郎。',64,'全唐诗/poet.song.68000.json','["小富秋來慰所望，青衫敘進校書郎。", "相公勳業久彌著，孫子門闌漸有光。", "莫話詩過已埋沒，且非椀脱得分張。", "白蓮逋客獨惆悵，涙盡西風歸政堂。"]'),
('d5684013-cc78-4f72-b9fb-0c80ed3a3271','次韻和中遠以予真州江上遭巨寇脱身感事作','晁說之','宋','宋诗','song-poetry','','[]','一世高梧丹葉翻，男昏女嫁失前村。',64,'全唐诗/poet.song.68000.json','["一世高梧丹葉翻，男昏女嫁失前村。", "但聞狼虎厭人肉，不見酒漿招鬼魂。", "久分彼天難叩問，未甘此道漫追原。", "江心火雜魚龍血，我脱身來君莫論。"]'),
('62aec36a-7842-400f-ab89-7a7b26b89aaa','寄題鎮江寶墨堂','晁說之','宋','宋诗','song-poetry','','[]','常潤特令賜吳楚，從兹錢氏政相宜。',64,'全唐诗/poet.song.68000.json','["常潤特令賜吳楚，從兹錢氏政相宜。", "江山閲世無今古，金石何年有合離。", "小諫縱歌文史外，侍郎決策甲兵期。", "只尋舊墨題新榜，念爾邦人肯擾之。"]'),
('fb3d2ed4-318b-4cdb-a398-4e071c8cc076','新愁','晁說之','宋','宋诗','song-poetry','','[]','宿恨故難遣，新愁豈易安。',48,'全唐诗/poet.song.68000.json','["宿恨故難遣，新愁豈易安。", "囷空鼠號擲，庭静鳥喑寒。", "月盛中秋色，人虧上國歡。", "灣頭十二衛，泣涕乞回鑾。"]'),
('e3c31a0b-c4fc-406c-a94a-df7db6abe190','眠睡','晁說之','宋','宋诗','song-poetry','','[]','病夫不睡情須怨，老子難眠思却清。',32,'全唐诗/poet.song.68000.json','["病夫不睡情須怨，老子難眠思却清。", "況復斗横催角引，梅花爛漫散秋聲。"]'),
('3c300814-8b35-4319-a8ee-0bba449dfe93','自適','晁說之','宋','宋诗','song-poetry','','[]','避難三年百感生，衆雖溷濁自澄清。',64,'全唐诗/poet.song.68000.json','["避難三年百感生，衆雖溷濁自澄清。", "閒窺鳥雀往來勢，静聽兒童讀誦聲。", "但道孤生元廢棄，莫言頻數論平生。", "大河今歲如爲用，即看千官赴上京。"]'),
('416824b2-eeff-49bf-9f89-e977e8e78df1','故資政殿學士特贈光禄大夫曾公挽辭二首  其一','晁說之','宋','宋诗','song-poetry','','[]','選吏時無最，論兵世有書。',48,'全唐诗/poet.song.68000.json','["選吏時無最，論兵世有書。", "風神相門舊，膽氣将壇初。", "地軸塵埃轉，天航津漢虚。", "忠規子孫在，太史筆何如。"]'),
('d6145627-386f-42e9-a250-7b25e124a803','故資政殿學士特贈光禄大夫曾公挽辭二首  其二','晁說之','宋','宋诗','song-poetry','','[]','馬援枕前嘆，張飛帳下怨。',48,'全唐诗/poet.song.68000.json','["馬援枕前嘆，張飛帳下怨。", "古人有餘淚，今日不堪言。", "犬豕方逃格，璵璠忽自焚。", "共嗟當宁恨，寧復問乾坤。"]'),
('65bd355f-6990-4f80-89b6-8e48e78cb970','久客','晁說之','宋','宋诗','song-poetry','','[]','客子能久慣，将何號有生。',48,'全唐诗/poet.song.68000.json','["客子能久慣，将何號有生。", "墨池能入用，紙被喜無聲。", "新月生緱嶺，淒風過渭城。", "忽如無所嘆，却似太忘情。"]'),
('26a3e77c-118d-444a-a87d-aaa1535c3315','幽齋','晁說之','宋','宋诗','song-poetry','','[]','幽齋無客自焚香，古像誰知静放光。',64,'全唐诗/poet.song.68000.json','["幽齋無客自焚香，古像誰知静放光。", "秋色深來人寂寞，鴈聲斷處月荒涼。", "病軀如似小損可，賊勢流傳大獗張。", "可笑韓公憂有分，人言憂責屬巖廊。"]'),
('a50586a0-da6a-4bf0-9464-22aff8babba6','愁闌','晁說之','宋','宋诗','song-poetry','','[]','淮南初客初嘗起，久客淮南愁亦闌。',64,'全唐诗/poet.song.68000.json','["淮南初客初嘗起，久客淮南愁亦闌。", "秋夜無聞喜風雨，柴門自掩醉江山。", "詩書不讀談常到，香火如勞意更閒。", "北望歸期殊未可，却思南渡滄浪間。"]'),
('b2b895e3-3aa4-4e17-bfad-a681ef828701','鄭州古有夕陽樓自唐末兵火後遂廢況今圃田殘破客中望揚州作絕句','晁說之','宋','宋诗','song-poetry','','[]','日月争流淚亦流，幾年不見夕陽樓。',32,'全唐诗/poet.song.68000.json','["日月争流淚亦流，幾年不見夕陽樓。", "太平時節古來少，却上迷樓一望休。"]'),
('3a6bf751-dcd4-491b-ab0f-4f639f26e5ec','将出江絕句','晁說之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','脩門縹緲夢悠悠，歲暮長江斗柄浮。',32,'全唐诗/poet.song.68000.json','["脩門縹緲夢悠悠，歲暮長江斗柄浮。", "奮翼鳴雞急自和，白頭鼓枻爲誰愁。"]'),
('50557dfc-42a2-49ef-b851-834eb296743c','司戶朱君邂逅真州獨爲予幹舳艫之具甚勤偶得絕句謝之','晁說之','宋','宋诗','song-poetry','','[]','白眼波濤争反覆，波心孤棹更誰看。',32,'全唐诗/poet.song.68000.json','["白眼波濤争反覆，波心孤棹更誰看。", "夫君念此客蓬鬢，不共青松共歲寒。"]'),
('39dc1c89-7973-4619-acb6-1f6e40c110d8','再遇筆屠處士','晁說之','宋','宋诗','song-poetry','','[]','江頭再遇筆屠生，共聽去年江水聲。',32,'全唐诗/poet.song.68000.json','["江頭再遇筆屠生，共聽去年江水聲。", "三副少多予自窘，一毫去取子能輕。"]'),
('260de4a7-b20e-4604-b644-17fc17eb32e6','藥裹','晁說之','宋','宋诗','song-poetry','','[]','藥裹白頭翁，孜孜離亂中。',48,'全唐诗/poet.song.68000.json','["藥裹白頭翁，孜孜離亂中。", "道從前日證，愁與昔年空。", "食足思同飽，時危恥自容。", "願将經濟策，上疏大明宮。"]'),
('45021673-6dd6-4df0-acbb-f400b8020534','月下渡金陵江','晁說之','宋','宋诗','song-poetry','','[]','玉樹開花媚綺窗，龍幡如植冕旒降。',32,'全唐诗/poet.song.68000.json','["玉樹開花媚綺窗，龍幡如植冕旒降。", "只今江月交光夜，情似月明愁似江。"]'),
('8234b471-ce84-4c36-9192-f2c4f024122b','飄流','晁說之','宋','宋诗','song-poetry','','[]','飄流北客江之左，自問行藏語亦難。',64,'全唐诗/poet.song.68000.json','["飄流北客江之左，自問行藏語亦難。", "江上即今無盜賊，浪中何日不風寒。", "曹潘鼙鼓於茲見，王謝風流何處看。", "歸客不知朱雀好，但誇明月洛南灣。"]'),
('3215bd4f-a66a-434a-8d0b-406dfcc8bfaa','歲暮六言','晁說之','宋','宋诗','song-poetry','','[]','臘尾豈堪北去，年頭又怯東奔。',28,'全唐诗/poet.song.68000.json','["臘尾豈堪北去，年頭又怯東奔。", "萍梗往來覆載，燕雀俯仰乾坤。"]'),
('1179b903-0a97-4d47-b866-08204e68675b','金陵二首  其一','晁說之','宋','宋诗','song-poetry','','[]','金陵形勢眼中見，一弔興亡夢寐間。',64,'全唐诗/poet.song.68000.json','["金陵形勢眼中見，一弔興亡夢寐間。", "侯景長驅走龍虎，王敦內叛壓江山。", "中原有主申明命，下國何人敢肆姦。", "白首自傷歸未得，此身何處得清閒。"]'),
('7e5a9d05-cf03-4396-ac48-99433b7c6dac','金陵二首  其二','晁說之','宋','宋诗','song-poetry','','[]','上帝於人靡有常，江流何處任興亡。',64,'全唐诗/poet.song.68000.json','["上帝於人靡有常，江流何處任興亡。", "干戈揖遜一錫杖，社稷山川半面粧。", "故自無人比叔子，尚憐有意保襄陽。", "白頭難待太平策，萬國明朝建治康。"]'),
('cae6d3cb-9478-4914-ad1d-92efa8924454','江南','晁說之','宋','宋诗','song-poetry','','[]','一家天下莫分三，天極明星萬象含。',32,'全唐诗/poet.song.68000.json','["一家天下莫分三，天極明星萬象含。", "此水北江歸海處，誰将此地號江南。"]'),
('3045986f-b5e3-4364-8615-2ef45783d509','歲暮聞武泰節使将歸金陵','晁說之','宋','宋诗','song-poetry','','[]','歲暮江頭鳬鴈身，悠悠心事竟誰親。',64,'全唐诗/poet.song.68000.json','["歲暮江頭鳬鴈身，悠悠心事竟誰親。", "久能收拾內朝僕，始作生疏外道人。", "欲問江吳借風色，恐於河伯廢精神。", "王孫旌節歸來好，莫使王孫恨更新。"]'),
('f3f88f18-bd90-471e-b705-1d907a36bf4b','武泰節使歸金陵','晁說之','宋','宋诗','song-poetry','','[]','戟影搖寒波影稀，王孫心事與人違。',64,'全唐诗/poet.song.68000.json','["戟影搖寒波影稀，王孫心事與人違。", "燈邊赤軸得居士，窗下清談見布衣。", "執玉詔從天上去，揮金船向歲前歸。", "尫羸不解少行樂，卧待公來起採薇。"]'),
('39bdbb69-bdfa-48e0-a8f5-e04f5aad79c3','歲暮','晁說之','宋','宋诗','song-poetry','','[]','客舍光陰白髮催，高援北斗夢徘徊。',64,'全唐诗/poet.song.68000.json','["客舍光陰白髮催，高援北斗夢徘徊。", "多愁須用枕雙疊，無問何須酒一杯。", "風去六朝迷遠樹，雲來一日忍新梅。", "即今盜賊須擒馘，牧守不逃言壮哉。"]'),
('f258630a-2894-4d17-a275-285bd74a9648','覧古','晁說之','宋','宋诗','song-poetry','','[]','遙岑不娛人，蒼莽頗愁絕。',96,'全唐诗/poet.song.68000.json','["遙岑不娛人，蒼莽頗愁絕。", "東南有斷梁，水寒不可涉。", "西闉不欲往，旦暮畏喋褻。", "歸來坐北堂，悠然理書策。", "之人阿堵中，雖死情不隔。", "周公徂東山，仲尼陳蔡厄。", "大儒且不遇，小子何足責。", "時命姑置之，何爲常促迫。"]'),
('ebcc98f8-6db6-4074-8a9c-f46a7a8cbbb1','謝沈次律水枕','晁說之','宋','宋诗','song-poetry','','[]','沈侯筆力鼎可扛，左手截取吳淞江。',112,'全唐诗/poet.song.68000.json','["沈侯筆力鼎可扛，左手截取吳淞江。", "折流來此一尺枕，指麾巨鰐回濤瀧。", "平生性不好長物，舉以遺我嗟無雙。", "呼兒快取蘄笛簟，掃除塵榻移當窗。", "隨眠置我丘壑裏，始信孫郎真枕水。", "我生不出長安城，四十二年塵況耳。", "領君此枕何瀟然，睡起醒心如一洗。"]'),
('4a84eb4d-c46a-497b-b41f-05d72420b93d','和新鄉二十一弟華嚴水亭二首  其一','晁說之','宋','宋诗','song-poetry','','[]','渚蒲淅淅風猶急，岸柳纖纖雨尚餘。',32,'全唐诗/poet.song.68000.json','["渚蒲淅淅風猶急，岸柳纖纖雨尚餘。", "棲鷺宿鷗渾去盡，泝溪還有兩三魚。"]'),
('1e85f017-6b08-47ca-84bf-94bcd1030a1a','和新鄉二十一弟華嚴水亭二首  其二','晁說之','宋','宋诗','song-poetry','','[]','荷蓋點溪三數葉，藤稍遶樹幾千層。',32,'全唐诗/poet.song.68000.json','["荷蓋點溪三數葉，藤稍遶樹幾千層。", "投閒更與高人約，重抱琴來聽廣陵。"]'),
('e3be1a16-a3ce-4dde-b468-b367276e4dd3','次韻王立之雪中以酒見餉','晁說之','宋','宋诗','song-poetry','','[]','同雲慘慘驅朝暄，龍沙一雪人相憐。',160,'全唐诗/poet.song.68000.json','["同雲慘慘驅朝暄，龍沙一雪人相憐。", "寒猿哀嘯失山木，饑鶴仰唳空無天。", "當年補天真戲爾，不知修月何時已。", "坐煩耆舊說辛卯，至遣兒童憂甲子。", "城中米價貴如玉，舉家倒廪無斗粟。", "千金狐裘豈易得，百結鶉衣不堪鬻。", "我生但識茅與菅，何曾過眼逢瑤璠。", "展君新詩問所似，欲辯不敢非忘言。", "開壺酌酒澆我胸，酒酣起舞顔爲紅。", "會見東風掃冰雪，江梅塞桞煩春工。"]'),
('9f1d3ad3-ab95-4525-b8b8-ecaec5b08506','次二十一兄九日韻','晁說之','宋','宋诗','song-poetry','','[]','清秋九日至，晚菊兩三開。',48,'全唐诗/poet.song.68000.json','["清秋九日至，晚菊兩三開。", "愁把他鄉酒，思登故國臺。", "賜懷朝士寵，詩想從臣才。", "向晚能無淚，飄飄鴈影來。"]'),
('f5a47ea6-2836-4aa3-9f1d-ecd328faaa96','懷濟北弟姪','晁說之','宋','宋诗','song-poetry','','[]','久客思吾子，生涯滯故鄉。',48,'全唐诗/poet.song.68000.json','["久客思吾子，生涯滯故鄉。", "獨攜高士傳，翻憶紫香囊。", "合榻言猶在，同堂樂未央。", "翩翩春草夢，隨意遶池塘。"]'),
('81db3f0d-3a3c-4b82-8df1-c79b816a7df3','題韋偃雙松老僧圖','晁說之','宋','宋诗','song-poetry','','[]','兩松鬰蒼蒼，夭矯出奇峭。',60,'全唐诗/poet.song.68000.json','["兩松鬰蒼蒼，夭矯出奇峭。", "翛然龍蛇姿，勢欲排巖嶠。", "老禪獨會心，默坐觀萬竅。", "我亦發深省，倚檻一長嘯。", "此興含千古，孰謂韋偃少。"]'),
('3401707f-741c-4906-b9a1-612a78147f5d','和呂希哲','晁說之','宋','宋诗','song-poetry','','[]','渭濱人老釣綸中，晚達那知有早窮。',32,'全唐诗/poet.song.68000.json','["渭濱人老釣綸中，晚達那知有早窮。", "顧我巖栖終作底，謾將病目送飛鴻。"]'),
('8494f799-27ef-406d-b396-852609dbb9ed','別後寄東萊公','晁說之','宋','宋诗','song-poetry','','[]','鳳老不行食，子復將衆雛。',132,'全唐诗/poet.song.68000.json','["鳳老不行食，子復將衆雛。", "一門三世行，名數文章俱。", "自可不富貴，天德公已餘。", "公乎默終日，誰言得親疏。", "人間亦何事，前賢重作書。", "公豈不窮愁，聊爲筆墨娛。", "掩卷長嘆息，曷不巖廊與。", "卻慚小人計，不當君子君。", "可恨空江水，潮生明月初。", "捩柁讋北客，別去敢踟躕。", "回首望丹穴，涕泫日漣如。"]'),
('41ce0de5-f97a-4f34-aa94-5b4c9127f617','聞叔易隱居被詔','晁說之','宋','宋诗','song-poetry','','[]','東海一生垂釣客，石渠萬卷校書郎。',32,'全唐诗/poet.song.68000.json','["東海一生垂釣客，石渠萬卷校書郎。", "丈人風味今如此，鶴到揚州興更長。"]'),
('e13ecbfe-6389-4969-887f-88a50ae0ebbd','詩一首','晁說之','宋','宋诗','song-poetry','','[]','泗濱浮石豈不好，怊悵上方承眷時。',32,'全唐诗/poet.song.68000.json','["泗濱浮石豈不好，怊悵上方承眷時。", "今日道傍誰著眼，女牆猶得擲胡兒。"]'),
('67587899-19d8-481e-ba49-e64904574c58','贈張彧','晁說之','宋','宋诗','song-poetry','','[]','璧水衣冠明玉雪，市樓風月話江湖。',32,'全唐诗/poet.song.68000.json','["璧水衣冠明玉雪，市樓風月話江湖。", "莫學羣兒敗家法，入門無不曳長裾。"]'),
('6bc1acdd-a368-4273-b55a-d0a84e1b3443','句  其一','晁說之','宋','宋诗','song-poetry','','[]','清霜下牛斗，凜然北固秋。',12,'全唐诗/poet.song.68000.json','["清霜下牛斗，凜然北固秋。"]'),
('817d9512-0bed-4aa7-b238-f98ed21c60c4','句  其二','晁說之','宋','宋诗','song-poetry','','[]','煩君一日殷勤意，示我十年感遇詩。',16,'全唐诗/poet.song.68000.json','["煩君一日殷勤意，示我十年感遇詩。"]'),
('06b5c847-05aa-4578-a3ea-ef74bba0e6dc','句  其三','晁說之','宋','宋诗','song-poetry','','[]','怪底君王慚漢武，不誅方士守輪臺。',16,'全唐诗/poet.song.68000.json','["怪底君王慚漢武，不誅方士守輪臺。"]'),
('242856d8-cdb4-4b78-9e2f-2a0fc71573f9','句  其四','晁說之','宋','宋诗','song-poetry','','[]','荆州持大橘，亦名作黄柑。',12,'全唐诗/poet.song.68000.json','["荆州持大橘，亦名作黄柑。"]'),
('a7b3d234-e024-4d4f-933a-4463b3ae956d','句  其五','晁說之','宋','宋诗','song-poetry','','[]','撫掌笑木奴，爾豈當封侯。',12,'全唐诗/poet.song.68000.json','["撫掌笑木奴，爾豈當封侯。"]'),
('d4dd1743-5cad-4cb0-bfbc-04a4bf4ab9f0','過姑孰作','李沖元','宋','宋诗','song-poetry','','[]','琉璃萬頃碧如堆，畫棟連雲戶牖開。',64,'全唐诗/poet.song.68000.json','["琉璃萬頃碧如堆，畫棟連雲戶牖開。", "晴嶂勢吞三楚盡，暮潮聲带九江來。", "六朝寂寞惟流水，孤壘荒涼只舊臺。", "惆悵騎鯨人已老，夜船空棹月明迴。"]'),
('16830801-6b6d-4a9f-83b6-767ac7bbdb60','仰山','李沖元','宋','宋诗','song-poetry','','[]','孤雲欲作人間雨，流水空傳物外聲。',32,'全唐诗/poet.song.68000.json','["孤雲欲作人間雨，流水空傳物外聲。", "老柏倚巖高轉瘦，寒花著雨墜還生。"]'),
('cb0efdf1-08c9-4b5d-afb7-7e436900ce03','句','李沖元','宋','宋诗','song-poetry','','[]','窄逕隨溪轉，懸崖带蘚斑。',12,'全唐诗/poet.song.68000.json','["窄逕隨溪轉，懸崖带蘚斑。"]'),
('91feef37-7eef-40a7-8a69-5759f96ec786','題禹廟','蔣白','宋','宋诗','song-poetry','','[]','大禹歸天後，南惟此廟存。',48,'全唐诗/poet.song.68000.json','["大禹歸天後，南惟此廟存。", "屋腥龍掛影，巖墨電燒痕。", "夜祭雲間火，春鼙浪裏門。", "到今疏鑿水，敢不向東奔。"]'),
('9ba38a6b-9727-41d4-bd57-c72b997f9f33','題定慧院','史聲','宋','宋诗','song-poetry','','[]','寺名定慧知何代，橋古碑橫不記年。',64,'全唐诗/poet.song.68000.json','["寺名定慧知何代，橋古碑橫不記年。", "古樹亂鴉啼晚照，故園新蝶舞春煙。", "十層寶塔化塵路，五色雲衢散上天。", "惟有玉蓮池內水，滄浪深處老龍眠。"]'),
('69703b67-cb1d-4726-9f83-5542d276cb2b','送別嚴希孟','史聲','宋','宋诗','song-poetry','','[]','歲暮送行舟，寒煙古渡頭。',48,'全唐诗/poet.song.68000.json','["歲暮送行舟，寒煙古渡頭。", "渚禽衝客起，野水带冰流。", "經史探深趣，江山屬壯遊。", "莫將和氏璧，輕向暗中投。"]'),
('2faf047a-16c4-4486-bb28-511aed99df56','句','史聲','宋','宋诗','song-poetry','','[]','施食池腥龍戲鉢，長明燈暗鼠偷油。',16,'全唐诗/poet.song.68000.json','["施食池腥龍戲鉢，長明燈暗鼠偷油。"]'),
('cedbc898-f76b-4e22-accc-cd033e61c43d','同友人泛舟至仁王','劉燾','宋','宋诗','song-poetry','','[]','青秧出水細於鍼，嫩葉初齊綠未深。',32,'全唐诗/poet.song.68000.json','["青秧出水細於鍼，嫩葉初齊綠未深。", "又是一年春欲盡，杖藜乘興足幽尋。"]'),
('a0f7c1ea-6542-4502-8cd3-bc2cb859b85f','題召伯埭斗野亭','劉燾','宋','宋诗','song-poetry','','[]','地勢如披掌，天形似覆盤。',48,'全唐诗/poet.song.68000.json','["地勢如披掌，天形似覆盤。", "三星羅戶牖，北斗掛闌干。", "晚色芙蕖靜，秋香桂子寒。", "更無山礙眼，剩覺水雲寬。"]'),
('bca2d5b1-cc02-4f86-93a7-8b5128fd9b21','題朱邑墓','劉燾','宋','宋诗','song-poetry','','[]','古木森森覆墓亭，大農祠在古桐城。',32,'全唐诗/poet.song.68000.json','["古木森森覆墓亭，大農祠在古桐城。", "後來爲政應千輩，能使斯民獨有情。"]'),
('bed67aba-d91e-45c7-b1cd-6059a42c19eb','蝶','劉燾','宋','宋诗','song-poetry','','[]','聚作梨梢白，輕爭柳絮狂。',24,'全唐诗/poet.song.68000.json','["聚作梨梢白，輕爭柳絮狂。", "夜來花裏宿，通體牡丹香。"]'),
('fb23434c-e7e6-4b1a-a2ac-506ace6db0ff','罨畫溪','劉燾','宋','宋诗','song-poetry','','[]','竹林深處杜鵑啼，兩巖青青草色齊。',32,'全唐诗/poet.song.68000.json','["竹林深處杜鵑啼，兩巖青青草色齊。", "欲識人間真罨畫，朱籐倒影入清溪。"]'),
('04fe8855-f670-447d-99a2-fbdc1e8ed671','宿華嚴院','劉燾','宋','宋诗','song-poetry','','[]','夜宿霧山霧，晨茹芝山芝。',144,'全唐诗/poet.song.68000.json','["夜宿霧山霧，晨茹芝山芝。", "年來嗜好衰，但與青山宜。", "登臨意未愜，出戶車已脂。", "王事有期程，愛山豈余私。", "崎嶇田野間，食寢將安之。", "天寒未落日，稅駕忽在茲。", "二山已陳迹，茲處尤新奇。", "翠竹與黄花，一一對山扉。", "對景自忘言，若與予心期。", "眠雲飽山色，那得困與饑。", "山僧喜我來，迎我留新詩。", "我有愛山癡，山僧知不知。"]'),
('b1dc3898-dadd-4e11-a6b5-324bea1ef639','題樂平寺','劉燾','宋','宋诗','song-poetry','','[]','名藍占幽寂，花木深禪房。',96,'全唐诗/poet.song.68000.json','["名藍占幽寂，花木深禪房。", "開軒俯芳流，竹風終日涼。", "謂此已勝絕，坐可雄諸方。", "誰知槿籬外，古木鬰蒼蒼。", "下有湍激澗，珠玉鳴瑯璫。", "何當開松門，兩岸安石牀。", "盡發溪山奇，枕流挈其芳。", "他年我重來，君子留徜徉。"]'),
('73af5a6a-8b71-40bc-aa7b-f87cd94ae325','遊天竺觀激水','周燾','宋','宋诗','song-poetry','','[]','拳石耆婆色兩青，竹龍驅水轉山鳴。',32,'全唐诗/poet.song.68000.json','["拳石耆婆色兩青，竹龍驅水轉山鳴。", "夜深不見跳珠碎，疑是簷間滴雨聲。"]'),
('55da2654-3efe-4a8f-9c69-b9c5ce0cdd3e','詩一首','周燾','宋','宋诗','song-poetry','','[]','東山蠟屐壞車輪，小草青知山外香。',32,'全唐诗/poet.song.68000.json','["東山蠟屐壞車輪，小草青知山外香。", "園柳鳴禽喚幽夢，惠連詩句更何人。"]'),
('c9b6ba60-e7da-4be6-8996-15d92484b8bd','題羅漢院小閣','周燾','宋','宋诗','song-poetry','','[]','匹馬招提晚憩鞍，前村簫鼓餞餘寒。',32,'全唐诗/poet.song.68000.json','["匹馬招提晚憩鞍，前村簫鼓餞餘寒。", "誰知小閣欄干曲，卻得梅花正面看。"]'),
('e947938a-d022-4696-82ed-be5c09d4db4b','再宿次前韻','周燾','宋','宋诗','song-poetry','','[]','重來端復解征鞍，清夜溪風六月寒。',32,'全唐诗/poet.song.68000.json','["重來端復解征鞍，清夜溪風六月寒。", "欲寫經行二年事，平林須入畫圖看。"]'),
('13f66ee6-9ab0-4212-9349-6f2c1603e0c2','和吳拭暑雪軒','周燾','宋','宋诗','song-poetry','','[]','崇臺窮石照，氣味樂偷閑。',48,'全唐诗/poet.song.68000.json','["崇臺窮石照，氣味樂偷閑。", "南陸朱明馭，西闌白雪山。", "茶甌回舌本，麈尾落談間。", "欲綴風煙句，彌高不可攀。"]'),
('45b71988-1dfa-40d4-8e54-1f7a42eff79b','合江亭  其一','周燾','宋','宋诗','song-poetry','','[]','共思赤腳踏層冰，聊適江皋興自清。',64,'全唐诗/poet.song.68000.json','["共思赤腳踏層冰，聊適江皋興自清。", "昨夜雨雲驅濁暑，曉來煙水快新晴。", "山疑九疊張雲勢，灘激千巖落布聲。", "巾履從來在丘壑，願陪閑日此間行。"]'),
('e90d3d14-47f2-4e53-8684-d5d6e2f3fe8c','合江亭  其二','周燾','宋','宋诗','song-poetry','','[]','卻暑追隨水上亭，東郊乘曉戴殘星。',64,'全唐诗/poet.song.68000.json','["卻暑追隨水上亭，東郊乘曉戴殘星。", "餘歌咽筦來幽浦，薄霧疏煙入畫舲。", "興發江湖馳象魏，情鐘原隰詠飛令。", "故溪何日垂綸去，天末遙岑寸寸青。"]'),
('ec3d46ef-8cb7-4dd9-b4b5-632bb4ff55e5','送頭陀赴廬山寺','鄭常','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','僧家無住著，早晚出東林。',48,'全唐诗/poet.song.68000.json','["僧家無住著，早晚出東林。", "得道非真相，頭陀是苦心。", "持齋山果熟，倚錫野雲深。", "溪寺誰相待，香花與梵音。"]'),
('a2b58cf2-21ab-4e0e-8896-04ef5f8f01ca','大別山','彭天益','宋','宋诗','song-poetry','','[]','江漢西南萬里來，雙流合處聳崔巍。',32,'全唐诗/poet.song.68000.json','["江漢西南萬里來，雙流合處聳崔巍。", "神鰲載得蓬瀛去，金粟擎將世界回。"]'),
('5ed68911-720b-4792-b986-b2afef17a117','遊司空山','彭天益','宋','宋诗','song-poetry','','[]','此行疑是入天台，雲鎖巖扉次第開。',64,'全唐诗/poet.song.68000.json','["此行疑是入天台，雲鎖巖扉次第開。", "未得路通遊紫府，且隨溪轉上丹臺。", "藤蘿映带皆天設，山水瀠洄總地裁。", "果是仙家遺舊跡，清奇端不讓蓬萊。"]'),
('db6dfa48-aadd-441c-9389-fc9ee3d9357b','句','彭天益','宋','宋诗','song-poetry','','[]','鸞山配鳳嶺，金水對銀阬。',12,'全唐诗/poet.song.68000.json','["鸞山配鳳嶺，金水對銀阬。"]'),
('924de2e6-8ec4-411f-83c0-8d46a730815a','訪翠微邈上人','郟僑','宋','宋诗','song-poetry','','[]','行客倦奔馳，尋日到翠微。',48,'全唐诗/poet.song.68000.json','["行客倦奔馳，尋日到翠微。", "相看無俗語，一笑任天機。", "曲沼淡寒玉，橫山鎖落暉。", "情根枯未得，愛此幾忘歸。"]'),
('8117cd39-e77f-4f73-8a08-b8418a65edac','訪淩峰賢上人','郟僑','宋','宋诗','song-poetry','','[]','步入淩峰閣，尋師師未歸。',24,'全唐诗/poet.song.68000.json','["步入淩峰閣，尋師師未歸。", "憑欄寂無語，唯見白雲飛。"]'),
('20a5ca5c-69df-4d5d-8092-d15fcb9dcb1b','爲簡公約賦素琴堂','郟僑','宋','宋诗','song-poetry','','[]','素琴之堂虛且清，素琴之韻淪杳冥。',130,'全唐诗/poet.song.68000.json','["素琴之堂虛且清，素琴之韻淪杳冥。", "神閑意定默自鳴，宮商不動誰與聽。", "堂中道人骨不俗，貌龐形端顔瑩玉。", "我嘗見之醒心目，寧必絲桐絃斷續。", "嗚乎靖節已死不復聞，成虧相半疑昭文。", "阮手鍾耳相吐吞，素琴之道詎可論。", "道人道人聽我語，紛紛世俗誰師古。", "金徽玉軫方步武，虛堂榜名無自苦。"]'),
('4c5ab512-ee66-4387-aceb-9bbc27210a7c','無題','呂欽問','宋','宋诗','song-poetry','','[]','彭澤有琴嘗無絃，大令舊物惟青氈。',32,'全唐诗/poet.song.68000.json','["彭澤有琴嘗無絃，大令舊物惟青氈。", "我亦四壁對默坐，中有一牀供晝眠。"]'),
('055c5a2a-9358-427f-b7e4-83faed630c20','初涼','呂欽問','宋','宋诗','song-poetry','','[]','西風吹木葉，庭戶乍涼時。',24,'全唐诗/poet.song.68000.json','["西風吹木葉，庭戶乍涼時。", "夜有愁人嘆，寒先病骨知。"]'),
('baca192f-38dc-4015-aa27-aa5f5e0c0983','游瑯琊山呈銳公長老','王吉','宋','宋诗','song-poetry','','[]','踏石披雲一逕通，翠微環合見禪宮。',64,'全唐诗/poet.song.68000.json','["踏石披雲一逕通，翠微環合見禪宮。", "峰巒鬰密泉聲上，樓殿參差樹色中。", "午夜千溪分水月，清秋十里韻松風。", "平生久得名山約，吟賞今纔信宿同。"]'),
