('805bf352-33e3-4c16-a6c8-84ab901df464','喜吳雲叟公裕垂訪','釋子淳','宋','宋诗','song-poetry','','[]','山路春風桃李香，延陵長者賁岸房。',64,'全唐诗/poet.song.68000.json','["山路春風桃李香，延陵長者賁岸房。", "行行廓爾忘途轍，步步翛然合道場。", "妙凈宗乘松宿鶴，虛明田地月含霜。", "相逢相見有何事，共語毗盧頂後光。"]'),
('01aded66-e038-40c9-91b7-e5dc9cb62e8d','送止維那作丐','釋子淳','宋','宋诗','song-poetry','','[]','常思止禪者，返本如嬰兒。',68,'全唐诗/poet.song.68000.json','["常思止禪者，返本如嬰兒。", "一念萬年去，春秋都不知。", "斫倒寒巖無影樹，迴頭焰裡再抽枝。", "春老別吾入酈去，緣生會有歸山咦。", "凈榻相看坐，清風起四維。"]'),
('3601319f-c8d5-4ca5-bca1-1d76c28f181e','和正可知藏適軒','釋子淳','宋','宋诗','song-poetry','','[]','適軒新開非華飾，爲愛清涼消暑濕。',64,'全唐诗/poet.song.68000.json','["適軒新開非華飾，爲愛清涼消暑濕。", "景象千般何處來，塵埃一點應難入。", "蒲團禪版靜沉沉，松韻竹風常龔龔。", "香斷爐寒坐夜深，苔墀月滿無人立。"]'),
('8f0e1748-fa4f-4b34-a842-bec2eff11824','謝蒙城善友惠米','釋子淳','宋','宋诗','song-poetry','','[]','客到蒙城有信歸，殷勤惠米助晨炊。',64,'全唐诗/poet.song.68000.json','["客到蒙城有信歸，殷勤惠米助晨炊。", "老僧鉢滿慵相喚，長者恩深祇自知。", "粒粒圓成難著會，明明嚼碎更何疑。", "趙州遺語誠非謬，一飽元來忘百饑。"]'),
('dbdc849b-cfbc-4633-9787-55a925379efb','任善友求頌','釋子淳','宋','宋诗','song-poetry','','[]','差別道難通，應須識自宗。',24,'全唐诗/poet.song.68000.json','["差別道難通，應須識自宗。", "無根枯樹子，月夜影重重。"]'),
('002b1f5b-1946-44be-8644-e93906c4ce4e','丹霞誧法弟新建暖堂以頌慶之','釋子淳','宋','宋诗','song-poetry','','[]','暖堂新構侵雲表，桂月松風常滿抱。',32,'全唐诗/poet.song.68000.json','["暖堂新構侵雲表，桂月松風常滿抱。", "玉燭光中靜應時，言前妙唱般陽道。"]'),
('326f25a4-d620-41d8-ad33-697cfbc5e5d5','山居五首  其一','釋子淳','宋','宋诗','song-poetry','','[]','林麓結茅廬，翛然稱所居。',48,'全唐诗/poet.song.68000.json','["林麓結茅廬，翛然稱所居。", "松風驚破夢，澗冰靜涵虛。", "春老花猶媚，秋殘葉未疏。", "良宵無限意，東嶺月生初。"]'),
('41e2d12b-0d47-4cc9-b708-7664c3818841','山居五首  其二','釋子淳','宋','宋诗','song-poetry','','[]','祇這一閑田，古今無變遷。',48,'全唐诗/poet.song.68000.json','["祇這一閑田，古今無變遷。", "泥牛耕不盡，寶月鎮長圓。", "巖桂和煙翠，溪花含露鮮。", "甘藏青嶂裡，懶更謁時賢。"]'),
('4c59bb57-5d49-46bd-8fde-ab7c61d910cb','山居五首  其三','釋子淳','宋','宋诗','song-poetry','','[]','家近亂山根，日高懶啟門。',48,'全唐诗/poet.song.68000.json','["家近亂山根，日高懶啟門。", "樵歌雲外唱，胡曲句前論。", "路僻無人到，庭荒有蘚痕。", "蕭蕭巖石畔，祇麽老煙村。"]'),
('72b12eb2-1912-45a1-a109-d12a13a6ec2f','山居五首  其四','釋子淳','宋','宋诗','song-poetry','','[]','兀坐鎮長行，孰人知此情。',48,'全唐诗/poet.song.68000.json','["兀坐鎮長行，孰人知此情。", "竹風輕有韻，巖溜細無聲。", "岌岌三山秀，依依片月明。", "門前枯樹子，孤鶴夢難成。"]'),
('a247c039-8fc2-446c-ad41-77d684e45c3f','山居五首  其五','釋子淳','宋','宋诗','song-poetry','','[]','不戀白雲關，家山撒手還。',48,'全唐诗/poet.song.68000.json','["不戀白雲關，家山撒手還。", "玉爐香旖旎，石磵水潺湲。", "庭樹煙籠合，窗軒雨灑斑。", "經行及坐臥，常在寂寥間。"]'),
('0ecb6496-8cd3-4d46-9346-5c7d098be0c6','寄隨守向大夫三首  其一','釋子淳','宋','宋诗','song-poetry','','[]','歲寒木欲老林坰，茲沐恩光入翠層。',32,'全唐诗/poet.song.68000.json','["歲寒木欲老林坰，茲沐恩光入翠層。", "再整絲綸垂釣手，隨緣溳水且騰騰。"]'),
('5e700857-a9cf-4c57-ba28-2b8e47a95d36','寄隨守向大夫三首  其二','釋子淳','宋','宋诗','song-poetry','','[]','道同曾未隔毫端，相別相逢會者難。',32,'全唐诗/poet.song.68000.json','["道同曾未隔毫端，相別相逢會者難。", "偶此又蒙清照及，松風桂月襲人寒。"]'),
('34223311-9926-4eed-837d-4d790d58f851','寄隨守向大夫三首  其三','釋子淳','宋','宋诗','song-poetry','','[]','無絃琴上有希聲，此遇知音作證明。',32,'全唐诗/poet.song.68000.json','["無絃琴上有希聲，此遇知音作證明。", "不犯指端彈一曲，碧琉璃界月三更。"]'),
('834401e1-c21b-4a03-bad7-1eeb9bba0e1f','送吳公裕','釋子淳','宋','宋诗','song-poetry','','[]','天氣暄妍三月春，青山垂訪白頭人。',64,'全唐诗/poet.song.68000.json','["天氣暄妍三月春，青山垂訪白頭人。", "威儀雍肅披儒雅，語論清泠洗渴塵。", "道合圓常無異路，心空及第自通津。", "相逢相別休懷念，千里同風德及鄰。"]'),
('dda04674-98fa-4de7-9156-f2d580a37a36','蠲上人求頌','釋子淳','宋','宋诗','song-poetry','','[]','一九逢春信，梅花破雪開。',24,'全唐诗/poet.song.68000.json','["一九逢春信，梅花破雪開。", "箇中如會得，千里不空來。"]'),
('6e1a97d9-513e-482f-bf8a-a383007daa69','和張居士','釋子淳','宋','宋诗','song-poetry','','[]','默訥虛明履趣深，蟾蜍推月照天心。',32,'全唐诗/poet.song.68000.json','["默訥虛明履趣深，蟾蜍推月照天心。", "松風未作寒林靜，一弄無絃琴上音。"]'),
('33571392-1617-4c71-bd44-e14295c90c25','和張伯威見寄','釋子淳','宋','宋诗','song-poetry','','[]','今日重來坐暖霞，故人笑謂老年華。',32,'全唐诗/poet.song.69000.json','["今日重來坐暖霞，故人笑謂老年華。", "劫空別有壺春在，雲對青山興莫涯。"]'),
('070b39ef-5b64-46c2-8be0-b22e16165d63','和章陽叔見寄二首  其一','釋子淳','宋','宋诗','song-poetry','','[]','休將水乳試鵝王，妙識醇醨別有方。',32,'全唐诗/poet.song.69000.json','["休將水乳試鵝王，妙識醇醨別有方。", "本地不消春氣力，靈枝劫外有餘芳。"]'),
('a294cb51-e14f-4ee4-92f4-56a4749b74a3','和章陽叔見寄二首  其二','釋子淳','宋','宋诗','song-poetry','','[]','師曠離婁不我徒，昭然罔象得玄珠。',32,'全唐诗/poet.song.69000.json','["師曠離婁不我徒，昭然罔象得玄珠。", "心萌口擬成途轍，底事圓明異有無。"]'),
('015b6de8-aec1-469a-a956-2b6c2560e7a0','酬時于叔','釋子淳','宋','宋诗','song-poetry','','[]','妙句靈然溢目寒，幽微旨趣曾還難。',32,'全唐诗/poet.song.69000.json','["妙句靈然溢目寒，幽微旨趣曾還難。", "相逢更問無絃曲，風入松梢不在彈。"]'),
('681d6daf-f4c4-40e1-a68e-98452c6012c2','偈五首  其一','釋子淳','宋','宋诗','song-poetry','','[]','乾坤之內，宇宙之間。',20,'全唐诗/poet.song.69000.json','["乾坤之內，宇宙之間。", "要有一寶，秘在形山。"]'),
('b2858a93-3202-4965-978f-d04177fccfed','偈五首  其二','釋子淳','宋','宋诗','song-poetry','','[]','我宗有語句，金刀剪不開。',24,'全唐诗/poet.song.69000.json','["我宗有語句，金刀剪不開。", "深深玄妙旨，玉女夜懷胎。"]'),
('6561173b-9f3c-489b-acd5-e327c1cdaede','偈五首  其三','釋子淳','宋','宋诗','song-poetry','','[]','亭亭日午猶虧半，寂寂三更尚未圓。',32,'全唐诗/poet.song.69000.json','["亭亭日午猶虧半，寂寂三更尚未圓。", "六戶不曾知暖意，往來常在三更前。"]'),
('621b9f75-8347-49bc-b24b-cc445cf4a272','偈五首  其四','釋子淳','宋','宋诗','song-poetry','','[]','寶月流輝，澄潭布影。',34,'全唐诗/poet.song.69000.json','["寶月流輝，澄潭布影。", "水無蘸月之意，月無分照之心。", "水月兩忘，方可稱斷。"]'),
('ba7a6f7c-d9f6-495c-bce9-5038e714ff2f','偈五首  其五','釋子淳','宋','宋诗','song-poetry','','[]','日照孤峰翠，月臨溪水寒。',24,'全唐诗/poet.song.69000.json','["日照孤峰翠，月臨溪水寒。", "祖師玄妙訣，莫向寸心安。"]'),
('3107dc2a-9526-42f1-b691-a55d4993f04e','頌古一○一首  其一','釋子淳','宋','宋诗','song-poetry','','[]','妙相圓明不可親，奴兒婢子自殷勤。',32,'全唐诗/poet.song.69000.json','["妙相圓明不可親，奴兒婢子自殷勤。", "指天指地稱尊大，也是傳言送語人。"]'),
('d313c58d-5d9c-4aec-b608-e89acf1bc077','頌古一○一首  其二','釋子淳','宋','宋诗','song-poetry','','[]','相好巍巍大丈夫，一生無智恰如愚。',32,'全唐诗/poet.song.69000.json','["相好巍巍大丈夫，一生無智恰如愚。", "從來佛祖猶難望，地獄天堂豈可拘。"]'),
('b1c597ef-e031-46a4-9763-40cb2ab24fa8','頌古一○一首  其三','釋子淳','宋','宋诗','song-poetry','','[]','卓爾難將正眼窺，迴超今古類難齊。',32,'全唐诗/poet.song.69000.json','["卓爾難將正眼窺，迴超今古類難齊。", "苔封古殿無人侍，月鎖蒼梧鳳不棲。"]'),
('7f5c1a8f-549e-46a7-8a76-64e6d58c76ed','頌古一○一首  其四','釋子淳','宋','宋诗','song-poetry','','[]','木人來問青霄路，石女年尊似不聞。',32,'全唐诗/poet.song.69000.json','["木人來問青霄路，石女年尊似不聞。", "攜手相將歸故國，暮山岌岌鎖重雲。"]'),
('4e8ea8b3-d8ac-4e99-a606-557757e161d9','頌古一○一首  其五','釋子淳','宋','宋诗','song-poetry','','[]','玄微及盡本翛然，若謂渠閑萬八千。',32,'全唐诗/poet.song.69000.json','["玄微及盡本翛然，若謂渠閑萬八千。", "月印澄江魚不見，釣人何必更拋筌。"]'),
('c9404fa6-8277-4e91-9097-4613b3c26e0a','頌古一○一首  其六','釋子淳','宋','宋诗','song-poetry','','[]','垂手還他作者機，尋常語裏布鎗旗。',32,'全唐诗/poet.song.69000.json','["垂手還他作者機，尋常語裏布鎗旗。", "重詢擬進歸方丈，一句分明更不疑。"]'),
('0fb5cca0-a956-450e-b934-8c64487ca18d','頌古一○一首  其七','釋子淳','宋','宋诗','song-poetry','','[]','白雲深處路難通，擬問蹤由已涉功。',32,'全唐诗/poet.song.69000.json','["白雲深處路難通，擬問蹤由已涉功。", "掛角羚羊無影跡，從容還落正偏中。"]'),
('3ab060d6-c236-48e5-8eb4-b4d794d762b4','頌古一○一首  其八','釋子淳','宋','宋诗','song-poetry','','[]','饑冷嫩草遙山去，渴飲寒泉曲澗回。',32,'全唐诗/poet.song.69000.json','["饑冷嫩草遙山去，渴飲寒泉曲澗回。", "放蕩不耕空劫地，暮天何用牧歌催。"]'),
('9f2bd0fe-ff41-4b54-b6e8-efb661a24309','頌古一○一首  其九','釋子淳','宋','宋诗','song-poetry','','[]','王鞭高舉擊金門，引出珊瑚價莫論。',32,'全唐诗/poet.song.69000.json','["王鞭高舉擊金門，引出珊瑚價莫論。", "迴古輪王全意氣，不彰寶印自然尊。"]'),
