('046315c8-7446-4f8e-8953-de89067afeb6','頌古一○一首  其九○','釋子淳','宋','宋诗','song-poetry','','[]','靈山會上言雖普，少室峰前句未形。',32,'全唐诗/poet.song.69000.json','["靈山會上言雖普，少室峰前句未形。", "瑞草蒙茸含月秀，寒松蓊鬰出雲青。"]'),
('e5f390b4-ab76-4c42-8f6f-6fa4d9d6ef9b','頌古一○一首  其九一','釋子淳','宋','宋诗','song-poetry','','[]','劫火洞然無相宅，金門不睹玉樓家。',32,'全唐诗/poet.song.69000.json','["劫火洞然無相宅，金門不睹玉樓家。", "寶天雲淡銀河冷，浩浩波瀾豈動沙。"]'),
('91de4e98-0cc7-407b-ac33-afd7166e58e0','頌古一○一首  其九二','釋子淳','宋','宋诗','song-poetry','','[]','不掛唇皮一句奇，少林冷坐最慈悲。',32,'全唐诗/poet.song.69000.json','["不掛唇皮一句奇，少林冷坐最慈悲。", "須知此道非傳授，立雪神光已強爲。"]'),
('3ebd1ec7-556c-4709-82b9-03f70e7259f2','頌古一○一首  其九三','釋子淳','宋','宋诗','song-poetry','','[]','荆山美玉何須辨，赤水玄珠不用拈。',32,'全唐诗/poet.song.69000.json','["荆山美玉何須辨，赤水玄珠不用拈。", "罔象無心黄帝重，卞和有智楚王嫌。"]'),
('bc7f191e-a219-40a2-b567-2e8944e9c8bd','頌古一○一首  其九四','釋子淳','宋','宋诗','song-poetry','','[]','珊瑚枝上玉花開，風遞清香遍九垓。',32,'全唐诗/poet.song.69000.json','["珊瑚枝上玉花開，風遞清香遍九垓。", "勿謂乾坤成委曲，韶陽親見睦州來。"]'),
('9eb38d8a-cdde-4742-9427-ad64079b794a','頌古一○一首  其九五','釋子淳','宋','宋诗','song-poetry','','[]','水澄月滿道人愁，妙盡無依類莫收。',32,'全唐诗/poet.song.69000.json','["水澄月滿道人愁，妙盡無依類莫收。", "劫外正偏兼带路，不萌枝上辨春秋。"]'),
('26581306-62f6-430a-874c-1d3d92996d0a','頌古一○一首  其九六','釋子淳','宋','宋诗','song-poetry','','[]','六國清平賀聖年，珠簾高卷月明前。',32,'全唐诗/poet.song.69000.json','["六國清平賀聖年，珠簾高卷月明前。", "金輪那肯當堂坐，不用丹墀擊靜鞭。"]'),
('9ef4a56c-6252-4f76-964b-7fc67f0a45ea','頌古一○一首  其九七','釋子淳','宋','宋诗','song-poetry','','[]','等閑應問豈安排，一句全提隱顯該。',32,'全唐诗/poet.song.69000.json','["等閑應問豈安排，一句全提隱顯該。", "薄霧依依籠古徑，孤峰終不露崔嵬。"]'),
('075ddd94-c3e1-4a3e-85a4-dbcdeaa766c3','頌古一○一首  其九八','釋子淳','宋','宋诗','song-poetry','','[]','星流水國夜然燈，月印江天明似鏡。',32,'全唐诗/poet.song.69000.json','["星流水國夜然燈，月印江天明似鏡。", "隱顯無私位不該，依稀擬動成偏正。"]'),
('6ed29573-3dd9-4859-a9a1-560c1eb7e8cf','頌古一○一首  其九九','釋子淳','宋','宋诗','song-poetry','','[]','道合平常絕異端，行人何必歷艱難。',32,'全唐诗/poet.song.69000.json','["道合平常絕異端，行人何必歷艱難。", "從今莫信孫臏卜，龜殻無靈不用鑽。"]'),
('2fb56a4b-8908-41d4-bdcd-781495644cb5','頌古一○一首  其一○○','釋子淳','宋','宋诗','song-poetry','','[]','此樹不從天地生，登山涉水承渠力。',32,'全唐诗/poet.song.69000.json','["此樹不從天地生，登山涉水承渠力。", "如今擲向亂峰前，免致叢林爲軌則。"]'),
('1a1fb6e5-bb16-45c5-9d25-2795da4ffc01','頌古一○一首  其一○一','釋子淳','宋','宋诗','song-poetry','','[]','靈然不涉古來今，三界都盧一點心。',32,'全唐诗/poet.song.69000.json','["靈然不涉古來今，三界都盧一點心。", "檻外桃花春蝶舞，門前楊柳曉鶯吟。"]'),
('558586ff-c2e4-4c06-8904-7783719a2129','古樂府','晁沖之','宋','宋诗','song-poetry','','[]','大星何歷歷，小星爛如石。',178,'全唐诗/poet.song.69000.json','["大星何歷歷，小星爛如石。", "掖垣崔嵬横紫微，十二羽林森北極。", "今夕何夕月欲沒，虎抱空關龍厭直。", "崢嶸北斗著地垂，手去瓠瓜不盈尺。", "嚴陵醉卧光武傍，浮楂正值天孫織。", "王良挾策飛上天，傅說空騎箕尾立。", "君不見茂陵棄子欲登仙，自将壯士終南邊。", "忽然遭窘出璽綬，歸來下詔除民田。", "阿瞞急示乘輿物，鮮卑仍棄珊瑚鞭。", "又不見古來垂堂戒華屋，敵國挾輈戎接轂。", "白龍魚服誤網羅，孔雀金花被牛觸。"]'),
('cfe98626-fa87-49a0-91dd-13f805cf6735','雪效柳子厚','晁沖之','宋','宋诗','song-poetry','','[]','月落雞聲寒，曉色静茅屋。',72,'全唐诗/poet.song.69000.json','["月落雞聲寒，曉色静茅屋。", "開門驚不知，夜雪壓脩竹。", "槎牙生新冰，鱗甲刻溪谷。", "皛皛洲渚明，冽冽川原肅。", "孤蹲雀不動，沉酣客猶宿。", "呼童晨汲歸，獨潄寒泉玉。"]'),
('b2d25ef5-3f0d-4535-a8cf-fead04f575bb','擬一上人懷山之什','晁沖之','宋','宋诗','song-poetry','','[]','中夜雪打窗，燈暗火照屋。',72,'全唐诗/poet.song.69000.json','["中夜雪打窗，燈暗火照屋。", "袖手地爐火，缾聲起絲竹。", "憶我故山房，松風韻崖谷。", "山空牛斗寒，寺静魚鼓肅。", "西寨鹿不歸，東嶺鶴獨宿。", "更想醉翁亭，兩峰高並玉。"]'),
('32f15d2f-288c-41b4-80ee-d6f45b891b89','題魯山温泉','晁沖之','宋','宋诗','song-poetry','','[]','平生耳熟聞驪山，夢寐不到臨潼關。',131,'全唐诗/poet.song.69000.json','["平生耳熟聞驪山，夢寐不到臨潼關。", "當年太液金井碧，温泉宛在關山間。", "憶昔君來必十月，騎玉花驄带風雪。", "太真獨侍沐浴邊，鯨甲龍鱗影清絕。", "五十年昇平一迷，却驅萬騎出關西。", "自爲前朝同禍水，翻令後代異廉溪。", "君不見汝海之南魯山左，亦有此泉名不播。", "征夫問路說湯頭，可憐是亦陳驚坐。"]'),
('30afddfc-4adc-4d5d-9fe7-05e609302ab7','香山示孔處厚','晁沖之','宋','宋诗','song-poetry','','[]','我來南經幾山過，馬行似衝山色破。',128,'全唐诗/poet.song.69000.json','["我來南經幾山過，馬行似衝山色破。", "風煙席卷嵓穴開，澗花縈迴水流左。", "懸崖彷彿聞松聲，下瞰幽深鳥飛墮。", "老夫他年有所歸，定結白茅依紫邏。", "日高下馬古寺門，魚鼓欣聞脫清餓。", "道人碧眼照川谷，雲起盤陀藉高坐。", "慇勤勸我更莫歸，淚鶴啼猿亦相和。", "窗前笑喚祁孔賓，世間安用招魂些。"]'),
('f967ce7f-5620-4718-a4d7-91dabfdbde83','田中行','晁沖之','宋','宋诗','song-poetry','','[]','落葉如流人，遷徙不可收。',168,'全唐诗/poet.song.69000.json','["落葉如流人，遷徙不可收。", "嚴霜枯百草，清此山下溝。", "我行將涉之，脫屨笑復休。", "憮然顧籃輿，崎嶇反經丘。", "天風吹我裳，彼亦難久留。", "晚過柳下門，鳥聲上嘲啾。", "父老四五輩，向我如有求。", "邀我酌白酒，酒酣語和柔。", "指云此屋南，頗有良田疇。", "勸我耕其中，庶結同社游。", "吾母性慈險，此事誠易謀。", "伯也久吏隱，可以吾無憂。", "請歸召家室，賣衣買肥牛。", "所望上帝喜，祈穀常有秋。"]'),
('4d490dee-1b2d-42c8-9c5a-4c9f986b65d6','同魯山韓丞觀女靈廟前險石','晁沖之','宋','宋诗','song-poetry','','[]','君不見魯陽之西兩山麓，十里連岡寫平陸。',262,'全唐诗/poet.song.69000.json','["君不見魯陽之西兩山麓，十里連岡寫平陸。", "青林白晝暗古祠，雀啅虛簷蛛網屋。", "屋邊怪石何瑰奇，鳯筋虎骨連肌肉。", "巉巖欲下落澗渚，澒洞千鈞一毫屬。", "天匠惟知刻畫功，鬼力深憂護持哭。", "前峰高蹇下如揖，餘峰危慓皆俯伏。", "披尋宿莽得佳趣，窪爲溪壑呀爲谷。", "香爐佛迹不在外，仙掌蛾眉此其足。", "秀潤潛涵夏木清，空濛映带春江綠。", "我知此必藴靈異，何止懷藏易城玉。", "閴寂嗟來麋鹿游，孤峻幸免牛羊觸。", "自經千載禹刊鑿，不逢萬里秦驅逐。", "踟蹰三遶回高岡，却立下視雲蒼蒼。", "古今誰爲好事者，後有韓子前奇章。", "君不見玉川先生洛陽宅，脩竹蕭蕭獨爲客。", "他年如與鶴乘軒，可來相見銅駝陌。"]'),
('1e03730b-7a9c-43b6-a2b7-fb6d65e52f57','陸元鈞寄日注茶','晁沖之','宋','宋诗','song-poetry','','[]','我昔不知風雅頌，草木獨以茶比諷。',192,'全唐诗/poet.song.69000.json','["我昔不知風雅頌，草木獨以茶比諷。", "陋哉徐鉉說茶苦，欲與淇園竹同種。", "又疑禹漏税九州，橘柚當年錯包貢。", "腐儒妄測聖人意，遠物勞民亦安用。", "含桃熟薦當在盤，荔子生來枉飛鞚。", "羊爼異好亦何有，蚶菜殊珍要非奉。", "君家季疵真禍首，毁論徒勞世仍重。", "爭新鬭試誇撃拂，風俗移人可深痛。", "老夫病渴手自煎，嗜好悠悠亦從衆。", "更煩小陸分日注，密封細字蠻奴送。", "槍旗却憶採擷初，雪花似是雲溪動。", "更期遺我但敲門，玉川無復周公夢。"]'),
('14dae84b-4a85-4ada-99b1-f607466adeb7','送王敦素','晁沖之','宋','宋诗','song-poetry','','[]','先君有六女，所託皆高門。',276,'全唐诗/poet.song.69000.json','["先君有六女，所託皆高門。", "季也久擇壻，晚得與子婚。", "子家望海內，實惟謫仙孫。", "筆也有家法，勢作風雷奔。", "結交多英豪，坐致名譽喧。", "憶昔識子初，河流出崑崙。", "中間一再見，騏驥始伏轅。", "去年接同居，底裏見所存。", "磊落忠義人，愛國憂黎元。", "使當元祐時，密勿與討論。", "上可參廊廟，下可禆諫垣。", "惜哉不遇知，白髮早已繁。", "卑官不可說，感激有主恩。", "爛漫有歸期，繫舟古槐根。", "祖餞無酒食，贈遺請以言。", "子家鍾山下，隨事有田園。", "竹徑背古寺，草堂面江村。", "高軒納翠微，修筒引潺湲。", "林影散疏帙，山色搖酒罇。", "日飲建康水，時登謝公墩。", "沈酣左氏學，浩蕩極辭源。", "客至勿多語，欲吐且復吞。", "書來無匆匆，慰我别後魂。"]'),
('3fe171f5-d577-4d2e-bc63-4d4c885495ff','次四兄韻答許下諸公','晁沖之','宋','宋诗','song-poetry','','[]','羣雄將風騷，敵若攻守墨。',120,'全唐诗/poet.song.69000.json','["羣雄將風騷，敵若攻守墨。", "公將百萬兵，如一劇孟足。", "間楚或揮金，伐虞還取玉。", "使我備偏裨，授書防敗辱。", "安敢凱旋歌，直可向師哭。", "短兵不須接，長城已完筑。", "畏強我但守，用奇公自出。", "入壘畏膝行，免冠謝頭禿。", "論功轂可丹，錫命綬當綠。", "顧我老更癡，猛虎空手觸。"]'),
('dcd20b0d-f849-4fdf-94a8-9b730460319d','贈僧法一墨','晁沖之','宋','宋诗','song-poetry','','[]','黄山之巔百尺松，虬枝偃盖連羣峰。',195,'全唐诗/poet.song.69000.json','["黄山之巔百尺松，虬枝偃盖連羣峰。", "山神守護魑魅避，道人剪伐天爲容。", "捫崖踸踔篝火遠，絕壁晻靄凝烟濃。", "玄霜霏霏玉杵下，捕麋煮角當嚴冬。", "陰房風日不可到，律琯吹盡灰無蹤。", "小書細字著名姓，黄金照耀圖雙龍。", "守臣再拜選進日，九關有詔開重重。", "老儒偶得實天幸，千金更買無由逢。", "上人澹泊何所好，工書草隸如飛蓬。", "苦來求我惜不得，一酬十載相過從。", "君不見玉堂詞人紫垣客，拜賜舞蹈黄羅封。", "長安紙價猶未貴，江南江北山皆童。"]'),
('dbc533bd-8595-46e9-af71-ae6299adf03a','法一以余所贈墨爲不佳','晁沖之','宋','宋诗','song-poetry','','[]','上人好事世莫當，羅列四寶如文房。',133,'全唐诗/poet.song.69000.json','["上人好事世莫當，羅列四寶如文房。", "廣交往往得奇物，有墨尺度如圭長。", "秋麋折角膠與力，春麝入臍煤生香。", "已将雪覆輕羅帕，更令花映紅紗囊。", "草堂老人不自料，亦藏一餅誇精妙。", "自言和璧持贈君，反爲燕石遭譏誚。", "嗚呼萬事孰不然，古今工拙那同調。", "君不見當年諸李數不到廷寛，只今賜墨無老潘。"]'),
('39e82fea-3c0c-4d40-a958-53ddb1652646','復以承晏墨贈之','晁沖之','宋','宋诗','song-poetry','','[]','我聞江南墨官有諸奚，老超尚不如庭珪。',165,'全唐诗/poet.song.69000.json','["我聞江南墨官有諸奚，老超尚不如庭珪。", "後來承晏復秀出，喧然父子名相齊。", "百年相傳文斷碎，彷彿尚見蛟龍背。", "電光屬天星斗昏，雨痕倒海風雲晦。", "却憶當年清暑殿，黄門侍立才人見。", "銀鈎洒落金花牋，牙床磨試紅絲研。", "同時書畫三萬軸，大徐小篆徐熙竹。", "御題四絕海內傳，秘府毫芒惜如玉。", "君不見建隆天子開國初，曹公受詔行掃除。", "王侯舊物人今得，更寫西天貝葉書。"]'),
('717c283a-e602-4a51-b8ec-5cc4551bd333','紀愁','晁沖之','宋','宋诗','song-poetry','','[]','北風吹我裳，夏潦漂我屋。',120,'全唐诗/poet.song.69000.json','["北風吹我裳，夏潦漂我屋。", "牛羊踐我稼，雀鼠耗我穀。", "雪寒墮我指，雨淫疾我腹。", "朝行桑榆間，秋序傷遠目。", "莫涉水之涯，含沙中兩足。", "攬轡馬病黄，伏軾輿脫輹。", "陟山既見虎，還舍乃對鵩。", "一沐三握髮，十飯九不肉。", "先生昔離垢，居士今耐辱。", "飽聞戒畏塗，那知有沈陸。"]'),
('d131665c-511a-4608-801b-2fc9cdd97a9a','四兄諸人皆用屋字詩送一上人余獨留之','晁沖之','宋','宋诗','song-poetry','','[]','狺狺犬護門，喔喔雞登屋。',72,'全唐诗/poet.song.69000.json','["狺狺犬護門，喔喔雞登屋。", "不疑故人來，但謂風敲竹。", "孤僧雪中歸，白馬度塹谷。", "坐久飯食訖，尚說毛髪肅。", "吹燈燃濕薪，我起子就宿。", "明日且復留，長安米如玉。"]'),
('8deb62ff-baf6-426c-92bd-fe946d0eeec1','送一上人還滁州瑯琊山','晁沖之','宋','宋诗','song-poetry','','[]','上人法一朝過我，問我作詩三昧門。',256,'全唐诗/poet.song.69000.json','["上人法一朝過我，問我作詩三昧門。", "我聞大士入詞海，不起宴坐澄心源。", "禪波洞徹百淵底，法水蕩滌諸塵根。", "迅流速度超鬼國，到岸捨筏登崑崙。", "無邊草木悉妙藥，一切禽鳥皆能言。", "化身八萬四千臂，神通轉物如乾坤。", "山河大地悉自說，是身口意初不喧。", "世間何事在妙理，悟處不獨非風幡。", "羣鵝轉頸感王子，佳人舞劍驚公孫。", "風飄素練有飛勢，雨注破屋空留痕。", "惜哉數子枉玄解，但令筆畫空騰騫。", "君看瑯琊釀泉上，醉翁妙語今猶存。", "向來溪壑不改色，青嶂尚屬僧家園。", "君行到此知此意，辨才第二文中尊。", "西江一口盡可吸，雲夢八九何勞吞。", "他年一瓣爐中香，此老與有法乳恩。"]'),
('f34f2d2c-d72d-4524-9b06-14738923fa4e','和十二兄五首  其一','晁沖之','宋','宋诗','song-poetry','','[]','淵明詩百篇，無一不說酒。',120,'全唐诗/poet.song.69000.json','["淵明詩百篇，無一不說酒。", "四顧宇宙間，獨與此物厚。", "子雲苦家貧，日給或亡有。", "艱難識奇字，草玄至白首。", "時時載酒来，尚乃好事友。", "吾兄斯人徒，性亦嗜醇酎。", "寧知俗士嫌，益覺兒女醜。", "孰云醉無度，婉婉春月柳。", "區區布肉論，遲速同一朽。", "但看古聖賢，得如飲者不。"]'),
('bb59a719-7fa4-40c5-858c-fa12e1c7d8f7','和十二兄五首  其二','晁沖之','宋','宋诗','song-poetry','','[]','伯也今代豪，嗜詩如嗜酒。',120,'全唐诗/poet.song.69000.json','["伯也今代豪，嗜詩如嗜酒。", "賦多轉遒勁，語老愈深厚。", "塵言刪不存，妙句元自有。", "白華忽補亡，關睢不爲首。", "塤篪起兄弟，珠玉到朋友。", "吟詠九日菊，沉酣八月酎。", "搜剔發清新，聯翩雜奇醜。", "詳味吁謨章，用意過楊柳。", "但使身愈窮，未信名可朽。", "不知造物意，令作清廟不。"]'),
('5bdb9b3a-a1de-48e0-a92e-feb24ccb43da','和十二兄五首  其三','晁沖之','宋','宋诗','song-poetry','','[]','崎嶇謫仙人，豪放一寓酒。',120,'全唐诗/poet.song.69000.json','["崎嶇謫仙人，豪放一寓酒。", "平生韓荆州，未識意已厚。", "幕府强辟召，此例未見有。", "書幣入吾廬，鞍馬望隴首。", "出處計已熟，不復訊交友。", "南山别何時，氣尚若酣酎。", "籌策屈大才，談笑誅小醜。", "戍角斷落梅，羌笛起折柳。", "将軍意未快，戰士骨已朽。", "請公入參謀，可用和戎不。"]'),
('f412b34c-d527-43cf-85c2-ed305109c55f','和十二兄五首  其四','晁沖之','宋','宋诗','song-poetry','','[]','先生翰墨英，揮灑每被酒。',120,'全唐诗/poet.song.69000.json','["先生翰墨英，揮灑每被酒。", "氣凌蒼柱穹，勢壓坤軸厚。", "俊拔今固無，妙絕古未有。", "驚鸞忽矯翼，犇馬時驤首。", "高步禇薛流，下視鍾王友。", "好事隨取之，所至具名酎。", "簡疏秦隸奇，譎怪夏篆醜。", "么麽張芝草，嫵媚元和柳。", "載觀碑籍存，尚恐金石朽。", "未知太極成，有請於公不。"]'),
('6000ef5a-76d3-4788-bc4f-62ee03204b10','和十二兄五首  其五','晁沖之','宋','宋诗','song-poetry','','[]','我家溱洧間，春水色如酒。',120,'全唐诗/poet.song.69000.json','["我家溱洧間，春水色如酒。", "嵩少在吾旁，日夕意亦厚。", "田園雖不廣，幽興隨事有。", "藥畦灌陳根，芋區採駢首。", "春郊餉耕徒，秋社接酒友。", "飽誦傳家書，促釀供客酎。", "益知簡易真，未媿疏拙醜。", "邇來居東都，物色不見柳。", "造次遇摧折，荏苒及衰朽。", "欲歸便可爾，未知公果不。"]'),
('230eb4b2-430d-43ce-ae77-8270c5c96e44','夷門行贈秦夷仲','晁沖之','宋','宋诗','song-poetry','','[]','君不見夷門客有侯嬴風，殺人白晝紅塵中。',111,'全唐诗/poet.song.69000.json','["君不見夷門客有侯嬴風，殺人白晝紅塵中。", "京兆知名不敢捕，倚天長劍著崆峒。", "同時結交三數公，聯翩走馬幾馬驄。", "仰天一笑萬事空，入門賓客不復通。", "起家簪笏明光宮。", "嗚呼男兒名重太山身如葉，手犯龍鱗心莫懾。", "一生好色馬相如，慷慨直辭猶諫獵。"]'),
('3ccae4f1-fcdf-4109-bbed-36f315049a46','次四兄雪夜韻','晁沖之','宋','宋诗','song-poetry','','[]','夏蟲不知冰，越犬不識雪。',84,'全唐诗/poet.song.69000.json','["夏蟲不知冰，越犬不識雪。", "我獨冰雪間，肘見冠纓絕。", "青燈挂長檠，文字夜涉獵。", "問米米已無，問酒酒已竭。", "當時陶淵明，同日無此闕。", "置書忽不樂，面壁卧嘔噎。", "蟲犬兩不如，悲歌聊一發。"]'),
('5d373ba9-8cb9-4b35-b79f-3226d3062bce','書懷寄李相如','晁沖之','宋','宋诗','song-poetry','','[]','秋風吹畦蔬，農事亦已闌。',108,'全唐诗/poet.song.69000.json','["秋風吹畦蔬，農事亦已闌。", "黄黄杞下菊，佳色尸冢間。", "我生復何如，憔悴嘗照顔。", "清晨戴星出，薄暮及目還。", "骯髒二十載，老髮羞儒冠。", "天未有佳人，秀擢如芝蘭。", "憮然念夙昔，風流得餘懽。", "緬想蒲柳姿，與君同歲寒。", "一别事瓦裂，令人氣如山。"]'),
('fa3a11e4-1ca1-4d18-9838-4f9537df6f12','次韻集津兄會羣從王敦素宿王立之園明日西征馬上寄示諸人','晁沖之','宋','宋诗','song-poetry','','[]','秋高訪幽居，風急桑未落。',132,'全唐诗/poet.song.69000.json','["秋高訪幽居，風急桑未落。", "天寒雞犬静，地僻門巷闊。", "主人避世賢，自說久棲泊。", "呼兒出罇罍，梨栗亦不惡。", "賓客四五人，談笑動林薄。", "夜闌慘無懽，離憂倏中作。", "伯也天下士，千金輕一諾。", "揮斥楊墨徒，正是鄒魯學。", "如何但銀魚，生事了無託。", "惜哉桃李姿，見笑葵與藿。", "雞鳴驅車行，令人意參錯。"]'),
('841100a9-7dbb-4649-b349-74fdd3789b92','復至新鄉廨寄張穉','晁沖之','宋','宋诗','song-poetry','','[]','驅車出吾廬，落月猶在樹。',168,'全唐诗/poet.song.69000.json','["驅車出吾廬，落月猶在樹。", "我行欲何之，所以河源去。", "去去益以遠，炯炯不可論。", "羣語車鐸間，尚想兒女喧。", "稍涉原上路，漸見柳下村。", "霧草結宿露，風林散朝暾。", "悠悠望蘧廬，我僕欣載犇。", "昔出日在畢，今出壁中昏。", "昔如水上鷗，今如檻中猿。", "所憂負平生，豈但感寒暄。", "明濟十里黄，漪漪見淇園。", "晚投伯氏廨，拓落復何言。", "周覧故時居，愐見松菊存。", "故侶未易招，且自置肴罇。"]'),
('62287674-68c7-46c1-8814-11f74380b149','洗馬次十一兄之道韻','晁沖之','宋','宋诗','song-poetry','','[]','霸橋春水波鱗鱗，橋邊結束何圉人。',131,'全唐诗/poet.song.69000.json','["霸橋春水波鱗鱗，橋邊結束何圉人。", "解鞍傍水入洗馬，飛龍九尺凌漪淪。", "風鬃霧鬣才一沐，玉花照影光滿身。", "月題卻貫黄金勒，更覺閃艷開精神。", "主人貴想不必問，特賜內廄天麒麟。", "即今此物亦安用，燕山萬里胡無塵。", "嫖姚功高自不出，長鳴但踏城西春。", "君不見少陵時已無伯樂，尚有曹將軍寫真。"]'),
('b2c243d0-ce50-4e81-9dcf-f9eb53233185','覽古','晁沖之','宋','宋诗','song-poetry','','[]','遙岑不娛人，蒼莽頗愁絕。',96,'全唐诗/poet.song.69000.json','["遙岑不娛人，蒼莽頗愁絕。", "東南有斷梁，水寒不可涉。", "西闉不欲往，旦莫畏喋褻。", "歸來坐北堂，悠然理書策。", "之人阿堵中，雖死情不隔。", "周公徂東山，仲尼陳蔡厄。", "大儒且不遇，小子何足責。", "時命姑置之，胡爲常促迫。"]'),
('e200c845-01b9-432b-b532-a9b55d2c0178','戲李相如攜婦還金鄉','晁沖之','宋','宋诗','song-poetry','','[]','舍人固多奇，奉璧登章臺。',96,'全唐诗/poet.song.69000.json','["舍人固多奇，奉璧登章臺。", "君王撃缶罷，將軍負荆來。", "長卿束髮時，亦復悦名字。", "一從臨卭游，心迹了不似。", "茂陵未得仕，要是才足依。", "高堂援哀琴，月出載婦歸。", "文君入成都，乃復愧四壁。", "晚見負弩來，良悔抱頸泣。"]'),
('96eaa6c3-1514-45b5-95bd-1908436c5be1','次韻王立之雪中以酒見餉','晁沖之','宋','宋诗','song-poetry','','[]','朔雲慘慘驅朝暄，龍沙一尺人相憐。',160,'全唐诗/poet.song.69000.json','["朔雲慘慘驅朝暄，龍沙一尺人相憐。", "寒猿哀嘯失山木，饑鶴仰唳空舞天。", "當年補天真戲爾，不知修月何時已。", "坐煩耆舊說辛卯，至遣兒童憂甲子。", "城中米價貴如玉，舉家倒廩無斗粟。", "千金狐裘豈易得，百結鶉衣不堪鬻。", "我生但識茅與菅，何曾過眼逢瑤璠。", "辱君新詩問所似，欲辨不敢非忘言。", "開壺酌酒澆我胸，酒酣起舞顔爲紅。", "會見東風掃冰雪，江梅塞柳煩春工。"]'),
('4e37825a-892e-4beb-8e03-f7f52ac2c881','東陽山人僻居','晁沖之','宋','宋诗','song-poetry','','[]','我家京洛間，桂玉資薄産。',216,'全唐诗/poet.song.69000.json','["我家京洛間，桂玉資薄産。", "平生丘壑心，水竹不滿眼。", "清晨有客吳中來，山川指授收奇才。", "笑談長揖波浪下，懷抱遠承巖穴開。", "東陽山人高華隱，豪俠持身復修謹。", "旁山多闢黍秫田，碧溪東流及春醖。", "溪南一畝當翠微，秋風蓴熟菰葉肥。", "龜魚上带藻荇動，鷗鷺下拂芙蓉飛。", "亭陰野塘亦新築，溪山共作窗中綠。", "諸郎年少皆知書，子夜哦詩動修竹。", "歲時冠盖如浮雲，撃鐘鼎食江淮聞。", "愛山自比謝康樂，多士不減春申君。", "我欲沿溪揚小楫，亭邊共醉藤蘿月。", "叩門夜訪君家時，扁舟重載山陰雪。"]'),
('a1c4be65-fd3e-4803-972f-709fd4e780b9','謝沈次律水枕','晁沖之','宋','宋诗','song-poetry','','[]','沈侯筆力鼎可扛，左手截取吳淞江。',112,'全唐诗/poet.song.69000.json','["沈侯筆力鼎可扛，左手截取吳淞江。", "折流來此一尺枕，指麾巨鰐回濤瀧。", "平生性不好長物，舉以遺我嗟無雙。", "呼兒快取蘄笛簟，掃除塵榻移當窗。", "隨眠置我丘壑裏，始信孫郎真枕水。", "我生不出長安城，四十二年塵涴耳。", "領君此枕何灑然，睡起醒心如一洗。"]'),
('f62b353a-9dbe-4f3f-acfb-62a904680b7b','簡江子之求茶','晁沖之','宋','宋诗','song-poetry','','[]','政和密雲不作團，小夸寸許蒼龍蟠。',120,'全唐诗/poet.song.69000.json','["政和密雲不作團，小夸寸許蒼龍蟠。", "金花絳囊如截玉，綠面仿彿松溪寒。", "人間此品那可得，三年聞有終未識。", "老夫於此百不忙，飽食但苦夏日長。", "北窗無風睡不解，齒頰苦澀思清凉。", "故人新除協律郎，交游多在白玉堂，揀牙鬭夸皆飲嘗。", "幸爲傳聲李太府，煩渠折簡買頭綱。"]'),
('bf9e44a6-1761-457c-a3b3-bae37bffa52f','贈張琪君章','晁沖之','宋','宋诗','song-poetry','','[]','春風頗清識，評議登草木。',60,'全唐诗/poet.song.69000.json','["春風頗清識，評議登草木。", "燕麥與菟葵，種種承標目。", "如何桃李姿，結根滯空谷。", "我將俎豆之，折泄恐不欲。", "君且爲此情，吾亦未免俗。"]'),
('f89e27f9-3fba-4cd7-88f7-9d48a6159931','效古别昭德羣從','晁沖之','宋','宋诗','song-poetry','','[]','千載一相逢，相見無浹旬。',120,'全唐诗/poet.song.69000.json','["千載一相逢，相見無浹旬。", "一生能幾别，且復無此身。", "昔别尚可惜，此别重惜之。", "兩髀跨鞍馬，非復少壮時。", "他人怪康强，自覺筋力衰。", "所苦氣如縷，所憂命如絲。", "死生亦大矣，而乃常别離。", "人生一月間，得笑無六七。", "朝爲衆狙喜，莫作枯魚泣。", "已矣泉下人，優哉冢中骨。"]'),
('7b8515b6-d51e-479b-806f-deac46a84dea','睡起','晁沖之','宋','宋诗','song-poetry','','[]','素屏紋簟徹輕紗，睡起冰盤自削瓜。',64,'全唐诗/poet.song.69000.json','["素屏紋簟徹輕紗，睡起冰盤自削瓜。", "風筍微微開綠籜，雨槐細細落黄花。", "經營薄産初無意，補葺疏籬漸有涯。", "待得高秋尋靖老，臨流坐石問丹砂。"]'),
('b9509b0d-cd2a-4257-816a-353febf6424d','送韓溫父','晁沖之','宋','宋诗','song-poetry','','[]','東風未曉放船行，臥唱陽關發渭城。',32,'全唐诗/poet.song.69000.json','["東風未曉放船行，臥唱陽關發渭城。", "老去與人渾惜別，不知何處可忘情。"]'),
('67997ff0-f67b-4603-9e72-4d6c9cf78d16','和四兄閑居感歎有作','晁沖之','宋','宋诗','song-poetry','','[]','掩卷忽不樂，捫心空浩歎。',48,'全唐诗/poet.song.69000.json','["掩卷忽不樂，捫心空浩歎。", "家聲畏淪墜，世態屬艱難。", "月倒迎門屣，風彈挂壁冠。", "蕭然對孤竹，一笑共衰殘。"]'),
('a2194ffc-6ac0-4e64-8433-eec09150bc70','復次韻','晁沖之','宋','宋诗','song-poetry','','[]','出門吾所懶，無客亦何歎。',48,'全唐诗/poet.song.69000.json','["出門吾所懶，無客亦何歎。", "舉世遽如許，孤風良獨難。", "荒蕪蔣詡徑，破敝晏嬰冠。", "興發看山去，書籤記讀殘。"]'),
('cf060794-efd6-4ea0-b3fb-25b4fbcbe383','寄江子之','晁沖之','宋','宋诗','song-poetry','','[]','平生江季子，疏嬾近忘吾。',48,'全唐诗/poet.song.69000.json','["平生江季子，疏嬾近忘吾。", "不啻三年别，如何一字無。", "燒丹岣嶁令，釀酒步兵厨。", "二者将安擇，功名莫浪圖。"]'),
('378c7a06-d7f2-4099-b995-e8ec2d28632b','次四兄韻效李義山雪','晁沖之','宋','宋诗','song-poetry','','[]','莫冬一丈長安雪，壯士臨風獨慨慷。',64,'全唐诗/poet.song.69000.json','["莫冬一丈長安雪，壯士臨風獨慨慷。", "門巷豈無騎馬客，江湖猶有捕魚郎。", "夜平蔡賊兵輕敵，曉入梁園賦擅塲。", "載酒欲尋誰與飲，江梅頭白自悲傷。"]'),
('59f03874-a9fb-4002-966f-1faec372f05c','寄江子我','晁沖之','宋','宋诗','song-poetry','','[]','契闊三秋日，情親四海兄。',48,'全唐诗/poet.song.69000.json','["契闊三秋日，情親四海兄。", "只應常折柳，何必更班荆。", "老把詩爲活，遙將月伴行。", "功名君莫懶，吾病負平生。"]'),
('122aa74f-0008-4bb0-a426-2532f500ac68','戲成','晁沖之','宋','宋诗','song-poetry','','[]','長夏軒窗倚碧岑，人間塵土莫相侵。',32,'全唐诗/poet.song.69000.json','["長夏軒窗倚碧岑，人間塵土莫相侵。", "榴花不得春風力，顔色何如桃杏深。"]'),
('7d64ef83-78b8-4b8d-ad16-2dc1e8c16631','和子我晚歸','晁沖之','宋','宋诗','song-poetry','','[]','七里灣頭宿發飛，六家店上行人稀。',32,'全唐诗/poet.song.69000.json','["七里灣頭宿發飛，六家店上行人稀。", "渡口有船招不得，歸來稚子候柴扉。"]'),
('777a2aa8-f4db-4702-8218-7478339ea6e2','懷蘇門山','晁沖之','宋','宋诗','song-poetry','','[]','昔在新中日，蘇門歲一游。',48,'全唐诗/poet.song.69000.json','["昔在新中日，蘇門歲一游。", "石連沙鑿鑿，水遶竹悠悠。", "丘壑從茲得，江山及此不。", "吾衰思卜筑，城闕恨淹留。"]'),
('149146f4-ed76-478a-9d92-a88dc5a2d3df','二十一兄生女有詩次韻','晁沖之','宋','宋诗','song-poetry','','[]','金盤滿貯華清水，看浴蘭芽玉雪容。',64,'全唐诗/poet.song.69000.json','["金盤滿貯華清水，看浴蘭芽玉雪容。", "自是迺翁懷直道，還爲健婦有家風。", "樹從此日栽成後，酒到他年釀熟中。", "剩買嫁資揮百萬，不悉婚與貴人通。"]'),
('6f8d717f-2f7e-4c7f-8407-02adc0ae2108','决道念八弟得小金印以詩贈之','晁沖之','宋','宋诗','song-poetry','','[]','季也獲金印，籀文秦不如。',48,'全唐诗/poet.song.69000.json','["季也獲金印，籀文秦不如。", "情知非鬼篆，恨不識天書。", "池靜龜游罷，庭閒散鬭餘。", "春風還舊物，疏俊獨憐渠。"]'),
('29a36609-34d1-4b04-84b4-ce9a7373aed2','夜坐','晁沖之','宋','宋诗','song-poetry','','[]','入夜暑氣薄，輝輝星滿空。',48,'全唐诗/poet.song.69000.json','["入夜暑氣薄，輝輝星滿空。", "鈎簾倚新月，卻扇受微風。", "痟混幾時愈，浮楂何處通。", "輕生一快意，波浪五湖中。"]'),
('731ac951-e8f7-47c1-aa8e-08c8c7af7dd9','和人遊李文和園','晁沖之','宋','宋诗','song-poetry','','[]','北李園池推甲第，西岡人物復諸生。',64,'全唐诗/poet.song.69000.json','["北李園池推甲第，西岡人物復諸生。", "乘鸞此地回緱嶺，走馬何人出大明。", "六月火雲無復暑，百年水木有餘清。", "敢陪賓客追前輩，知子能詩近得聲。"]'),
('20155941-f351-4b31-bdb3-dba5fd858da9','送僧','晁沖之','宋','宋诗','song-poetry','','[]','無端伏枕日，不見放舟時。',48,'全唐诗/poet.song.69000.json','["無端伏枕日，不見放舟時。", "晚得平安報，初成送别詩。", "山深歸履急，江闊度杯遲。", "定許同香火，終參惠遠師。"]'),
('43874460-9f8d-44a8-b5a6-ce3d1e0c3bfa','樂府二首  其一','晁沖之','宋','宋诗','song-poetry','','[]','病來飲不敵羣豪，笑岸紗巾卸錦袍。',32,'全唐诗/poet.song.69000.json','["病來飲不敵羣豪，笑岸紗巾卸錦袍。", "一座空煩春筍手，玉盃乳酪貯櫻桃。"]'),
('fabd826d-5769-4bfc-9bd4-69a148f8429a','樂府二首  其二','晁沖之','宋','宋诗','song-poetry','','[]','自摘酴醾滿架空，擬將豪氣敵春風。',32,'全唐诗/poet.song.69000.json','["自摘酴醾滿架空，擬將豪氣敵春風。", "欲知盞面玻瓈闊，看照紅顔在酒中。"]'),
('4d28e9a9-cac3-4513-9802-562777960aa8','傷心','晁沖之','宋','宋诗','song-poetry','','[]','沙路朱轓想馭軒，傷心歲月似星奔。',64,'全唐诗/poet.song.69000.json','["沙路朱轓想馭軒，傷心歲月似星奔。", "平泉有墅空流水，綠野無人但繞垣。", "九老畫圖傳盛事，四朝書史載殊恩。", "如何圬者持鏝過，已向比鄰問子孫。"]'),
('27474c49-67ab-4b7a-8ee8-3683900be79e','怡怡軒贈王次翁','晁沖之','宋','宋诗','song-poetry','','[]','先生骨老勁如松，柴米辛勤只自供。',64,'全唐诗/poet.song.69000.json','["先生骨老勁如松，柴米辛勤只自供。", "每笑燃萁何太急，應憐舂粟不相容。", "雖能有弟同斯樂，忍使在兒繼此蹤。", "已約伯兄同卜筑，連牆投老願相從。"]'),
('a6cdab52-3c9f-49a1-ab37-5ffa1186cc5e','亭成','晁沖之','宋','宋诗','song-poetry','','[]','故里佗年隱，新亭此日成。',48,'全唐诗/poet.song.69000.json','["故里佗年隱，新亭此日成。", "江山俱有助，草木盡知名。", "圃菊黄浮酒，汀蓴紫泛羹。", "松風如與便，願許從諸生。"]'),
('a2bf630e-011c-4ef9-8094-c82a338fbe18','至日','晁沖之','宋','宋诗','song-poetry','','[]','短晷催長至，新晴改故陰。',48,'全唐诗/poet.song.69000.json','["短晷催長至，新晴改故陰。", "風霜游子鬢，節序異鄉心。", "合坐呼盧轉，分曹舉白深。", "百年家魏闕，存沒一沾襟。"]'),
('80a044cf-e056-4e35-80dc-19669917ce1f','贈山人沈廣漢','晁沖之','宋','宋诗','song-poetry','','[]','禪房白几静無塵，野服黄冠意甚真。',64,'全唐诗/poet.song.69000.json','["禪房白几静無塵，野服黄冠意甚真。", "避世全生深得策，閉門謝客亦高人。", "忍情斷酒非關病，隨意收書不計貧。", "近約嵩陽陳叔易，趁移丹竈過殘春。"]'),
('5abe6079-0190-4a52-83e8-39504dbee6c9','龍興道中','晁沖之','宋','宋诗','song-poetry','','[]','澗道垂黄花，山城擁紅葉。',24,'全唐诗/poet.song.69000.json','["澗道垂黄花，山城擁紅葉。", "人爭小舟渡，馬就平沙涉。"]'),
('f5d80a7d-f089-4615-83ac-8fd6877253f8','敦素有以書局處之者作詩迎之','晁沖之','宋','宋诗','song-poetry','','[]','君王側席訪詞臣，萬里江湖賀季真。',64,'全唐诗/poet.song.69000.json','["君王側席訪詞臣，萬里江湖賀季真。", "翰苑向來非此老，道山何處得斯人。", "朝回金馬門前曉，宴罷銅駝陌上春。", "底事年年最如意，春風還試綵衣新。"]'),
('5250a4b6-9f03-48d1-947c-6a70e1246775','立春','晁沖之','宋','宋诗','song-poetry','','[]','巧勝金花真樂事，堆盤細菜亦宜人。',32,'全唐诗/poet.song.69000.json','["巧勝金花真樂事，堆盤細菜亦宜人。", "自慚白髮嘲吾老，不上譙門看打春。"]'),
('2b2ae351-e084-4bc3-a303-37c1f6d62ad5','和集津兄謝王立之紅絲花','晁沖之','宋','宋诗','song-poetry','','[]','故園桃李秋搖落，掃地無花可惱公。',32,'全唐诗/poet.song.69000.json','["故園桃李秋搖落，掃地無花可惱公。", "近說城南王子妓，亦持紅拂劇西風。"]'),
('b5f9ac3b-5450-475f-89cb-17f700a9d5b1','又次韻謝王立之惠紅絲花','晁沖之','宋','宋诗','song-poetry','','[]','老來嗜酒無賓主，我醉應眠不遣卿。',32,'全唐诗/poet.song.69000.json','["老來嗜酒無賓主，我醉應眠不遣卿。", "如許此花同九日，爲君採掇笑淵明。"]'),
('04e8870b-b197-471a-b397-67aac538ebdd','謝任伯久無書常子然寄茶謝之因簡任伯','晁沖之','宋','宋诗','song-poetry','','[]','諫議茶猶送，郎官迹已疏。',24,'全唐诗/poet.song.69000.json','["諫議茶猶送，郎官迹已疏。", "斜封三道印，不奉一行書。"]'),
('c9ea7a0f-f7bd-434c-9547-fe7d1fa3f4c6','客有駑馬不肯借詩誚之','晁沖之','宋','宋诗','song-poetry','','[]','胡兒少欲立奇功，貴買西宛玉面驄。',64,'全唐诗/poet.song.69000.json','["胡兒少欲立奇功，貴買西宛玉面驄。", "金躞蹀微鳴躡影，錦連錢不動追風。", "庭槐洗立清陰下，沙路調行返照中。", "出郭借人乘豈肯，自誇騎入大明宮。"]'),
('5a647f2a-b672-4de9-b7e8-0e311b3f4cce','自然詩','晁沖之','宋','宋诗','song-poetry','','[]','先生手不廢經營，白屋憑虚結此亭。',64,'全唐诗/poet.song.69000.json','["先生手不廢經營，白屋憑虚結此亭。", "燕夌兔絲侵密坐，南箕北斗挂疏櫺。", "青松夾日交傾盖，翠柏分風倚列屏。", "莫道君家無長物，案頭燈火有流螢。"]'),
('48db232e-00d6-471e-b384-4673d383301b','避暑普淨院','晁沖之','宋','宋诗','song-poetry','','[]','夭矯柏如龍，清幽閟一宮。',48,'全唐诗/poet.song.69000.json','["夭矯柏如龍，清幽閟一宮。", "庭無御史雨，門有大王風。", "今日名天下，羣公坐此中。", "阿戎相就語，歷歷見元豐。"]'),
('6340ee95-9d7a-468a-8442-de9f082211e0','送惠純上人遊閩','晁沖之','宋','宋诗','song-poetry','','[]','蚤聽閩人說土風，此身嘗欲到閩中。',64,'全唐诗/poet.song.69000.json','["蚤聽閩人說土風，此身嘗欲到閩中。", "春溝水動茶花白，夏谷雲生荔子紅。", "襟带九江山不斷，梯航百粤海相通。", "北窗夜展圖經看，手自題書寄遠公。"]'),
('a1a8cf8a-c286-434a-87a4-68ed480efc6a','道中','晁沖之','宋','宋诗','song-poetry','','[]','北風吹雨不能晴，羸病人騎瘦馬行。',32,'全唐诗/poet.song.69000.json','["北風吹雨不能晴，羸病人騎瘦馬行。", "鬚髪向來渾白盡，半緣憂患半多情。"]'),
('f66e8b30-cdff-4f70-a46b-2b851ac6beec','行泌水上','晁沖之','宋','宋诗','song-poetry','','[]','肅肅郊原靜，牛羊草樹間。',48,'全唐诗/poet.song.69000.json','["肅肅郊原靜，牛羊草樹間。", "石磯寒不掃，水閣靜常關。", "故里無消息，孤城絕往還。", "多愁獨來此。", "猶得見河山。"]'),
('296617ad-d505-4267-91aa-a9c1ba21a377','送王敦素','晁沖之','宋','宋诗','song-poetry','','[]','龍蟠山色引衡廬，霜落江清影碧虚。',64,'全唐诗/poet.song.69000.json','["龍蟠山色引衡廬，霜落江清影碧虚。", "鼓枻厭騎沙苑馬，行厨欲食武昌魚。", "緩歌玉樹翻新曲，趣入金鑾續舊書。", "官達故人稀會面，君來相見肯如初。"]'),
('95c819cd-868d-475d-ab3b-1725aa3c33db','次韻江子我蠟梅二首  其一','晁沖之','宋','宋诗','song-poetry','','[]','步屧穿花醉曉風，翻枝摘葉興何窮。',32,'全唐诗/poet.song.69000.json','["步屧穿花醉曉風，翻枝摘葉興何窮。", "他年上苑求佳種，越白江紅掃地空。"]'),
('412822f5-178c-46cb-822b-e667f6df9f3d','次韻江子我蠟梅二首  其二','晁沖之','宋','宋诗','song-poetry','','[]','江城仍似錦城無，半額輕黄笑越姝。',32,'全唐诗/poet.song.69000.json','["江城仍似錦城無，半額輕黄笑越姝。", "我亦少花如杜老，舍南爲乞兩三株。"]'),
('396d787b-2fac-4327-8023-0dc43cef23d1','次韻集津兄懷嵩少示王立之','晁沖之','宋','宋诗','song-poetry','','[]','早聞三十六峰前，願寄茅茨一澗邊。',64,'全唐诗/poet.song.69000.json','["早聞三十六峰前，願寄茅茨一澗邊。", "谷轉馬蹄山繚繞，嵓開虎口樹嬋娟。", "陽坡日煖宜瓜地，陰嶺天寒熟芋田。", "便好與公相隱去，不宜相對尚茫然。"]'),
('d0a55756-4717-402d-8adf-6e673be20192','和王立之蠟梅二首  其一','晁沖之','宋','宋诗','song-poetry','','[]','茅簷竹塢兩幽奇，岸幘尋花醉亦知。',32,'全唐诗/poet.song.69000.json','["茅簷竹塢兩幽奇，岸幘尋花醉亦知。", "崖蜜已成蜂去盡，夜寒惟有露房垂。"]'),
('14b4b206-f0ba-4157-831e-acd56ad66cf6','和王立之蠟梅二首  其二','晁沖之','宋','宋诗','song-poetry','','[]','老去攀翻興益奇，招攜風月作新知。',32,'全唐诗/poet.song.69000.json','["老去攀翻興益奇，招攜風月作新知。", "但令春釀皆如此，百罰深盃亦倒垂。"]'),
('c17bf0e0-1f61-4c9f-b171-0fbdad860f54','滎澤驛阻雪','晁沖之','宋','宋诗','song-poetry','','[]','去年冬不雪，今雪太匆匆。',48,'全唐诗/poet.song.69000.json','["去年冬不雪，今雪太匆匆。", "輕薄愁兼雨，欹斜怯受風。", "雁依寒浦靜，鴉噪暮林空。", "憔悴西征客，惟應白髪同。"]'),
('b12b843d-4414-4444-9111-c716c90bfe4b','秋雨感事','晁沖之','宋','宋诗','song-poetry','','[]','苦雨荒秋宅，寒生木葉悲。',48,'全唐诗/poet.song.69000.json','["苦雨荒秋宅，寒生木葉悲。", "半垂藤護壁，中缺蔓穿籬。", "書校時開帙，壺提日繫絲。", "儒冠吾已悞，何責五男兒。"]'),
('a499e306-db83-4ee1-bbcb-3f5aeee42121','次二十一兄九日韻','晁沖之','宋','宋诗','song-poetry','','[]','清秋九日至，晚菊兩三開。',48,'全唐诗/poet.song.69000.json','["清秋九日至，晚菊兩三開。", "愁把他鄉酒，思登故國臺。", "賜懷朝士寵，詩想從臣才。", "向晚能無淚，飄飄雁影來。"]'),
('eaa633d2-5ec1-408f-ace5-3957659682d8','問訊次九日韻','晁沖之','宋','宋诗','song-poetry','','[]','問訊西南戍，提封莫遠開。',48,'全唐诗/poet.song.69000.json','["問訊西南戍，提封莫遠開。", "休傳通蜀道，端可棄輪臺。", "擬上平戎策，慚無屬國才。", "何須千里馬，遠自渥注來。"]'),
('3722ebc4-1ca4-4e54-8b32-5b5182353a16','積善堂詩','晁沖之','宋','宋诗','song-poetry','','[]','星次朝當赦，龍符夜改元。',180,'全唐诗/poet.song.69000.json','["星次朝當赦，龍符夜改元。", "忽傳優老詔，周及庶臣門。", "細札頒殊禮，陪封錫異恩。", "大酺堪一笑，束帛不須論。", "緬想吾宗盛，恭惟母德尊。", "孝忠兼仲子，辭翰競諸孫。", "掖誥金鸞潤，宮衣翠翟溫。", "萬錢賓客賀，五色帝王言。", "諼草開新夏，蟠桃屬舊樽。", "曲迎團扇度，舞接綵衣翻。", "冰下看魚尾，霜邊見筍根。", "英聲彤管在，繪事畫屏存。", "有客依同姓，逢人問故園。", "淹留驚伏臘，俛仰媿晨昏。", "西望浮雲合，巾車擬載奔。"]'),
('d77d5bb1-0253-4035-88c7-372f9db137aa','春日二首  其一','晁沖之','宋','宋诗','song-poetry','','[]','男兒更老氣如虹，知鬢何嫌似斷蓬。',32,'全唐诗/poet.song.69000.json','["男兒更老氣如虹，知鬢何嫌似斷蓬。", "欲問桃花借顔色，未甘着笑向春風。"]'),
('e635fdd9-e558-4223-94f7-4b9e3a5d4fdd','春日二首  其二','晁沖之','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u60dc\u6625", "\u5b8b\u8bd7", "\u5199\u666f"]','陰陰溪曲綠交加，小雨翻萍上淺沙。',32,'全唐诗/poet.song.69000.json','["陰陰溪曲綠交加，小雨翻萍上淺沙。", "鵝鴨不知春去盡，爭隨流水趁桃花。"]'),
('42bb7ccc-a207-4dcf-80c8-5e5a8718fe67','次二十一兄韻','晁沖之','宋','宋诗','song-poetry','','[]','憶在長安最少年，酒酣到處一欣然。',64,'全唐诗/poet.song.69000.json','["憶在長安最少年，酒酣到處一欣然。", "獵回漢苑秋高夜，飲罷秦臺雪作天。", "不擬伊優陪殿下，相隨于蔿過樓前。", "如今白髮山城裏，宴坐觀空習斷緣。"]'),
('9056f5ed-3c3b-4eee-8d21-a4a94f54ec1a','别飾道二十弟','晁沖之','宋','宋诗','song-poetry','','[]','少傅三朝老，文章壯九州。',48,'全唐诗/poet.song.69000.json','["少傅三朝老，文章壯九州。", "賦詩資政殿，賜字太清樓。", "拔燭辭軒陛，簪花近冕旒。", "慶門吾老矣，華國汝能不。"]'),
('0e016e00-4ca4-438d-9057-b77666078a8e','暮春','晁沖之','宋','宋诗','song-poetry','','[]','濺濺流水曲穿沙，林葉深深不過鴉。',32,'全唐诗/poet.song.69000.json','["濺濺流水曲穿沙，林葉深深不過鴉。", "自恨春來渾不識，殷勤着地拾殘花。"]'),
('a7b3735e-7ba1-4fa7-83e1-016c9fa55d8d','別息道士二十弟','晁沖之','宋','宋诗','song-poetry','','[]','中令有清德，風流二百年。',48,'全唐诗/poet.song.69000.json','["中令有清德，風流二百年。", "舉家惟食粥，絕口不言錢。", "里閈容吾老，庭闈賴汝賢。", "陶丘過范蠡，莫泛五湖船。"]'),
('79edabcd-bbe8-45dc-9be3-f74eace92045','和江子我竹夫人','晁沖之','宋','宋诗','song-poetry','','[]','黄藤白簟倦呼盧，高卧南窗示楷模。',64,'全唐诗/poet.song.69000.json','["黄藤白簟倦呼盧，高卧南窗示楷模。", "郭芍藥情元最密，鄭櫻桃迹近相疏。", "下帷度日甘同夢，隱几終年得異書。", "晚向禪房陪杖屨，清秋霜霰意如何。"]'),
('dbf23786-cee9-49d2-bd46-bf66ff7d8ab8','戲留次褒三十三弟','晁沖之','宋','宋诗','song-poetry','','[]','白下春泥尚未乾，汴流更待小潺湲。',32,'全唐诗/poet.song.69000.json','["白下春泥尚未乾，汴流更待小潺湲。", "不知汝定成行不，寒食今無數日間。"]'),
('63c36b4b-bcad-45a1-bb8d-51612d0e6bdf','行武涉田中','晁沖之','宋','宋诗','song-poetry','','[]','慣習兒童喜，從容父老懽。',48,'全唐诗/poet.song.69000.json','["慣習兒童喜，從容父老懽。", "桔橰看俯仰，稼穡愧艱難。", "荷葉生池岸，蒲萄落井幹。", "求田如得此，當爲駐征鞍。"]'),
('0d884d8e-a8bc-4588-b0fa-d40280418b1b','懷濟北弟姪','晁沖之','宋','宋诗','song-poetry','','[]','久客思吾子，生涯滯故鄉。',48,'全唐诗/poet.song.69000.json','["久客思吾子，生涯滯故鄉。", "獨攜高士傳，翻憶紫香囊。", "合榻言猶在，同堂樂未央。", "翩翩春草夢，隨意遶池塘。"]'),
('82b207fa-49ff-42ae-890b-5bcb926a369d','王敦素許紙不至戲簡促之','晁沖之','宋','宋诗','song-poetry','','[]','摩娑垢面戲陶泓，拂拭蒼髯笑管城。',32,'全唐诗/poet.song.69000.json','["摩娑垢面戲陶泓，拂拭蒼髯笑管城。", "已與陳玄俱絕倒，從君更召楮先生。"]'),
('d54b3aa5-b567-4d6a-b700-e9c1ec1296f7','别昭德弟愴然傷懷','晁沖之','宋','宋诗','song-poetry','','[]','吾廬去汝到何期，四十年間此别離。',64,'全唐诗/poet.song.69000.json','["吾廬去汝到何期，四十年間此别離。", "合抱樹元從舊種，幾叢菊始自新移。", "老無兄弟飄零日，遠有公卿曠絕時。", "努力不思勤負米，欲求三徑可從誰。"]'),
('262dfb73-6874-46e1-99af-7107ae1ad865','别飾道二十弟','晁沖之','宋','宋诗','song-poetry','','[]','飄零南北一衰門，知是澶淵五世孫。',64,'全唐诗/poet.song.69000.json','["飄零南北一衰門，知是澶淵五世孫。", "嗟我獨無兄弟在，憐君尚有典型存。", "老身素苦貧常瘦，病目仍緣哭轉昏。", "他日汝歸馳駟馬，訪吾肯過浣花村。"]'),
('0edd1f39-568d-415d-8a43-2fc7e7fe8eaa','和虞道二十三弟','晁沖之','宋','宋诗','song-poetry','','[]','千載風流賀秘書，也知今有此人無。',32,'全唐诗/poet.song.69000.json','["千載風流賀秘書，也知今有此人無。", "吾家父子真相似，不愧朝廷乞鑑湖。"]'),
('23ea0309-5522-40d5-8072-171e7422b320','和葉甥少藴內翰重開西湖見寄二首  其一','晁沖之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','使君重鑿西湖罷，也復封詩寄我來。',64,'全唐诗/poet.song.69000.json','["使君重鑿西湖罷，也復封詩寄我來。", "洲上新題花島處，苑中舊體柏梁臺。", "風烟直覺鍾山近，魚鳥渾疑澗水開。", "揮翰玉堂還有日，行春停騎且留杯。"]'),
('31503438-45f4-4cb4-a8fe-04ac8f6f9d89','和葉甥少藴內翰重開西湖見寄二首  其二','晁沖之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一麾偃蹇江湖去，五馬侵尋觀闕來。',64,'全唐诗/poet.song.69000.json','["一麾偃蹇江湖去，五馬侵尋觀闕來。", "就日金波通漢苑，望雲玉澗斷蘇臺。", "自迎檝立看時渡，手種花行到處開。", "笑語風流韓别駕，莫令鸚鵡訴餘杯。"]'),
('f22d7bb4-f6f4-421d-8acd-d8c5d16dd422','和寄葉甥少藴內翰見招','晁沖之','宋','宋诗','song-poetry','','[]','翰林赫奕今如此，莫道人惟舊雨來。',64,'全唐诗/poet.song.69000.json','["翰林赫奕今如此，莫道人惟舊雨來。", "龐老終身遠州府，劉郎何面向春臺。", "園宜杏子非時結，溪闊梅花過日開。", "兩地聲聞無百里，相望一覆手中杯。"]'),
('b6a7385c-738f-4dee-bc0b-c3ceb5640223','次韻再答少藴知府甥和四兄長句并見寄二首  其一','晁沖之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','錦袍昔是詩成得，别墅今非棋賭來。',64,'全唐诗/poet.song.69000.json','["錦袍昔是詩成得，别墅今非棋賭來。", "山蔚藍光交抱舍，水桃花色合圍臺。", "通人竹塢深深入，謝客松扉遠遠開。", "定與西湖争勝負，只應惟欠使君杯。"]'),
('8a88bfd3-8476-4917-8af9-f4cea10cc375','次韻再答少藴知府甥和四兄長句并見寄二首  其二','晁沖之','宋','宋诗','song-poetry','','[]','塵埃自與青雲斷，歲月誰令白髮來。',64,'全唐诗/poet.song.69000.json','["塵埃自與青雲斷，歲月誰令白髮來。", "數口無歸關外客，一春多病幾登臺。", "常閒水上鷗從遠，只老籠中鶴任開。", "日日避愁無處脫，直須到手不停杯。"]'),
('1315d349-de5c-4484-be9f-a1512fc0ee98','復和少藴內翰甥兼謝伯藴通判兄再贈','晁沖之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖波浪還佳色，風物悲人老可驚。',64,'全唐诗/poet.song.69000.json','["西湖波浪還佳色，風物悲人老可驚。", "游接竹林公對叔，夢迷春色我思兄。", "酒沽鸚鵡杯行盡，詩傍蟾蜍研立成。", "壯思不逢韓吏部，高名誰伴謝宣城。"]'),
('d82d65fd-dc3c-49d0-b248-e3d733558ea2','復用韻','晁沖之','宋','宋诗','song-poetry','','[]','史奏德星今復聚，郷評月旦昔何驚。',64,'全唐诗/poet.song.69000.json','["史奏德星今復聚，郷評月旦昔何驚。", "潁川人望須公守，荀氏家聲付此兒。", "湖影龜魚同聚散，棠陰燕雀半生成。", "若爲修禊無絲竹，古調新詩唱渭城。"]'),
('fa0f7199-bccd-4ce8-a384-579b6412e5aa','僧舍小山三首  其一','晁沖之','宋','宋诗','song-poetry','','[]','此老絕蕭洒，久參曹洞禪。',48,'全唐诗/poet.song.69000.json','["此老絕蕭洒，久參曹洞禪。", "胸中有丘壑，左手取山川。", "樹小風聲細，巖深日影圓。", "江湖不歸客，相對一茫然。"]'),
('eaccfe1a-06ca-495b-81df-8d9d4f2dd3a9','僧舍小山三首  其二','晁沖之','宋','宋诗','song-poetry','','[]','愛此聚沙戲，知自法王孫。',48,'全唐诗/poet.song.69000.json','["愛此聚沙戲，知自法王孫。", "一運郢斤手，都無禹鑿痕。", "藤梢未挂壁，荷葉欲生盆。", "笑問山陰道，潛通何處村。"]'),
('3759443e-9813-4e02-b738-c987c0a2cb84','僧舍小山三首  其三','晁沖之','宋','宋诗','song-poetry','','[]','爛石有佳色，禪房叠更幽。',48,'全唐诗/poet.song.69000.json','["爛石有佳色，禪房叠更幽。", "九疑峰不斷，十字水長流。", "枕簟日逃暑，軒窗時卧遊。", "吾衰更何往，只此對湯休。"]'),
('a4db28eb-2fb3-4b38-8c25-510b86960a86','挽十六叔父朝散  其一','晁沖之','宋','宋诗','song-poetry','','[]','慘淡魚山路，公歸膺獲麟。',36,'全唐诗/poet.song.69000.json','["慘淡魚山路，公歸膺獲麟。", "車送逾千兩，人哀備百身。", "傷心蒿里夜，揮淚竹林春。"]'),
('43d850a5-8848-4e00-a604-0a1075b8a3f0','挽十六叔父朝散  其二','晁沖之','宋','宋诗','song-poetry','','[]','翰墨傳名教，公深有世風。',48,'全唐诗/poet.song.69000.json','["翰墨傳名教，公深有世風。", "斯文今乃喪，吾道亦何窮。", "埋玉嗟何及，揮金樂未終。", "子孫知心盛，斷獄有陰功。"]'),
('694ab795-4d10-4bb3-b32b-5b502cbe889b','和二十二弟二首  其一','晁沖之','宋','宋诗','song-poetry','','["\u592a\u6e56"]','静處偷看肘後書，幽棲古有此人無。',32,'全唐诗/poet.song.69000.json','["静處偷看肘後書，幽棲古有此人無。", "綠蓑青箬非吾事，白浪狂風滿太湖。"]'),
('208b1874-6612-468a-b768-deb18f25bbea','和二十二弟二首  其二','晁沖之','宋','宋诗','song-poetry','','[]','襟抱恢疏老更寛，笑談終夕盡君歡。',32,'全唐诗/poet.song.69000.json','["襟抱恢疏老更寛，笑談終夕盡君歡。", "主人更有桃花面，病眼其如隔霧看。"]'),
('d8bb3ac5-1193-4d35-9b25-e12fd192f742','題超化寺壁','晁沖之','宋','宋诗','song-poetry','','[]','曲池風定碧瀾平，小白魚如鏡裏行。',32,'全唐诗/poet.song.69000.json','["曲池風定碧瀾平，小白魚如鏡裏行。", "水竹再來應試我，壁間不用更題名。"]'),
('cebf8c92-0454-4a92-9dea-0bf9dbab3db0','夜行','晁沖之','宋','宋诗','song-poetry','','[]','老去功名意轉疏，獨騎瘦馬取長途。',32,'全唐诗/poet.song.69000.json','["老去功名意轉疏，獨騎瘦馬取長途。", "孤村到曉猶燈火，知有人家夜讀書。"]'),
('d29ee731-b3e4-4aca-83ea-2c99613b5807','和虞道二十三弟','晁沖之','宋','宋诗','song-poetry','','[]','向别已復久，此懷誰與明。',48,'全唐诗/poet.song.69000.json','["向别已復久，此懷誰與明。", "書來慰吾意，詩重識君情。", "放鶴惜未到，飛鴻今尚横。", "何由一隨汝，端爲薄浮名。"]'),
('fcce0da0-a37a-452a-84a1-fad2598ac26b','留别江子之','晁沖之','宋','宋诗','song-poetry','','[]','盡室飄零去上都，試於溱洧卜幽居。',64,'全唐诗/poet.song.69000.json','["盡室飄零去上都，試於溱洧卜幽居。", "不從刺史求彭澤，敢向君王乞鏡湖。", "平日甚豪今潦倒，少年最樂晚崎嶇。", "故人鼎貴甘相絕，别後君須寄一書。"]'),
('ba68f0d1-eda7-4f0e-b5e5-8d9a3e8ca14b','寄王立之','晁沖之','宋','宋诗','song-poetry','','[]','臘雨城南宅，衝寒憶屢陪。',48,'全唐诗/poet.song.69000.json','["臘雨城南宅，衝寒憶屢陪。", "拊憐庭下石，問訊竹間梅。", "諸子譍門立，羣公跋馬回。", "不知多病後，誰與倒罇罍。"]'),
('7e4044cb-1057-4fd8-a788-6b09046285e0','讀陳平傳','晁沖之','宋','宋诗','song-poetry','','[]','劉郎白首尚多疑，百戰功臣迹轉危。',32,'全唐诗/poet.song.69000.json','["劉郎白首尚多疑，百戰功臣迹轉危。", "致使文成謝封邑，未如還薦魏無知。"]'),
('802d835c-20e5-4016-919e-d6a4ce25ec0d','次韻江子我見寄','晁沖之','宋','宋诗','song-poetry','','[]','敢恨新居僻，深懷故國尊。',48,'全唐诗/poet.song.69000.json','["敢恨新居僻，深懷故國尊。", "耕耘得遺物，版築尚頽垣。", "溪隔城南寺，崖通市北門。", "他時如訪我，但認語音存。"]'),
('232ef554-a378-4f9d-b36e-43af80af59bd','朱少章曝麥爲雨所漂','晁沖之','宋','宋诗','song-poetry','','[]','看書不覺雨如澠，稚子驚呼妻怒嗔。',32,'全唐诗/poet.song.69000.json','["看書不覺雨如澠，稚子驚呼妻怒嗔。", "豈意持竿護雞者，翻同挾策牧羊人。"]'),
('0fce2ddc-bc6f-4250-a866-3d708cef1e43','過陳無己墓','晁沖之','宋','宋诗','song-poetry','','[]','鎖門脫落封將盡，題壁污漫字不分。',32,'全唐诗/poet.song.69000.json','["鎖門脫落封將盡，題壁污漫字不分。", "我亦嘗參諸弟子，往來徒步拜公墳。"]'),
('75d2d6fb-5068-4d1d-811c-aceacf417265','初來東里','晁沖之','宋','宋诗','song-poetry','','[]','乘流從此去，河漢失清都。',48,'全唐诗/poet.song.69000.json','["乘流從此去，河漢失清都。", "送騎沙邊散，征帆雨外孤。", "挾雌棲隴雉，生子哺巢烏。", "宇宙将安往，飄飄盡畏途。"]'),
('5e1849b3-2be2-465f-b205-6ab9627cb4b8','至東里次前韻','晁沖之','宋','宋诗','song-poetry','','[]','茂陵家四壁，不必在成都。',48,'全唐诗/poet.song.69000.json','["茂陵家四壁，不必在成都。", "老矣招魂苦，傷哉問影孤。", "市中寧有虎，屋上豈無烏。", "四海皆行路，吾何必此途。"]'),
('4322ec62-d968-4bce-9669-eb6278a905fc','都下追感往昔因成二首  其一','晁沖之','宋','宋诗','song-poetry','','[]','少年使酒走京華，縱步曾遊小小家。',64,'全唐诗/poet.song.69000.json','["少年使酒走京華，縱步曾遊小小家。", "看舞霓裳羽衣曲，聽歌玉樹後庭花。", "門侵楊柳垂珠箔，窗對櫻桃卷碧紗。", "坐客半驚隨逝水，主人星散落天涯。"]'),
('16e3f3b5-fe0d-4abb-83c7-026d265b29a5','都下追感往昔因成二首  其二','晁沖之','宋','宋诗','song-poetry','','[]','春風踏月過章華，青鳥雙邀阿母家。',64,'全唐诗/poet.song.69000.json','["春風踏月過章華，青鳥雙邀阿母家。", "繫馬柳低當戶葉，迎人桃出隔牆花。", "鬢深釵暖雲侵臉，臂薄衫寒玉映紗。", "莫作一生惆悵事，鄰州不在海西涯。"]'),
('6f7d2a68-4ad6-423f-9993-68351312b2d4','次韻四兄蘆  其一','晁沖之','宋','宋诗','song-poetry','','[]','公如柳柳州，柳橋如柳浪。',24,'全唐诗/poet.song.69000.json','["公如柳柳州，柳橋如柳浪。", "惱殺涉溱人，望望不可上。"]'),
('fecf3134-1d91-4e98-920b-21375c1650fe','次韻四兄蘆  其二','晁沖之','宋','宋诗','song-poetry','','[]','碧蘆自愁絕，黄蘆正枯折。',24,'全唐诗/poet.song.69000.json','["碧蘆自愁絕，黄蘆正枯折。", "宵征雁影孤，墮此橋下月。"]'),
('87c1f846-f7aa-446f-80c4-7916c3215a7c','次韻陳叔易蘆橋柳橋二首  其一','晁沖之','宋','宋诗','song-poetry','','[]','落日河梁上，遲留客去時。',24,'全唐诗/poet.song.69000.json','["落日河梁上，遲留客去時。", "近鄰無遠送，莫說最長枝。"]'),
('6990fa56-4d2c-4bd7-bc9a-84ab98332abe','次韻陳叔易蘆橋柳橋二首  其二','晁沖之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','橋闊狹如馬，蘆高低似人。',24,'全唐诗/poet.song.69000.json','["橋闊狹如馬，蘆高低似人。", "白蘋洲上客，枉恨洞庭春。"]'),
('6710086f-3638-4c5f-a3ca-0887fe408627','次韻朱少章蘆橋柳橋二首  其一','晁沖之','宋','宋诗','song-poetry','','[]','蘆橋復柳橋，蘆枯柳可愛。',24,'全唐诗/poet.song.69000.json','["蘆橋復柳橋，蘆枯柳可愛。", "不厭春與秋，主人客有待。"]'),
('34c0c785-65b7-4083-a30c-f928b19d361e','次韻朱少章蘆橋柳橋二首  其二','晁沖之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭生白波，隴首起黄雲。',24,'全唐诗/poet.song.69000.json','["洞庭生白波，隴首起黄雲。", "漁舟霧裏見，羌笛月中聞。"]'),
('278a9bfb-b09c-4805-af43-9e64d0485fd2','挽蔡晉如','晁沖之','宋','宋诗','song-poetry','','[]','南部清笳咽，東門素旐飛。',48,'全唐诗/poet.song.69000.json','["南部清笳咽，東門素旐飛。", "如何一老漢，不及二疏歸。", "宇宙那復見，死生從此違。", "吾年未四十，已嘆故人稀。"]'),
('1934c988-bb90-4e9f-b1a4-c97a4ac5a2b8','夏室','晁沖之','宋','宋诗','song-poetry','','[]','夏室不禦暑，竹陰新未交。',48,'全唐诗/poet.song.69000.json','["夏室不禦暑，竹陰新未交。", "幽花時結子，晚燕續開巢。", "午夢還高枕，晨炊出近庖。", "此生吾自了，客至莫相嘲。"]'),
('a0684644-dede-41cf-9d18-39a89c852f1e','謾興','晁沖之','宋','宋诗','song-poetry','','[]','苻郎傳檄度江南，謝老風流倚翠嵐。',32,'全唐诗/poet.song.69000.json','["苻郎傳檄度江南，謝老風流倚翠嵐。", "但自圍棋君莫問，顧輪別墅乞羊曇。"]'),
('0ea94acc-adb1-4d3d-9bdb-ec9f311e73d3','過鴻儀寺','晁沖之','宋','宋诗','song-poetry','','[]','折葦枯荷倒浦風，黑雲垂雨掛長虹。',32,'全唐诗/poet.song.69000.json','["折葦枯荷倒浦風，黑雲垂雨掛長虹。", "山僧生養池魚看，不許遊人學釣翁。"]'),
('ed306b4a-091a-45dd-9371-03ccc2a5f858','答韓君表','晁沖之','宋','宋诗','song-poetry','','[]','百年鄠杜家相近，人物凋零我獨驚。',64,'全唐诗/poet.song.69000.json','["百年鄠杜家相近，人物凋零我獨驚。", "但見少陵能繼祖，不聞小陸可優兄。", "終朝詩賦遒仍鬱，老去文章健更成。", "敢擬濟河輕一戰，隱然望已怯長城。"]'),
('456720b2-3bf3-4101-b106-0fe4d430fa13','次君表韻答葉少藴甥','晁沖之','宋','宋诗','song-poetry','','[]','老去幽棲誰比數，傳君詩一邑人驚。',64,'全唐诗/poet.song.69000.json','["老去幽棲誰比數，傳君詩一邑人驚。", "敢叨禮亦推甥舅，借問年猶愧弟兄。", "今日蓍龜真有望，終身木雁兩無成。", "凡才那可供□去，目送飛霞向赤城。"]'),
('52adca3e-1393-4594-adbb-a49afb8ed78f','與秦少章題漢江遠帆五首  其一','晁沖之','宋','宋诗','song-poetry','','[]','楚山全控蜀，漢水半呑吳。',24,'全唐诗/poet.song.69000.json','["楚山全控蜀，漢水半呑吳。", "老眼知佳處，曾看八景圖。"]'),
('d5ccd717-a27b-48b9-8682-56efe76ab709','與秦少章題漢江遠帆五首  其二','晁沖之','宋','宋诗','song-poetry','','[]','江山起暮色，草木歛餘昏。',24,'全唐诗/poet.song.69000.json','["江山起暮色，草木歛餘昏。", "誰感離騷賦，丹青弔屈原。"]'),
('4bae0768-c7db-4e0c-b5a6-aa7c99c75fd6','與秦少章題漢江遠帆五首  其三','晁沖之','宋','宋诗','song-poetry','','[]','雪埋鳯林寺，浪打鹿門山。',24,'全唐诗/poet.song.69000.json','["雪埋鳯林寺，浪打鹿門山。", "今日江風惡，郎船勸不還。"]'),
('869c5315-7b5f-43b5-a2c0-ea3bf9dabc1f','與秦少章題漢江遠帆五首  其四','晁沖之','宋','宋诗','song-poetry','','[]','江闊雁不到，山深猿自迷。',24,'全唐诗/poet.song.69000.json','["江闊雁不到，山深猿自迷。", "傳聞杜陵老，只在瀼東西。"]'),
('5d86be3f-36cd-438f-b16d-5fe16da787ad','與秦少章題漢江遠帆五首  其五','晁沖之','宋','宋诗','song-poetry','','[]','石似浣沙石，江如濯錦江。',24,'全唐诗/poet.song.69000.json','["石似浣沙石，江如濯錦江。", "征帆向何處，雲霧晦蓬窗。"]'),
('136e0e7c-3bc8-48f5-97a1-a8bf968f7fe0','莫春書事','晁沖之','宋','宋诗','song-poetry','','[]','少年猶在老書生，酒後思家夜起程。',32,'全唐诗/poet.song.69000.json','["少年猶在老書生，酒後思家夜起程。", "自佩弓刀防不測，獨隨騾馱雨中行。"]'),
('fa7f4cf6-76f6-4860-af65-d2575e8e048f','謝富察見過','晁沖之','宋','宋诗','song-poetry','','[]','飯蔬君莫厭，瓜菓我時須。',48,'全唐诗/poet.song.69000.json','["飯蔬君莫厭，瓜菓我時須。", "自可隨豐儉，誰能問有無。", "墮蜂衝博局，驚燕避投壺。", "不憚過從遠，頻來訪老夫。"]'),
('58a8c9ec-ad7e-45c7-b627-2e02d891c2d2','范元章惠然相過見問奇章公服鍾乳三千兩事因爲長句戲之','晁沖之','宋','宋诗','song-poetry','','[]','君家文物冠先朝，破甑生塵久寂寥。',64,'全唐诗/poet.song.69000.json','["君家文物冠先朝，破甑生塵久寂寥。", "借有三千兩鍾乳，定無八百石胡椒。", "湘妃暗鼓卦邊瑟，秦女高吹月下簫。", "不待青春行樂了，直持玉檢上宸宵。"]'),
('fd3aa8c0-5ad7-4551-95df-413230235597','再至都成','晁沖之','宋','宋诗','song-poetry','','[]','崢嶸花蕚西，清曉望猶迷。',48,'全唐诗/poet.song.69000.json','["崢嶸花蕚西，清曉望猶迷。", "御路紅塵合，宮槐碧瓦齊。", "夾城知輦過，複道覺香低。", "中使傳宣入，千門避馬蹄。"]'),
('0f319530-b550-49b5-a35a-dfe87cfdd42c','春晚圃田道中三首  其一','晁沖之','宋','宋诗','song-poetry','','[]','度柳穿橋聽午雞，一溝春水國門西。',32,'全唐诗/poet.song.69000.json','["度柳穿橋聽午雞，一溝春水國門西。", "行人不用傷新别，看取塵間萬馬蹄。"]'),
('c305443a-1e8b-48b8-bfe9-5ef32590a62e','春晚圃田道中三首  其二','晁沖之','宋','宋诗','song-poetry','','[]','酒酣馳馬笑彎弓，便擬長驅向虜中。',32,'全唐诗/poet.song.69000.json','["酒酣馳馬笑彎弓，便擬長驅向虜中。", "但恐老儒無骨相，不堪劍履畫南宮。"]'),
('c7e6204f-c167-4dc0-9339-137eb756eb22','春晚圃田道中三首  其三','晁沖之','宋','宋诗','song-poetry','','[]','君王重老降褒書，特賜宣陽宅一區。',32,'全唐诗/poet.song.69000.json','["君王重老降褒書，特賜宣陽宅一區。", "聞說會稽人不識，鑑湖還肯借臣無。"]'),
('109d3b7e-2ee4-46e2-8fe1-124be14cffe6','玉字黄庭經','晁沖之','宋','宋诗','song-poetry','','[]','寶氣宵纏北斗間，仙書自把下天壇。',32,'全唐诗/poet.song.69000.json','["寶氣宵纏北斗間，仙書自把下天壇。", "誤緣不是凡心起，月戶雲窗讀字難。"]'),
('c132714d-5c4f-4a31-8442-1b8f31364077','重過鴻儀寺','晁沖之','宋','宋诗','song-poetry','','[]','秋色遠如許，寒花奈若何。',48,'全唐诗/poet.song.69000.json','["秋色遠如許，寒花奈若何。", "客行傷老大，野次記經過。", "廢圃猶殘菊，枯池但折荷。", "吾生與物態，天意豈蹉跎。"]'),
('6aee99d9-55d3-4453-9ae2-43463de82ac3','贈江子我子之','晁沖之','宋','宋诗','song-poetry','','[]','江郎淮海秀，經術古同師。',48,'全唐诗/poet.song.69000.json','["江郎淮海秀，經術古同師。", "温潤無前輩，清新有近詩。", "一丘須早計，五斗莫堅辭。", "獻賦修竿牘，知君定不爲。"]'),
('0b7a1489-66cf-4ab1-a8aa-0b4779bb6348','贈江端本子我','晁沖之','宋','宋诗','song-poetry','','[]','嚲免雞豚今日債，斷除妻子宿生緣。',32,'全唐诗/poet.song.69000.json','["嚲免雞豚今日債，斷除妻子宿生緣。", "豐登便是人天供，努力東臯自種田。"]'),
('ec6dd5cf-d2cc-4fd9-bcbf-f799e2ee99e8','送僧歸建州','晁沖之','宋','宋诗','song-poetry','','[]','清秋潁汝歸時晚，不及羣公送惠休。',64,'全唐诗/poet.song.69000.json','["清秋潁汝歸時晚，不及羣公送惠休。", "曲几數行題字别，扁舟幾日爲詩留。", "東吳楊柳雲中渚，南越梅花雪外洲。", "萬里故郷聊一到，江山風物往來游。"]'),
('f8ec5e6a-4283-427a-b1f4-347e355145ca','和新鄉二十一兄華嚴水亭五首  其一','晁沖之','宋','宋诗','song-poetry','','[]','近市危樓通野寺，隔溪高柳接京華。',32,'全唐诗/poet.song.69000.json','["近市危樓通野寺，隔溪高柳接京華。", "蕩舟不怕風波急，看盡芙蓉十里花。"]'),
('28a36fd5-e968-4158-ad23-463e0f7357f7','和新鄉二十一兄華嚴水亭五首  其二','晁沖之','宋','宋诗','song-poetry','','[]','池水泠泠淥未深，叢篁低草背庭陰。',32,'全唐诗/poet.song.69000.json','["池水泠泠淥未深，叢篁低草背庭陰。", "晚來欲別龜魚去，更向軒西獨瞰臨。"]'),
('886d02ad-2f0c-4987-a28a-7f7711eeb33e','和新鄉二十一兄華嚴水亭五首  其三','晁沖之','宋','宋诗','song-poetry','','[]','嗜酒不知淹歲月，好閑久欲棄簪纓。',32,'全唐诗/poet.song.69000.json','["嗜酒不知淹歲月，好閑久欲棄簪纓。", "暫游蓮社同陶令，終向瓜田學邵平。"]'),
('cc12feca-332c-4308-a14d-c16547e4bd87','和新鄉二十一兄華嚴水亭五首  其四','晁沖之','宋','宋诗','song-poetry','','[]','渚蒲浙浙風猶急，岸柳纖纖雨尚餘。',32,'全唐诗/poet.song.69000.json','["渚蒲浙浙風猶急，岸柳纖纖雨尚餘。", "栖鷺宿鷗渾去盡，泝溪還有兩三魚。"]'),
('500d1e95-e759-4d0f-815f-be65e450baea','和新鄉二十一兄華嚴水亭五首  其五','晁沖之','宋','宋诗','song-poetry','','[]','荷蓋點溪三數葉，藤梢遶樹幾千層。',32,'全唐诗/poet.song.69000.json','["荷蓋點溪三數葉，藤梢遶樹幾千層。", "投閑更與高人約，重抱琴來聽廣陵。"]'),
('3ef81b13-e9c5-4004-be1c-0ca149d64c6d','感梅憶王立之','晁沖之','宋','宋诗','song-poetry','','[]','王子已仙去，梅花空自新。',48,'全唐诗/poet.song.69000.json','["王子已仙去，梅花空自新。", "江山餘此物，海岱失斯人。", "賓客他鄉老，園林幾度春。", "城南載酒地，生死一沾巾。"]'),
('074982ca-140b-4b4c-bc18-03a9f7c6dbfd','送人遊江南','晁沖之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湧金門外斷紅塵，衣錦城邊着白蘋。',32,'全唐诗/poet.song.69000.json','["湧金門外斷紅塵，衣錦城邊着白蘋。", "不到西湖看山色，定應未可作詩人。"]'),
('a56dbc14-d934-47f1-93d8-cf4375abd05d','和顔伯武丈山寺','晁沖之','宋','宋诗','song-poetry','','[]','松門石磴隱山家，鐘鼓蕭然一院花。',32,'全唐诗/poet.song.69000.json','["松門石磴隱山家，鐘鼓蕭然一院花。", "齋罷老僧來施食，階前馴雀趁饑鴉。"]'),
('397e3a94-b7e1-4e95-b287-87cec67d4dbc','小魏買馬久不至以詩寄之','晁沖之','宋','宋诗','song-poetry','','[]','聞說黄金廄，騏驎惜別羣。',48,'全唐诗/poet.song.69000.json','["聞說黄金廄，騏驎惜別羣。", "猶來果下馬，不必五花紋。", "駿骨愁時晚，薌萁念夕矄。", "老夫慵杖屨，待汝入嵩雲。"]'),
('220d531b-037e-46e7-b96c-cd535d0bb73a','和四兄清泉香餅子','晁沖之','宋','宋诗','song-poetry','','[]','清絕端因柏子香，風流特可付文房。',32,'全唐诗/poet.song.69000.json','["清絕端因柏子香，風流特可付文房。", "如何石火須臾頃，得盡人間一日長。"]'),
('2cefdfe8-50af-46fd-a66f-5f75896099cc','晝寢','晁沖之','宋','宋诗','song-poetry','','[]','聞說齊州路，遙通古睡鄉。',48,'全唐诗/poet.song.69000.json','["聞說齊州路，遙通古睡鄉。", "雲巖迷傅說，風峽宴襄王。", "日月星辰靜，山川草木長。", "不知三代貴，何似一張牀。"]'),
('7796b21e-4f4e-471d-b173-20b2f92f3a86','過陳無己墓','晁沖之','宋','宋诗','song-poetry','','[]','以我懷公意，知公待我情。',48,'全唐诗/poet.song.69000.json','["以我懷公意，知公待我情。", "五年三過客，九歲一門生。", "近訪遺文錄，重經故里行。", "寄書無鄭尹，誰爲葬彭城。"]'),
('3674ea63-4623-4e0b-995e-c0168c16b33e','懷王立之','晁沖之','宋','宋诗','song-poetry','','[]','不到城南久，黄梅幾度新。',48,'全唐诗/poet.song.69000.json','["不到城南久，黄梅幾度新。", "忽看人日作，淚盡大和春。", "翰墨猶如在，壺觴不復陳。", "常思醉風度，花底岸綸巾。"]'),
('a5f2f7c4-c0b3-4511-9a58-c62bc6ce3dd8','以少炭寄江子之','晁沖之','宋','宋诗','song-poetry','','[]','金籍曾通玉虛殿，仙曹擬拜翠微郎。',32,'全唐诗/poet.song.69000.json','["金籍曾通玉虛殿，仙曹擬拜翠微郎。", "莫嫌薄上温黁火，猶得濃薫篤耨香。"]'),
('73f28f14-1e18-4ade-808c-04d7e9e95a22','梅','晁沖之','宋','宋诗','song-poetry','','[]','素月清溪上，臨風不自勝。',48,'全唐诗/poet.song.69000.json','["素月清溪上，臨風不自勝。", "影寒垂積雪，枝薄带春冰。", "香近行猶遠，人來折未曾。", "江山正蕭瑟，玉色照松藤。"]'),
('37a34b45-3442-4505-be60-4e297ba2ac10','過王立之故居','晁沖之','宋','宋诗','song-poetry','','[]','酴醿架倒花仍發，薜荔墻摧石亦移。',32,'全唐诗/poet.song.69000.json','["酴醿架倒花仍發，薜荔墻摧石亦移。", "此地與君凡幾醉，年年同賦蠟梅詩。"]'),
('9846a905-891c-451d-a8f1-8a18d6efa733','再至徐州示諸弟','晁沖之','宋','宋诗','song-poetry','','[]','去年客徐得范子，今年客徐不得人。',64,'全唐诗/poet.song.69000.json','["去年客徐得范子，今年客徐不得人。", "斷無草木與同味，宛有魚鳥來相親。", "南尋白門傍山麓，西望黄樓行水濵。", "還家作詩示羣從，早晚一遊攜二陳。"]'),
('7626c0a4-048d-4e14-8b5d-514a77ecfd5e','秋夜情','晁沖之','宋','宋诗','song-poetry','','[]','獨眠百感秋夜情，孤城急雨中聞更。',32,'全唐诗/poet.song.69000.json','["獨眠百感秋夜情，孤城急雨中聞更。", "明朝覧鏡視鬢髮，不知白從何處生。"]'),
('af2dd19b-9e62-4dcb-93dc-d9e514b7c34a','謝胡御史寄茶兼簡深明','晁沖之','宋','宋诗','song-poetry','','[]','諫議茶猶寄，郎官迹已疏。',48,'全唐诗/poet.song.69000.json','["諫議茶猶寄，郎官迹已疏。", "斜封三道印，不奉一行書。", "會遠長安去，終臨顧渚居。", "大江清見底，爲問渴如何。"]'),
('ee697689-3efc-410d-adaa-1afc2da735dd','積善堂詩','晁沖之','宋','宋诗','song-poetry','','[]','我家得姓自衛史，文王之昭鐵厥美。',320,'全唐诗/poet.song.69000.json','["我家得姓自衛史，文王之昭鐵厥美。", "西京御史府大夫，父慈子忠不惜死。", "至今墓上無曲棘，潁川歲時虔廟祀。", "中原喪亂厭風塵，南渡不及渡遼水。", "晚惟道武攬英雄，遼東之晁同興起。", "世封潁川刺濟州，子孫嬋媛冠劍偉。", "唐有賢良如漢初，名動集賢爲學士。", "是時海內圖書家，一晁未讓張與李。", "忠實文華入本朝，三祖百孫同一體。", "中祖潁川襲遠封，東祖西祖復于濟。", "自從決策罷兵來，平進不厭百寮底。", "即今門戶益衰微，攬古懷今情曷已。", "上恩坱圠播無垠，宿莽心存春藿靡。", "漳州有母行百齡，疏封鈿服明光裏。", "夫人眼力尚針縷，拜恩不易從稚齒。", "初惟夫人有子賢，曰此布濩敢不俾。", "何勞夢帝血面論，直以微誠動旒扆。", "華堂白髮喜更新，即看青袍子高第。", "壽斝千場日未央，膝下曾玄扶且倚。", "中眷有孫不能叫，東眷孫文刊燁煒。"]'),
('9a1851e9-f397-4f6d-b300-2e5e5df28455','道中','晁沖之','宋','宋诗','song-poetry','','[]','雨子收還急，溪流直又斜。',48,'全唐诗/poet.song.69000.json','["雨子收還急，溪流直又斜。", "迢迢旁山路，漠漠滿林花。", "破水雙鷗影，掀泥百草芽。", "川原有高下，隨處着人家。"]'),
('ca986bf2-3ec3-4bc6-bd59-ca07f8695f2f','句  其一','晁沖之','宋','宋诗','song-poetry','','[]','扁舟幾日爲詩留。',8,'全唐诗/poet.song.69000.json','["扁舟幾日爲詩留。"]'),
('1552e9f0-8db0-4e82-92c4-a6b5d6dd2bee','句  其二','晁沖之','宋','宋诗','song-poetry','','[]','老景人情一羽輕。',8,'全唐诗/poet.song.69000.json','["老景人情一羽輕。"]'),
('4e430675-65ca-4d72-b084-c11791e67a43','句  其三','晁沖之','宋','宋诗','song-poetry','','[]','叔子擬度驊騮前。',8,'全唐诗/poet.song.69000.json','["叔子擬度驊騮前。"]'),
('015de7b6-f3ad-4500-b0c8-5d3e2c0a3c35','句  其一','晁貫之','宋','宋诗','song-poetry','','[]','思與諸公論人物，試憑清議賦招魂。',16,'全唐诗/poet.song.69000.json','["思與諸公論人物，試憑清議賦招魂。"]'),
('26bbdbdd-e61d-48a5-b015-614f9eb4b014','句  其二','晁貫之','宋','宋诗','song-poetry','','[]','草堂不見杜陵老，折得青松度水歸。',16,'全唐诗/poet.song.69000.json','["草堂不見杜陵老，折得青松度水歸。"]'),
('580df366-c48a-4480-98a9-d6ea5ca52370','和鄧慎思詩呈同院諸公三首  其一','耿南仲','宋','宋诗','song-poetry','','[]','秋日同文館，閒無一事依。',48,'全唐诗/poet.song.69000.json','["秋日同文館，閒無一事依。", "鬬羊誰得雋，倦鳥客思歸。", "寢處還相向，過從不患稀。", "何當有星聚，誰爲問璇璣。"]'),
('daf5a39e-79e5-4059-ab93-f50fe4a3e7e9','和鄧慎思詩呈同院諸公三首  其二','耿南仲','宋','宋诗','song-poetry','','[]','秋日同文館，褎然觀國光。',48,'全唐诗/poet.song.69000.json','["秋日同文館，褎然觀國光。", "泗濱何限磬，岱麓易求梁。", "劍氣頻衝斗，錐鋒定出囊。", "於余慚拙匠，操尺預量長。"]'),
('9f5f51f9-785d-4d0c-8168-79f9ba67eee8','和鄧慎思詩呈同院諸公三首  其三','耿南仲','宋','宋诗','song-poetry','','[]','秋日同文館，新凉逐雨回。',48,'全唐诗/poet.song.69000.json','["秋日同文館，新凉逐雨回。", "棘垣嬰吏局，蕙帳憶山隈。", "射爲巧狙發，田因文豹來。", "西城隨分鎻，夫我室多才。"]'),
('5dc7a02d-282f-4fa0-93ba-1e71b1b37be8','和鄧慎思秋日同文館詩三首  其一','耿南仲','宋','宋诗','song-poetry','','[]','詔命連催發，英髦一日齊。',48,'全唐诗/poet.song.69000.json','["詔命連催發，英髦一日齊。", "周瑜醇似酒，崔遠爽於梨。", "高館清無夢，寒燈坐賦題。", "還同宿山驛，風雨閉重閨。"]'),
('2da3b02f-d061-45e9-8da0-cba756e11942','和鄧慎思秋日同文館詩三首  其二','耿南仲','宋','宋诗','song-poetry','','[]','槐市任花黄，賡歌且闢場。',48,'全唐诗/poet.song.69000.json','["槐市任花黄，賡歌且闢場。", "醒心流水曲，警耳白雲章。", "冷竹枝枝翠，芳蘭葉葉香。", "滿前皆俊彦，何但有三康。"]'),
('5b8487b6-c5f1-4f90-8854-2ea2394485e3','和鄧慎思秋日同文館詩三首  其三','耿南仲','宋','宋诗','song-poetry','','[]','翠幕春雲合，場登看舞雞。',48,'全唐诗/poet.song.69000.json','["翠幕春雲合，場登看舞雞。", "冥搜人不到，驚盼日沉西。", "矒學愁精鑒，英材喜巨題。", "何人當首選，雙觡起蚖泥。"]'),
('072a3a92-b082-46a7-b8e7-e69cff24371f','和鄧慎思未試即事雜書率用秋日同文館爲首句三首  其一','耿南仲','宋','宋诗','song-poetry','','[]','敗葉掃還飛，秋容肅粉闈。',48,'全唐诗/poet.song.69000.json','["敗葉掃還飛，秋容肅粉闈。", "青錢如已選，白璧會須歸。", "燕坐書横案，孤吟月滿衣。", "還同潘散騎，魚鳥性都違。"]'),
('72991521-931b-44ff-94e4-786f8cbc25c2','和鄧慎思未試即事雜書率用秋日同文館爲首句三首  其二','耿南仲','宋','宋诗','song-poetry','','[]','大軸累千箱，鳬中見鶴長。',48,'全唐诗/poet.song.69000.json','["大軸累千箱，鳬中見鶴長。", "靜臨窓几讀，爽入肺肝凉。", "誇咤爭求勝，疲勞忽自忘。", "由來京邑貢，正合冠多方。"]'),
('5b6ad846-f5c5-4eb3-85e5-a64f2e5a2d2a','和鄧慎思未試即事雜書率用秋日同文館爲首句三首  其三','耿南仲','宋','宋诗','song-poetry','','[]','藹藹儒冠至，恢恢賢路開。',48,'全唐诗/poet.song.69000.json','["藹藹儒冠至，恢恢賢路開。", "才須金鑒别，人自玉山來。", "謝客書千卷，嵇康酒一杯。", "如君富術業，當與雉爲媒。"]'),
('6e35e4f7-de5a-4f2c-be0e-2cb8648163ca','和鄧慎思初入試院','耿南仲','宋','宋诗','song-poetry','','[]','昭回雲漢九天横，冠带彬彬盡俊英。',64,'全唐诗/poet.song.69000.json','["昭回雲漢九天横，冠带彬彬盡俊英。", "梁國有珠光照乘，趙人懷璧價連城。", "道山邃處分羣彦，文律持來考正聲。", "秋晚定知誰入彀，叔通還進魯諸生。"]'),
('8aceceac-3592-4f71-9929-65472d87a8d7','和余樗年試院即事呈諸公','耿南仲','宋','宋诗','song-poetry','','[]','重門鍵鑰阻山河，顧有良朋不厭過。',64,'全唐诗/poet.song.69000.json','["重門鍵鑰阻山河，顧有良朋不厭過。", "唾落如珠傾巨斛，袂揮成幕散輕羅。", "慚分處士吹竽俸，謾學東人掩鼻歌。", "笑語哄堂俄又夜，客愁還奈我曹何。"]'),
('56c4b7b7-a98c-4f0b-9eb4-e28dc7834cc8','和鄧慎思重九考罷試卷書呈同院諸公','耿南仲','宋','宋诗','song-poetry','','[]','貢珍已選茂良充，猶被拘縻類縳鐘。',64,'全唐诗/poet.song.69000.json','["貢珍已選茂良充，猶被拘縻類縳鐘。", "渌酒强陪高館飲，黄花不似故園逢。", "碁枰苦戰挑燈坐，蘚壁閒題捧硯從。", "風葉滿庭秋索寞，更籌向盡睡方濃。"]'),
('d0dcf0ae-d3cc-4d50-a11b-9ce8e65de868','和鄧慎思同舍問及故山景物用鍾字韻詩以答','耿南仲','宋','宋诗','song-poetry','','[]','草廬高卧對千峰，白眼誰能顧萬鍾。',64,'全唐诗/poet.song.69000.json','["草廬高卧對千峰，白眼誰能顧萬鍾。", "仄席不因天子詔，藏詩未許世人逢。", "他年社禝勳如立，歸老煙霞志會從。", "五柳一松應好在，月明空自結陰濃。"]'),
('d3be863a-a64c-4328-8433-2a1abc6f2feb','延祥寺','耿南仲','宋','宋诗','song-poetry','','[]','羅浮仙客隱，準擬訪丹臺。',48,'全唐诗/poet.song.69000.json','["羅浮仙客隱，準擬訪丹臺。", "爲國身將老，逢山眼倍開。", "月依松上過，風自竹間來。", "僧欲延清話，茶香屢撥灰。"]'),
('5c287f2b-3a83-4a97-bc77-f9fdddaf1920','題丹竈  其一','耿南仲','宋','宋诗','song-poetry','','[]','穉川初隱地，山邃枕如城。',24,'全唐诗/poet.song.69000.json','["穉川初隱地，山邃枕如城。", "寶鼎丹何在，雲衣骨亦輕。"]'),
('cb89a2a7-f105-49bb-afa1-7319751fe421','題丹竈  其二','耿南仲','宋','宋诗','song-poetry','','[]','金鼎交龍虎，當年想閉扃。',24,'全唐诗/poet.song.69000.json','["金鼎交龍虎，當年想閉扃。", "一丸丹既就，五色土猶靈。"]'),
('81007779-7d16-42a2-9f69-5a5005fac4d5','題丹竈  其三','耿南仲','宋','宋诗','song-poetry','','[]','始知勾漏地，猶勝步兵營。',24,'全唐诗/poet.song.69000.json','["始知勾漏地，猶勝步兵營。", "往躅今誰繼，遊人空慕名。"]'),
('d53cdf65-3574-4abd-b9a8-3db893171594','題丹竈  其四','耿南仲','宋','宋诗','song-poetry','','[]','過客空尋訪，飛仙已杳冥。',24,'全唐诗/poet.song.69000.json','["過客空尋訪，飛仙已杳冥。", "他山多可買，歸去讀黄庭。"]'),
('217c08f0-10b3-4925-be78-6cc0232d96dd','仙鶴樓','趙澤','宋','宋诗','song-poetry','','[]','嘉陵天虹飲東海，西溪玉带縈南山。',48,'全唐诗/poet.song.69000.json','["嘉陵天虹飲東海，西溪玉带縈南山。", "諸峰四面羅髻鬟，周遭百里如一環。", "炊煙萬竈斜陽裏，繁絃脆管東風起。"]'),
('0dbfe087-9410-4c71-b1b6-aac3ec06b6d4','遊碧落洞','時孝孫','宋','宋诗','song-poetry','','[]','昔經龍洞看飛泉，疋練穿巖落半天。',32,'全唐诗/poet.song.69000.json','["昔經龍洞看飛泉，疋練穿巖落半天。", "今日挈家來碧落，蕭然秋色滿晴川。"]'),
('104f86ef-9160-4675-bb78-563a87ea28d1','留題碧落洞','廖君玉','宋','宋诗','song-poetry','','[]','一洞清虛鎖茂林，我來尋訪嘆何深。',64,'全唐诗/poet.song.69000.json','["一洞清虛鎖茂林，我來尋訪嘆何深。", "遊人刻石有興廢，流水穿巖無古今。", "嶺上煙雲長带雨，路旁松桂日成陰。", "到難未得言歸去，且對金罇滿滿斟。"]'),
('52d2ddad-142b-4ce1-a7fb-f9ed9dd080e3','句','廖君玉','宋','宋诗','song-poetry','','[]','清人耳目中流水，壯客精神兩岸山。',16,'全唐诗/poet.song.69000.json','["清人耳目中流水，壯客精神兩岸山。"]'),
('5b864dbe-7e53-4a49-8402-a3eef36b878b','築長堤','田晝','宋','宋诗','song-poetry','','[]','築長堤，白頭荷杵隨者妻。',140,'全唐诗/poet.song.69000.json','["築長堤，白頭荷杵隨者妻。", "背脅傴僂筋力微，以手置胸路旁啼。", "老夫七十嫗與齊，五尺應門生兩兒。", "夜來春雨深一犁，破曉徑去耕南陂。", "南鄰里正豪且強，白紙大字來呼追。", "科頭跣足不得稽，要與官長修長堤。", "官長亦大賢，能得使者意。", "正堤駕軺軒，不復問餘事。", "終當升諸朝，自足富妻子。", "何惜桑榆年，一爲官長死。"]'),
('2f74af0a-ebc2-4c78-a76a-fbf25160f7d5','杜牧','田晝','宋','宋诗','song-poetry','','[]','弟病兄孤失所依，當時書語最堪悲。',32,'全唐诗/poet.song.69000.json','["弟病兄孤失所依，當時書語最堪悲。", "豈圖乞得南州後，卻恨尋芳去較遲。"]'),
('a98586a3-e3f7-48ec-a05d-bb2c9facd3e5','墨子','田晝','宋','宋诗','song-poetry','','[]','末學紛紛自有師，能言兼愛我獨疑。',32,'全唐诗/poet.song.69000.json','["末學紛紛自有師，能言兼愛我獨疑。", "定知已駕雲梯後，卻悔初心泣染絲。"]'),
('fe123cc9-5969-4a2a-b4d6-4fae22d19395','玉盤','田晝','宋','宋诗','song-poetry','','[]','少皡磨成白玉盤，六丁擎出太虛寬。',32,'全唐诗/poet.song.69000.json','["少皡磨成白玉盤，六丁擎出太虛寬。", "青光千古稱萬古，留向人間此夜看。"]'),
('e7de223e-c821-4079-b56f-a24774dc382d','遊金庭','劉旦','宋','宋诗','song-poetry','','[]','衡嶽真人稱福地，南齊高士寄山河。',64,'全唐诗/poet.song.69000.json','["衡嶽真人稱福地，南齊高士寄山河。", "赤城仙去騎丹鳳，墨沼人傳詠白鵝。", "一世風流俱寂寞，千年氣象故嵯峨。", "登臨不盡懷人恨，唯有蒼蒼石可磨。"]'),
('c237d46f-ec7a-4a24-9eba-172d594920ef','上巳謝王豐父惠酒','劉旦','宋','宋诗','song-poetry','','[]','風雩三月初三日，褉事宣和勝永和。',32,'全唐诗/poet.song.69000.json','["風雩三月初三日，褉事宣和勝永和。", "又見會稽王內史，蘭亭封酒愛新鵝。"]'),
('826bc4c4-315f-421d-8122-94490259b3b7','元日','劉旦','宋','宋诗','song-poetry','','[]','元日甘泉會，衣冠拜冕旒。',24,'全唐诗/poet.song.69000.json','["元日甘泉會，衣冠拜冕旒。", "圖書一四海，玉帛萬諸侯。"]'),
('ff12e191-9465-468e-ad2e-597447afff84','句  其一','劉旦','宋','宋诗','song-poetry','','[]','紫宸拜賜鳴雙笏，皂蓋頒春佩左符。',16,'全唐诗/poet.song.69000.json','["紫宸拜賜鳴雙笏，皂蓋頒春佩左符。"]'),
('c5beae3b-d2e4-4217-92a7-0416ae907196','句  其二','劉旦','宋','宋诗','song-poetry','','[]','膺門昔忝登龍客，董墓今悲下馬人。',16,'全唐诗/poet.song.69000.json','["膺門昔忝登龍客，董墓今悲下馬人。"]'),
('87f60521-3dcf-4559-8538-8129ca44f33f','句  其三','劉旦','宋','宋诗','song-poetry','','[]','感惻復何言。',6,'全唐诗/poet.song.69000.json','["感惻復何言。"]'),
('98a17cf8-2b2b-462d-8c2a-45b150cf14a7','答盈盈','王山','宋','宋诗','song-poetry','','["\u8861\u5c71"]','東風豔豔桃李鬆，花園春入屠酥濃。',384,'全唐诗/poet.song.69000.json','["東風豔豔桃李鬆，花園春入屠酥濃。", "龍腦透縷鮫綃紅，鴛鴦十二羅芙蓉。", "盈盈初見十五六，眉試青膏鬢垂綠。", "道字不正嬌滿懷，學得襄陽大隄曲。", "阿母偏憐掌上看，自此風流難管束。", "鶯啄含桃未嚥時，便會郎時風動竹。", "日高一丈羅窗晚，啼鳥壓花新睡短。", "膩雲纖指擺還偏，半被可憐留翠暖。", "淡黄衫袖仙衣輕，紅玉欄干粧粉淺。", "酒痕落腮梅忍寒，春羞入眼横波豔。", "一縷未消山枕紅，斜睇整衣移步嬾。", "才如韓壽潘安亞，擲果竊香心暗嫁。", "小花靜院酒闌珊，别有私言銀燭下。", "簾聲浪皺金泥額，六尺牙牀羅帳窄。", "釵横啼笑兩不分，歷盡風期腰一搦。", "若敎飛上九天歌，一聲自可傾人國。", "嬌多必是春工與，有能動人情幾許。", "前年按舞使君筵，睡起忍羞頭不舉。", "鳳凰簫冷曲成遲，凝醉桃花過風雨。", "阿盈阿盈聽我語，勸君休向陽臺住。", "一生縱得楚王憐，宋玉才多誰解賦。", "洛陽無限青樓女，袖籠紅牙金鳳縷。", "春衫粉面誰家郎，只把黄金買歌舞。", "就中薄倖五陵兒，一日冷心玉如土。"]'),
('d44e4ae0-c217-454f-af33-b0b175e9c0fa','弔盈盈三首  其一','王山','宋','宋诗','song-poetry','','[]','燭花紅死睡初醒，一枕孤懷病客情。',64,'全唐诗/poet.song.69000.json','["燭花紅死睡初醒，一枕孤懷病客情。", "海上有山應大夢，人間無路可長生。", "乾坤意入憑欄闊，風月人歸似舊情。", "漢殿香銷春寂寂，夕陽無語下西城。"]'),
('1f5d7d55-6607-45e5-8e31-9c5b7855cfa6','弔盈盈三首  其二','王山','宋','宋诗','song-poetry','','[]','絃絕秦箏鏡任塵，細腰休舞鳳凰茵。',64,'全唐诗/poet.song.69000.json','["絃絕秦箏鏡任塵，細腰休舞鳳凰茵。", "一枝濃艷埋香土，萬顆珍珠濕袖巾。", "行雨不歸魂夢斷，落花難伴綺羅春。", "漢皇甲帳當年意，縱有芳魂不似真。"]'),
('0de9e507-f036-4b20-9eab-979c69c98816','弔盈盈三首  其三','王山','宋','宋诗','song-poetry','','[]','小巷朱橋花又春，洞房何事不歸雲。',64,'全唐诗/poet.song.69000.json','["小巷朱橋花又春，洞房何事不歸雲。", "二年前過曾攜手，今日重來忽見墳。", "香魄已飛天上去，鳳簫猶似月中聞。", "縱然卻入襄王夢，會向陽臺憶使君。"]'),
('4a6be440-458b-470e-9362-02f63c43c307','憶盈盈題玉女池二首  其一','王山','宋','宋诗','song-poetry','','[]','浮世繁華一夢休，登臨因憶昔年遊。',64,'全唐诗/poet.song.69000.json','["浮世繁華一夢休，登臨因憶昔年遊。", "人歸依舊野花笑，玉冷幾經墳樹秋。", "風月過情須感慨，江山多恨即遲畱。", "如今縱擬誇才思，事往情多特地愁。"]'),
('df9ca7a8-c1e1-41ed-af60-0341944bcee1','憶盈盈題玉女池二首  其二','王山','宋','宋诗','song-poetry','','[]','柳條黄盡杏梢新，山翠無非昔日春。',64,'全唐诗/poet.song.69000.json','["柳條黄盡杏梢新，山翠無非昔日春。", "花色笑風春似醉，寂寥惟少賞花人。", "憶昔閑粧淡紵衣，一枝紅拂牡丹徽。", "無端不入襄王夢，爲雨爲雲到處飛。"]'),
('52c054c0-3ef7-4ee9-8f27-42b3cc98f115','夢中作','王山','宋','宋诗','song-poetry','','[]','絳闕琳宮鎖亂霞，長生未曉棄繁華。',64,'全唐诗/poet.song.69000.json','["絳闕琳宮鎖亂霞，長生未曉棄繁華。", "斷無方朔入間信，遠阻麻姑洞裏家。", "歷劫易翻滄海水，濃春難謝碧桃花。", "紫臺樹穩瑤池闊，鳳懶龍嬌日又斜。"]'),
('3e393cb9-c6ed-478e-b9a3-d37176978950','傷春曲','盈盈','宋','宋诗','song-poetry','','[]','芳菲時節，花壓枝折。',46,'全唐诗/poet.song.69000.json','["芳菲時節，花壓枝折。", "蜂蝶撩亂，闌檻光發。", "一旦碎花魂，葬花骨。", "蜂兮蝶兮何不來，空使雕闌對寒月。"]'),
('0bbea921-48e0-48f6-b887-a6f6042e560b','寄王山','盈盈','宋','宋诗','song-poetry','','[]','枝上差差綠，林間簌簌紅。',75,'全唐诗/poet.song.69000.json','["枝上差差綠，林間簌簌紅。", "已嘆芳菲盡，安能樽俎空。", "君不見岳駝茂草長安東，金玉鑣勒雪花驄。", "二十年前是俠少，纍纍昨日成衰翁。", "幾時港飲流霞鍾，共君倒載夕陽中。"]'),
('6a9d7f0e-45b8-46d9-9550-3825f93ce642','寄蘇小娟','趙院判','宋','宋诗','song-poetry','','[]','當時名妓鎮東吳，不好黄金只好書。',32,'全唐诗/poet.song.69000.json','["當時名妓鎮東吳，不好黄金只好書。", "借問錢塘蘇小小，風流還似大蘇無。"]'),
('d2119c46-b1da-465a-a72a-069b15eddfc0','和趙院判','蘇小娟','宋','宋诗','song-poetry','','[]','君住襄陽妾住吳，無情人寄有情書。',32,'全唐诗/poet.song.69000.json','["君住襄陽妾住吳，無情人寄有情書。", "當年若也來相訪，還有於潛官絹無。"]'),
('f41f1c4b-1d9d-4897-9f1a-8e2f44dec2ff','秋蠅','鄒浩','宋','宋诗','song-poetry','','[]','秋風快如刀，着木木欲折。',288,'全唐诗/poet.song.69000.json','["秋風快如刀，着木木欲折。", "蕃鮮轉凄凄，入眼無一悅。", "青蠅獨何爲，飛鳴猶未滅。", "造化本無私，爾生亦偶竊。", "念方三伏中，日車午停轍。", "下照人世間，何異紅爐熱。", "勁鳥倦戢翼，獰獸喘吐舌。", "惟人於此時，體懈劇疲薾。", "虚堂幸可逃，枕簟隨意設。", "好睡邊韶同，素嬾稽康埒。", "更此值清涼，酣寝謂須決。", "雙睫才欲交，汗膚遭爾齧。", "營營不絕聲，宛類讒口呐。", "使我寝不安，欲息還復挈。", "况如一簞貧，未能萬錢歠。", "園蔬薦脫粟，杯盤殊滅裂。", "雙筯才欲拈，咀嚼遭爾餮。", "適從何處來，食飲汙修潔。", "使我味不甘，欲嚥還復噎。", "敺除付疲兵，祗足增跛蹩。", "宜哉孫權彈，爲爾情激切。", "期望秋風回，一掃無餘孽。", "偶此延朝昏，勿謂風不烈。", "氣候侵凝凛，龍蛇且藏穴。"]'),
('e1785163-87e0-4328-b82c-bbd56bbcda35','書徐仲車先生詩集後','鄒浩','宋','宋诗','song-poetry','','[]','古人往矣名空存，爾來冠带誰其倫。',304,'全唐诗/poet.song.69000.json','["古人往矣名空存，爾來冠带誰其倫。", "語言淵騫行跖蹻，俯仰不愧何繽紛。", "先生道義完且潔，去彼取此非今人。", "事親不但綵衣戲，刻木省定長悲辛。", "抛官却掃醉經史，胸中寧復留纖塵。", "履穿袍敝突不墨，辭幣與粟甘清貧。", "自從秀髪到白首，造次於是如一晨。", "當知有昊憫澆散，先生故出援斯民。", "嗟余禀賦雖不敏，管窺偶幸知所因。", "講聞先生亦已久，云爲輙以書諸紳。", "朅來廣陵兩閲歲，所得比舊尤加親。", "此編雅什數百計，覃思成誦驚余神。", "恍如聽樂周太廟，黄鍾大呂皦且純。", "又如典瑞出圭璧，璀璨滿目非玞珉。", "偉哉固足信萬一，彷彿相見容彬彬。", "吾皇圖治急遺逸，空谷相望推蒲輪。", "先生高卧焉得遂，細扎匪日頒嚴闉。", "奈何韁鎖脫無計，灑掃猶阻致此身。", "願言師法不少懈，庶幾有立逃湮淪。"]'),
('3e2f2f3b-47e6-4dcd-acd8-0fd1b57679e1','送李光道承事罷高郵酒官','鄒浩','宋','宋诗','song-poetry','','[]','豫章拂青冥，密蔭覆百畝。',144,'全唐诗/poet.song.69000.json','["豫章拂青冥，密蔭覆百畝。", "初由拱把微，封植歲月久。", "大廈捜棟梁，匠者終見偶。", "甘井如車輪，千尋徹坤厚。", "畚鍤非一朝，致力自培塿。", "河流涸生塵，源源獨清瀏。", "李子素綺紈，操約世莫誘。", "字畫尤勁奇，往往過虞柳。", "當其求帖時，彷彿昔人嘔。", "吾惟蜩翼知，豈暇卹衆口。", "願言舉斯心，夙昔仁義藪。", "甘井與豫章，勿使擅所有。"]'),
('c66d5744-2a06-4b0e-9def-044b47ef959a','送樓謙中赴江州德化主簿','鄒浩','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','憶昨隨侍遊鄞川，窮探欲上蒼崖顛。',192,'全唐诗/poet.song.69000.json','["憶昨隨侍遊鄞川，窮探欲上蒼崖顛。", "崢嶸古寺忽邂逅，眸子顧我驚瞭然。", "子時苫塊慘無意，揮麈豈暇論幽玄。", "星離雨散已五載，誰謂此地方周旋。", "胸中突兀富經史，欬唾落紙珠璣圓。", "明明君王正側席，何事版籍從拘攣。", "匡廬勝槩半境內，足以寄傲追前賢。", "穿雲潄澗徧所歷，妙句流落人間傳。", "却來隱几北窗下，博山深炷沉香煙。", "細觀身世究竟處，何者當好何當捐。", "紛紛萬事付一笑，聊復爾耳姑隨緣。", "吁嗟二輪挽莫住，願子於此同勉旃。"]'),
('41f2aa55-c8e0-4947-abfb-8d4e6bf6d20c','贈茅山范道人','鄒浩','宋','宋诗','song-poetry','','[]','道人本是紅塵客，曾把錐刀閙胸臆。',192,'全唐诗/poet.song.69000.json','["道人本是紅塵客，曾把錐刀閙胸臆。", "一朝矯首看冥鴻，棄子捐妻人莫測。", "三茅峰北華陽南，凌亂烟霞閟殊特。", "築庵寄傲知幾年，但見日月忙如織。", "饑餐落英飲沆瀣，策杖溪雲隨降陟。", "蟾輝倒射松風寒，長嘯一聲山欲闢。", "飄然行止信自由，或到人間躡人迹。", "朱門甕牖初不分，遇酒輙傾論斗石。", "有時巧發驚四筵，季主猶慚多失策。", "紛紛流俗爭稱奇，豈識道人真所適。", "茅君仙去空遺蹤，高行三千當自積。", "琴閒棋罷幸相過，却恐鸞飛無處覓。"]'),
('4c16c35d-2e33-4dae-907a-b2690b16174b','送宋司理赴吏部','鄒浩','宋','宋诗','song-poetry','','[]','古木暗長堤，清漣漲輕縠。',156,'全唐诗/poet.song.69000.json','["古木暗長堤，清漣漲輕縠。", "南風聒烏檣，動子歸興速。", "今日共一樽，明朝各川陸。", "我心久已灰，慘愴輙眉蹙。", "鮑叔實我知，嵇康亦子熟。", "少年挺奇姿，綺麗誘莫逐。", "抑首掾雄藩，哀矜見推鞫。", "季文毎三思，石慶懼譴戮。", "多事如不勝，投刀斯中族。", "重華雖前旒，疏逖無隱伏。", "雜遝登俊良，能官真棫樸。", "行看萬里塗，追電恣騰蹴。", "赫赫繼家聲，勿忘勤聖讀。"]'),
('bfa1db26-8785-4627-a483-fb752f8b517a','登召伯斗野亭用孫莘老韵寄秀老參寥','鄒浩','宋','宋诗','song-poetry','','[]','廣陵最佳處，堂與南山平。',120,'全唐诗/poet.song.69000.json','["廣陵最佳處，堂與南山平。", "慨然寄遠矚，溷濁爲冰清。", "冷官從無徒，猶阻窺朱甍。", "矧兹斗野構，名實久已傾。", "距我逾一舍，何由偕友生。", "王事有邂逅，川途假新城。", "登亭若爲慰，饑渇甘大烹。", "蓮花襲襟裾，雙鶴唳且行。", "一笑發深省，坐見星斗明。", "回首莫逆交，物外正采榮。"]'),
('2af46841-28d3-4e45-a7e6-4df4b36d327d','寄樓謙中','鄒浩','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','三年客揚州，鄙吝誰與晤。',132,'全唐诗/poet.song.69000.json','["三年客揚州，鄙吝誰與晤。", "美人海上來，青眼獨余顧。", "荒涼吊遺蹤，毎毎參杖屨。", "敗意無俗物，欣快平生遇。", "陶丘今杜門，習嬾殆成痼。", "麈尾掛壁間，琴書自朝暮。", "匡山正倚天，枕潄實幽趣。", "清壮增茟力，重規謫仙句。", "相望越千里，欵段不獲驅。", "何當繼疇昔，把手論情素。", "惟有月下桐，秋聲已如故。"]'),
('3c0eb781-77bf-4e9a-9c1d-177426af12b2','效十二屬體','鄒浩','宋','宋诗','song-poetry','','[]','區區鼯鼠技不優，鼓刀要使無全牛。',96,'全唐诗/poet.song.69000.json','["區區鼯鼠技不優，鼓刀要使無全牛。", "力探虎穴必有獲，縱如兔窟焉能謀。", "好龍既久乃龍至，畫蛇添足豈蛇侔。", "驄馬御史風烈在，痩羊博士聲名流。", "棘端猶作刻猴用，寶鼎忽患烹雞求。", "相狗他年會見賞，牧豕海上非吾憂。"]'),
('87d5e2be-bf61-4f9d-a635-524704d6e05b','感年','鄒浩','宋','宋诗','song-poetry','','[]','一世三十年，我今二十九。',288,'全唐诗/poet.song.69000.json','["一世三十年，我今二十九。", "昔人當此時，事業已不朽。", "顔淵語心齋，瞠若夫子後。", "著錄盈三千，獨居四科首。", "荀彧王佐才，智略子房偶。", "脫身作謀主，談笑解紛糾。", "元賓與習之，二李相左右。", "復命索玄微，詞章配韓柳。", "夙成更超倫，初不愧黄耉。", "項槖實可師，仲尼安敢友。", "孔融登龍門，元禮接彌厚。", "叔度千頃波，能使荀淑忸。", "陳蕃置一室，誓滌天下垢。", "賈誼入朝廷，號咷動明后。", "陸機文賦成，見者咸歛手。", "禰衡孰比俊，帝室宜見受。", "李賀錦囊中，佳句敵瓊玖。", "相望編簡上，灼灼列星斗。", "而我獨何人，擬之一無有。", "追維故時事，浹背汗如瀏。", "窮年坐井底，曾不辨虀臼。", "多岐既亡羊，畫虎欲類狗。", "狂瀾儻不迴，何以刷兹醜。", "吁嗟歲律逝，易於屈伸肘。"]'),
('ba23ed60-c159-4a6a-a333-e4a1d9e16780','菏澤','鄒浩','宋','宋诗','song-poetry','','[]','滔天洚水非凡災，平地洶洶生風雷。',243,'全唐诗/poet.song.69000.json','["滔天洚水非凡災，平地洶洶生風雷。", "帝堯哀民作魚鼈，咨禹平之時懋哉。", "未暇雍容堂陛上，和羮以爾爲鹽梅。", "禹知休戚係予手，汲汲豈獲憐嬰孩。", "疏鑿高低捐四海，校量勢力天須回。", "爾時菏澤次第及，導引一股從東來。", "就中不獨豫州利，八荒賴以川原開。", "農桑處處酬願欲，鳥獸蹄跡還蓬萊。", "此澤雖微與有力，掲之載籍懸星魁。", "禹歸上天已萬祀，遺利猶今分九垓。", "帝里虎士不知數，朝昏待哺張其顋。", "轉輸粟布自東部，浹日何啻浮千桅。", "始知寸膠無足用，安危須仗經綸才。", "君不見黄河泛濫金堤摧，縻費皇家幾億財。", "華衣肉食皆妙選，年年議論喧中臺。"]'),
('a37fc76c-fbb6-47ed-949e-5db8609fcbf2','陶丘','鄒浩','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','山河融結皆奇状，此丘之形誰與剏。',160,'全唐诗/poet.song.69000.json','["山河融結皆奇状，此丘之形誰與剏。", "一成爲敦再爲陶，二帝昌時已詢訪。", "至今禹貢名字存，氣勢仍容菏澤傍。", "普天率土此其中，雜遝舟車來四向。", "分茅開國南面尊，屢致千金謝齊相。", "爾來日月幾春冬，興廢相尋人物上。", "紛紛萬事已塵埃，此丘迤邐初無恙。", "平生苦死嗜登臨，准擬携笻事疏放。", "冷雲寒日滿荆榛，蕞爾令人重悽愴。", "會須東走泰山顛，縱目乾坤更何障。"]'),
('be1dccf0-3d37-4f5f-9a02-47823095843f','默坐有感','鄒浩','宋','宋诗','song-poetry','','[]','後悔寧可追，稱誤豈容數。',48,'全唐诗/poet.song.69000.json','["後悔寧可追，稱誤豈容數。", "試觀古來人，何以爲先覺。", "一日三省躬，此事在力學。", "年光捷霜蹄，我心羞齷齪。"]'),
('e3f9abf7-c930-477b-b7bf-fb8dfd845a83','次韻羅正之提刑見寄','鄒浩','宋','宋诗','song-poetry','','[]','天邊故人贈明月，恍惚如臨滄海闊。',96,'全唐诗/poet.song.69000.json','["天邊故人贈明月，恍惚如臨滄海闊。", "幾年麈尾阻清談，一日中腸寛百結。", "鍾君骨朽誰能琴，流水高山猶到今。", "平生宮徴愧伯牙，邂逅夫子還知心。", "相期端欲追前古，諸事斯言逃責數。", "青雲窮達豈須論，廊廟由來齊子午。"]'),
('c99c3078-0dd3-44f0-a45d-5ae3e9690329','王景亮携晁無咎清美堂記來求詩爲賦此一篇','鄒浩','宋','宋诗','song-poetry','','[]','先生不出二十年，幅巾種樹老盧泉。',352,'全唐诗/poet.song.69000.json','["先生不出二十年，幅巾種樹老盧泉。", "盧泉水木清且妍，築堂流水茂樹間。", "晁侯作記筆如椽，畫欄素壁青瑤鎸。", "明珠白璧光射天，先生矜詫喜欲顛。", "春歸野岸綠漪漣，青山東缺如斷環。", "雪消風軟山蒼然，杏梢紅破臙脂寒。", "先生醉狂夢思山，自駕草車束塵編。", "上堂讀書門畫關，金徽朱絲弄猗蘭。", "相思古人太古前，若非豪士魯仲連。", "即是幽人梁伯鸞，先生好學老益堅。", "少時不信功名艱，青衫屢補履決穿。", "晚知有命絕可憐，歸來自買汶上田。", "䆉稏香露凝秋殷，只知留客有酒錢。", "肯問釡粥寒韲酸，拖金曳繡卷曉班。", "何似布褐暖且寛，先生所願一何亷。", "貴人孰與先生賢，朱門銅臭廚肉膻。", "夜闌白月照管絃，美人一笑夭桃燃。", "安知賢達死丘園，正恐後世終無傳。", "此意已輸先生先，我今欲歸無由緣。", "蕙帳依約聞清猨，何時相從一醉眠。", "梨花楊柳傍禁煙，曾點浴沂春衣單。", "德公渡沔應已還，山中桂枝聊攀援。"]'),
('62d1bb8e-8458-4c56-a37a-448623439567','三朡亭','鄒浩','宋','宋诗','song-poetry','','[]','結構安在哉，荒涼但郊藪。',48,'全唐诗/poet.song.69000.json','["結構安在哉，荒涼但郊藪。", "無言對斜陽，廬兒亦搔首。", "唯餘舊時春，年年暗榆柳。", "棄置勿復論，興衰古來有。"]'),
('51ea78fb-3d5f-431d-ba2f-6347c95dbc4f','成陽','鄒浩','宋','宋诗','song-poetry','','[]','茅茨土階不圖好，想見游宮滋草草。',64,'全唐诗/poet.song.69000.json','["茅茨土階不圖好，想見游宮滋草草。", "有時警蹕從天來，誶語應無路傍老。", "可封之民紛萬邦，豈獨兹城知所保。", "穀林南畔今如何，煙草茫茫車馬道。"]'),
('1ae21259-2d08-4b75-a5e6-472981f3b117','范蠡塚','鄒浩','宋','宋诗','song-poetry','','[]','山棲嘗膽時，禍胎久已孕。',192,'全唐诗/poet.song.69000.json','["山棲嘗膽時，禍胎久已孕。", "欲令蘇臺傾，端俟天人應。", "夫子實奇才，大事力能勝。", "中分句踐憂，內外各宜稱。", "一鼓雪前羞，功名在乘興。", "向非斷以獨，未必還千乘。", "荆棘梗寒宮，晨朝露常凝。", "可憐東門眼，至此不得瞪。", "烏喙鮮克終，天道亦惡剩。", "脫身海上來，嘉言誰與贈。", "位高金更多，所向豈蹭蹬。", "况有絕代姿，提携充妾媵。", "試看劍頭血，何如窮絕磴。", "由來進退間，處之貴不懵。", "孤墳忽生疑，文獻良足證。", "吳人未忘情，高樓時一凭。"]'),
('ad278398-4f34-4cd6-833b-d1c0d4cb67cc','恭王殿','鄒浩','宋','宋诗','song-poetry','','[]','昔人語君臣，相須比弓矢。',120,'全唐诗/poet.song.69000.json','["昔人語君臣，相須比弓矢。", "乃若父子間，至情非所擬。", "惟王適帝心，重以才藝美。", "朝罷正臨軒，隤丸未云已。", "誰令羽翮摧，高飛爲中止。", "朅來天宇東，基構傍菏水。", "靈光屹相望，應陋苟完矣。", "于今崇傳舍，便是當時阯。", "那知王者居，日與行子市。", "悲風起庭槐，颯颯盈雙耳。"]'),
('589a1737-09d9-43e2-8a48-882bb4c11df4','送交代榮子邕','鄒浩','宋','宋诗','song-poetry','','[]','頖宮久戢身，所造益了了。',120,'全唐诗/poet.song.69000.json','["頖宮久戢身，所造益了了。", "慷慨揖古人，百爲無一矯。", "就令力回天，初不變忽眇。", "璀璨文字間，與此故相表。", "服膺今十年，邂逅辱繼紹。", "遇我逾故交，微言幾昏曉。", "可憐不兩留，行色逐飛鳥。", "蓬山插青冥，鬰鬰佳氣遶。", "懷鉛謝風塵，大用此其兆。", "願子更勉旃，真賢古來少。"]'),
('ef9d2612-51ea-4618-b21f-9f2f3eaaf7db','端午郊園','鄒浩','宋','宋诗','song-poetry','','[]','叔度久不見，我心如亂茅。',144,'全唐诗/poet.song.69000.json','["叔度久不見，我心如亂茅。", "良辰適端午，萬事聊一抛。", "策馬指圭竇，同焉有神交。", "森森千畝竹，正爾清樂郊。", "相與造其下，香泉薦嘉肴。", "高談落美玊，逸氣騰長蛟。", "徑就真樂處，古音奏陶匏。", "日車駐晴空，木杪疑焚巢。", "何必蒲葵風，翛然滌惛怓。", "兹遊信物外，孰與娱雲髾。", "無端消息來，主人隨鉦鐃。", "會須更卜日，城府方膠膠。"]'),
('e65a5dff-0f44-43df-87bc-e4752e955c05','送黄元明赴梁縣尉','鄒浩','宋','宋诗','song-poetry','','[]','豫章控江南，山高水沄沄。',120,'全唐诗/poet.song.69000.json','["豫章控江南，山高水沄沄。", "鍾此千里秀，君家賢弟昆。", "文采映諸父，鸞鳳争騰騫。", "伯氏晚相遇，許我遊其藩。", "聪明置不用，道術臻忘言。", "妥然稠人中，容貌白玉温。", "求之古君子，端若李仲元。", "一尉聊爾耳，誰識君所存。", "霜風慘黄葉，雪雨埋朝暾。", "柴車竟行哉，我心憂聾昏。"]'),
('98b6d191-f378-4fc2-a38a-769be1a7aa6d','次韻醇中見寄','鄒浩','宋','宋诗','song-poetry','','[]','此身風中蓬，飄颻洛西豪。',156,'全唐诗/poet.song.69000.json','["此身風中蓬，飄颻洛西豪。", "所向不膠漆，杜門天自高。", "坐懷平生友，皎皎眉間毫。", "書隨鵲聲來，厚我逾綈袍。", "如何東野鳴，亦復追離騷。", "彼蒼久已均，後逸須先勞。", "試看刀筆微，他日猶蕭曹。", "麹蘖正多事，要在餔其糟。", "勿謂伯樂死，轅下終奇遭。", "况乃掣電中，幾許堪遊遨。", "展江涵清空，春光集漁舠。", "命駕裁數驛，慰此心忉忉。", "呂安何人斯，君首無徒搔。"]'),
('de80803c-7243-4a25-beff-c19b43d4aa8c','韓園','鄒浩','宋','宋诗','song-poetry','','[]','春風挽我出，邂逅陪友生。',120,'全唐诗/poet.song.69000.json','["春風挽我出，邂逅陪友生。", "濱湖足勝事，繫馬聊班荆。", "疏柳傲清淺，孤芳媚晴明。", "禽哢雜魚躍，日轉無人行。", "此間已深趣，繼踵仍高情。", "犀局自勝負，玉軫誰虧成。", "盈樽不在飲，會意時一傾。", "豈減七賢游，亦云四者并。", "如何渺茫外，忽起絲竹聲。", "未暇從爾爲，目斷陘山横。"]'),
('e799d3d7-ce08-4a64-9490-04b1f4b303e3','送宋子發節推','鄒浩','宋','宋诗','song-poetry','','[]','富貴如烈火，銷鑠誰爲鋼。',120,'全唐诗/poet.song.69000.json','["富貴如烈火，銷鑠誰爲鋼。", "黄金攫清旦，一視無四旁。", "夫子真璞玉，炎炎詎能傷。", "萬事有規矩，豈與時低昻。", "五十猶幕府，鬢髪初不霜。", "天眼終自清，弹冠指明光。", "卿雲澹朝日，舞蹈縈爐香。", "勿憂雨露隔，二聖方當陽。", "大器故晚成，此去未易量。", "巾車難更軔，潩水徒湯湯。"]'),
('c5b5f94d-421d-4692-bf80-d39f479e9522','次韻崔德符遊湖','鄒浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','無雙藹嘉譽，夫子真黄香。',108,'全唐诗/poet.song.69000.json','["無雙藹嘉譽，夫子真黄香。", "磥砢傲松檜，人間自炎涼。", "平生翰墨中，赤增戲蕭娘。", "潁川今何時，鼓翼端來翔。", "西湖謝塵土，危樓更斜陽。", "幽期得高士，一笑歌滄浪。", "新詩落圭璧，豈異連城償。", "胡爲獨韁鎖，不作逢瀟湘。", "杖屨行清秋，從容酬所望。"]'),
('13dda29a-d9d2-4a26-bb14-1fd412ccdb3d','次德符湖光亭之什','鄒浩','宋','宋诗','song-poetry','','[]','平湖泛日月，清光渺無端。',84,'全唐诗/poet.song.69000.json','["平湖泛日月，清光渺無端。", "并包入眼界，危構何軒軒。", "輪蹄隘行路，逸步誰與攀。", "只應空曠中，縹緲飛神仙。", "我心本虚室，朝市成青山。", "居然發餘照，妙用同一天。", "凭欄豈無人，杯盤争擊鮮。"]'),
('0b7b5d3c-fc9e-4f7e-b325-46b97cd8ab1a','簡德符','鄒浩','宋','宋诗','song-poetry','','[]','清標藐冰壺，一見滌袢暑。',240,'全唐诗/poet.song.69000.json','["清標藐冰壺，一見滌袢暑。", "况乃北窗風，窮辰薦佳語。", "鄭聲正喧天，忽此聞柷敔。", "坐令偕生疾，不得砭石去。", "我愚雖絕人，志氣肯爲鼠。", "如何城下盟，欣然爲君舉。", "請看時雨來，潤澤先柱礎。", "豈無力使然，默感自難阻。", "高堂久懸榻，寶劍已心許。", "昨宵共燈光，今作參商處。", "秋意入梧桐，滴瀝鬬東序。", "連墻莫至前，念君初逆旅。", "蛇影勿狐疑，當思啖虀杵。", "桑蓬元四方，事業在伊呂。", "匪石詎可轉，紛紛任兒女。", "但願早晴明，交臂無齟齬。", "更約靖節君，相與富毫楮。", "朝昏經史間，端知植禾黍。", "他年羊子妻，焉能斷機杼。", "君席果不分，我知逃爾汝。"]'),
('0b2836c5-28fa-435e-ab7c-e55e80ac6793','用王憲韻寄參寥','鄒浩','宋','宋诗','song-poetry','','[]','天資不紛華，脱身禮白足。',192,'全唐诗/poet.song.69000.json','["天資不紛華，脱身禮白足。", "一笑語曹溪，與世作眼目。", "有時戲毛穎，新詩奴鄭谷。", "翹然百家中，疏煙澹脩竹。", "頃年古招提，山青水澄淥。", "傾盖揖孤標，令人慚逐逐。", "平生稻粱謀，從此在鴻鵠。", "爾來落高陽，轅下方局促。", "况乃建隆師，黄壚已埋玉。", "豈必阮步兵，途窮泫然哭。", "賴君金石聲，丁寧鴈飛速。", "我心端何如，盲龜得浮木。", "遙聞玉堂老，初情敦夏屋。", "支遁久塵埃，風流一朝續。", "營營覆載間，萬事風前燭。", "願言掃雲窗，聊對傳燈錄。"]'),
('601446db-1d0b-4567-ac71-e6961170d692','送張舜諧遊上庠','鄒浩','宋','宋诗','song-poetry','','[]','高木紛萬状，皆從毫末來。',132,'全唐诗/poet.song.69000.json','["高木紛萬状，皆從毫末來。", "天時與人事，相資以爲媒。", "根本初不同，他時終異材。", "東風動霄壌，繁華媚池臺。", "花枝竟無言，車馬争徘徊。", "霜雪一朝怒，孰與松柏陪。", "青青幾千尺，寒峰正崔嵬。", "向來絲竹處，索寞空塵埃。", "明堂屹南面，梁棟支傾摧。", "匠石有青眼，肯爲桃李開。", "窮年後悔心，何似今日回。"]'),
('7888a9fb-41b0-4b3c-9e2a-951e44a81a35','穎橋僧舍壁間有詩頗怨不遇因次其韻刺之','鄒浩','宋','宋诗','song-poetry','','[]','食肝何必馬，食魚何必魴。',72,'全唐诗/poet.song.69000.json','["食肝何必馬，食魚何必魴。", "趣操苟冰炭，誰能屈鄒陽。", "人間所榮觀，金門與玉堂。", "患失紛鄙夫，白首猶悢悢。", "豈識君子心，草衣如繡裳。", "藪澤方尉羅，鷦鵬已翺翔。"]'),
('9b6f9672-0a2d-433c-942c-6750728ba701','路傍草','鄒浩','宋','宋诗','song-poetry','','[]','洪造初無私，物自生殊異。',96,'全唐诗/poet.song.69000.json','["洪造初無私，物自生殊異。", "叢叢路傍草，枝葉一何悴。", "行人或陵踐，牛羊肆殘毁。", "縱能勝疾風，厥害還遭值。", "瞻彼山中蘭，孤芳常茂遂。", "馨香動君子，采擷遠而至。", "須知得失間，所托惟其地。", "嗚呼儒衣冠，如何不尚志。"]'),
('11f17d34-688e-445f-b18a-08cb2f9f2a80','午枕有感','鄒浩','宋','宋诗','song-poetry','','[]','宰我嗜晝寝，邊韶仍愛眠。',240,'全唐诗/poet.song.69000.json','["宰我嗜晝寝，邊韶仍愛眠。", "當時師弟子，指摘良紛然。", "韋絃以爲戒，僶俛亦有年。", "分作蠧書魚，文字相周旋。", "縱不叔夜懶，猶慚頭在懸。", "如何到此地，午枕有所便。", "晨餐未停筯，睡思潛予牽。", "矇矓眼自醉，百體柔於綿。", "茗飲雖再三，驅逐無由緣。", "解衣卧北窗，徑走姬旦前。", "往往隨物化，飛躍参魚鳶。", "老木森古砌，日轉驚鳴蝉。", "矍然整巾屨，衙鼓忽已傳。", "由來棘圍中，疏放成拘攣。", "氣血似止水，鬰鬰爲此愆。", "何當徹門牡，四顧還青天。", "朝昏遞消息，有節亦有宣。", "焚膏續清晝，冥心寄韋編。", "往失固莫救，尚得來者全。", "聖處幾萬里，行矣勤着鞭。"]'),
('5872b25e-8d8e-4376-aeeb-72d10347a294','次韻鄧州范仲成秘校見寄','鄒浩','宋','宋诗','song-poetry','','[]','落筆文章真宋玉，八面縱横欺炙轂。',144,'全唐诗/poet.song.69000.json','["落筆文章真宋玉，八面縱横欺炙轂。", "潛藏頭角卧南陽，刖足豈是王駘辱。", "每嗟愚賈謾操金，他日辛勤只書簏。", "丈夫事業會驚人，誰知范叔成張禄。", "相逢憐我再虀鹽，不羨高門厭粱肉。", "追惟吳國舊時蹤，山澹晴煙水輸淥。", "幾年嵇阮作参商，漠漠茂林空自竹。", "懽然一笑换凄涼，端遇牛公容杜牧。", "爾來日月更中天，未應寂寞餐秋菊。"]'),
('73775a9d-c0d4-4197-9bdb-133e2e1d8ae8','用前韻寄鄧帥杜君章學士','鄒浩','宋','宋诗','song-poetry','','[]','策府名卿厭鳴玉，朅來南陽朱兩轂。',144,'全唐诗/poet.song.69000.json','["策府名卿厭鳴玉，朅來南陽朱兩轂。", "胸中雲夢吞八九，終然不貯閑榮辱。", "坐令政事邈前人，容易端如探筐簏。", "去年持刃今扶犁，所至熙熙豐穀禄。", "華堂夢斷燕絲簧，笑謂鄒枚不如肉。", "公雖飲少客自醉，但見銀缾倒輕渌。", "明明天子正搜賢，真賢繼踵還符竹。", "勳勞矧已疏屏風，八命難淹一州牧。", "願公快向百花洲，更集賓僚勤把菊。"]'),
('d44dbbcd-8bf5-4a9f-adf1-247d9effe351','用前韻寄穣城謝公静推官','鄒浩','宋','宋诗','song-poetry','','[]','邂逅蒹葭來倚玉，淺見慚如視車轂。',144,'全唐诗/poet.song.69000.json','["邂逅蒹葭來倚玉，淺見慚如視車轂。", "荷君傾倒過平生，妙處令人忘寵辱。", "并包今古入靈臺，欬唾珠璣幾盈簏。", "紛紛年少多公卿，何獨斯人猶寸禄。", "南陽刺史今伯樂，歎息龍媒異凡肉。", "剡章求以助風流，豈減紅蓮汎澄淥。", "更将餘力付蟠根，迎刃無留真破竹。", "才全如此帝未知，燕閒却自思頗牧。", "東山出處是家風，莫學淵明戀私菊。"]'),
('d4dfdd5b-186a-4525-91b6-f1cdcf1c4a10','范仲成約非晚過穎昌留數日因鄧兵還追用前韻寄之','鄒浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','勿歎卞和猶抱玉，勿嘲揚雄未丹轂。',144,'全唐诗/poet.song.69000.json','["勿歎卞和猶抱玉，勿嘲揚雄未丹轂。", "由來識拔須待時，阨窮不是男兒辱。", "相逢相别竟匆匆，賴有好詩藏敝簏。", "居然成誦想英標，殺馬無因愧持祿。", "還家青鏡覽形容，鞍上豈徒消髀肉。", "故人要我泛西湖，萬頃瀰漫浸天淥。", "坐中寂寞欠車公，只應冒雪歌黄竹。", "從今塵榻掃南窗，日俟高車起耕牧。", "懸知樂事與衆分，把琖追論燈下菊。"]'),
('5fdc6a31-2b21-41dd-b2c8-b4df51358447','與王仲弓分韻得東字','鄒浩','宋','宋诗','song-poetry','','[]','西豪星聚時，有客還頖宮。',120,'全唐诗/poet.song.69000.json','["西豪星聚時，有客還頖宮。", "解驂聽揮麈，落落凌霜風。", "平子素我厚，繆入題品中。", "夷甫不復言，目繫心已同。", "塤箎競遠韻，欣逢吾道東。", "平生仰高山，鵠立拘樊籠。", "誰令燕雀微，一旦追冥鴻。", "明珠繼來投，照夜驚兒童。", "從今日虚徐，所冀資磨礱。", "只恐天池鯤，朝夕摶晴空。"]'),
('32e29571-a8e1-415d-b3f7-5de3a26b3eb6','次韻仲弓見贈','鄒浩','宋','宋诗','song-poetry','','[]','我生分稽古，未始懷宴安。',144,'全唐诗/poet.song.69000.json','["我生分稽古，未始懷宴安。", "萬事不入眼，人間自悲懽。", "獨於文會時，所取良必端。", "起廢賴發藥，他年逃素餐。", "蘇君日千里，逸步逾飛翰。", "一從斷金來，況也寧永歎。", "于今更天誘，還逢魯圓冠。", "傾盖如舊識，禮法能見寛。", "須知高門閭，階庭富芝蘭。", "何獨仲弓家，弟兄稱二難。", "琴張誠可友，願言謝外觀。", "聖域渺無旁，觀水須觀瀾。"]'),
('544f3aa5-a40e-4439-b9cf-fd3fccc82144','送裴仲孺攝汝陰尉','鄒浩','宋','宋诗','song-poetry','','[]','我讀醉翁思潁詩，恨不六翮西南飛。',140,'全唐诗/poet.song.69000.json','["我讀醉翁思潁詩，恨不六翮西南飛。", "頖宮朅來濱潁水，潁水雖同非潁尾。", "羨君匹馬秋風前，吏隱去作南昌仙。", "霜威凛凛肅普天，環湖瀟灑皆當年。", "時豐鐃鼓如寒蟬，想見絲緍上釣船。", "太白還光醉翁死，鄰家仍無隱君子。", "山高水深誰與知，只恐未樂君先悲。", "朱方豪士森戈矛，青雲蹭蹬猶督郵，不如黄雞白酒相與醉即休。"]'),
('96bac2ca-c6e0-445f-acc1-dc559bdaffc7','次韻世美遊嵩山','鄒浩','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','肇分五嶽尊，上帝委奇石。',168,'全唐诗/poet.song.69000.json','["肇分五嶽尊，上帝委奇石。", "維嵩據地中，屹立萬仞壁。", "遠與四鎮殊，式應土圭測。", "有人仰崇高，坐厭拘名跡。", "邂逅天際來，驊騮脱車軛。", "将聖祭泰山，此心豈懸隔。", "擾擾塵土中，一朝復一夕。", "聞君有風期，欣然雙蠟屐。", "焉知馬足非，迥隔千峰碧。", "古人亦多端，相望託幽寂。", "法音動山靈，松栝惟所適。", "寄徑登顯途，自恃捷無敵。", "遺轍諒未泯，一一可遊歷。", "借問去來人，誰堪比心迹。"]'),
('ac11a952-934e-44cd-9943-23d2263cec4f','送崔子厚朝散倅安州','鄒浩','宋','宋诗','song-poetry','','[]','君家如武庫，人物常森森。',120,'全唐诗/poet.song.69000.json','["君家如武庫，人物常森森。", "伯氏妙難測，一笑冥古今。", "蒲團與蔾杖，終然作知音。", "王事挽以去，歲杪霜雪侵。", "輕軒奉白髪，遙指甑山岑。", "臣子難有已，忠孝亦已深。", "南方擁兵刃，調發多呻吟。", "使民還擊壌，屏星實分任。", "况乃功業本，從來在無心。", "獨恨鎖天北，誰與同瑤琴。"]'),
('0d8fe840-6983-457e-878d-9d22fad7aff5','次韻仲弓見懷','鄒浩','宋','宋诗','song-poetry','','[]','與子風雨散，掩關非世喧。',48,'全唐诗/poet.song.69000.json','["與子風雨散，掩關非世喧。", "琴書到古人，危坐屢忘言。", "何當同此趣，脫略文物繁。", "歲晏猶清居，厲節真王尊。"]'),
('542b8a5a-8dcf-49ad-b18f-a19696b83e4e','悼陳生','鄒浩','宋','宋诗','song-poetry','','[]','豪商破浪隨東風，轆轤相繼滄溟中。',384,'全唐诗/poet.song.69000.json','["豪商破浪隨東風，轆轤相繼滄溟中。", "回環極目渺無際，萬石之載裁飄蓬。", "一朝六鶂不得進，十舟八九成虚空。", "一舟邂逅脫魚腹，開帆豈暇論西東。", "大明出沒夜復旦，何許清越鳴晨鐘。", "舟人側耳正驚喜，忽瞻水際排奇峰。", "落帆沉矴泊古岸，介然荒徑雲間通。", "鄞川書生託舟尾，見之踴躍追猿狨。", "扶疏怪木進十里，突兀古院題天宮。", "入門長廊轉寂寂，堂上高拱厖眉翁。", "左右侍立滿三百，談玄演義聲玲瓏。", "相逢問勞憫流落，旋啓虚室棲行踪。", "紛紛袍布欺臘雪，獨此錦帳朝霞紅。", "黄金白玉薦豐饌，藥苗蔬甲青茸茸。", "主翁自言避巢寇，朅來不與中原同。", "于今天子果誰氏，語罷默默如盲聾。", "日遣二子共遊處，因得細詰開冥蒙。", "皆云我輩號處士，名字非列神仙宗。", "三等三百奉一主，上等第一裴休公。", "提携峻陟幾千丈，笑秦亭上聊從容。", "秦皇可笑笑不已，聲撼亭角摧穹隆。", "徐福曼倩亦何在，前後石壁猶房櫳。", "舉頭指似蓬萊島，霜雪直上磨蒼穹。", "波濤作勢撞山脚，魯有神聖躬磨礱。"]'),
('e7eeecd0-7539-42e7-b66a-c97dcac1821b','次韻世美冬夜見懷','鄒浩','宋','宋诗','song-poetry','','[]','君家儒學頻公侯，豈知孔孟窮於鄒。',128,'全唐诗/poet.song.69000.json','["君家儒學頻公侯，豈知孔孟窮於鄒。", "他年事業知未艾，詵詵孫子多清流。", "紅蓮上客更超詣，勁節耻與今人儔。", "自言名宦亦何有，回看家法長包羞。", "蕪城歲月已波逝，朅來文會消吾憂。", "青天白日有崔子，亦許交臂聞嘉謀。", "人生南北那可必，合散倐忽春雲浮。", "會須着鞭入聖域，無使後悔空冥搜。"]'),
('403b8b4b-dfcc-43c6-8cec-dc4418453dec','送德符還陽翟并簡陳叔易','鄒浩','宋','宋诗','song-poetry','','[]','霜嚴識蒼柏，火烈知黄金。',120,'全唐诗/poet.song.69000.json','["霜嚴識蒼柏，火烈知黄金。", "不有小人謗，孰窺君子心。", "前程已如此，紛紛矧於今。", "衡門杜朝夕，巧舌猶追尋。", "一與接爲構，何以逃交侵。", "任大始多事，由來天意深。", "北風動秋夜，興落西山岑。", "逸駕豈受挽，耿耿聊分襟。", "太丘阻眉宇，爲我先寄音。", "漁父可師否，兹焉共浮沉。"]'),
('b297839f-a938-42c8-9a9e-ef7e2902e06a','烹密雲龍','鄒浩','宋','宋诗','song-poetry','','[]','君不見子建七步俄一詩，太沖十年僅三賦。',227,'全唐诗/poet.song.69000.json','["君不見子建七步俄一詩，太沖十年僅三賦。", "相去何啻楚與越，爾來題品皆才具。", "我生尚友到古人，袖手寒窗重慚懼。", "巧遲拙速非所長，舟泝湍流只如故。", "秋風逸思誰肯分，惟資茗飲祛昏瞀。", "人間氣味足奇功，畢竟不能成好句。", "集仙公子天上回，拭目元豐新制度。", "夜光明月豈足珍，矯矯真龍翳雲霧。", "潛藏飛躍自有時，只恐緘縢終不固。", "况聞醉翁歸潁東，更號六一逃機務。", "震霆端的助滂沱，名稱恰應當年數。", "從今掩卷待青禽，晴軒屑玉和甘露。", "胸中無復舊塵埃，五物狂吟在朝暮。", "須知料虎戚自貽，莫譏惡客君家蠧。"]'),
('b4bfa497-83ef-41e5-a527-ceb56be4de6d','次韻蘇子駿寄其弟世美','鄒浩','宋','宋诗','song-poetry','','[]','霜風戰蕪城，耿耿袖間手。',264,'全唐诗/poet.song.69000.json','["霜風戰蕪城，耿耿袖間手。", "峩冠何許來，逸氣蟠九有。", "入眼無可人，終焉收下走。", "舌端寫天河，那知膽非斗。", "離亭巧梯媒，節物幾榆柳。", "所向曹匼阿，剛腸欲雷吼。", "饑寒挽柴車，莫獲親可否。", "年來但韋編，妙處知不朽。", "規模綿古今，元自一布肘。", "翛然環堵中，未覺羲皇久。", "三復鶺鴒詩，亦已等妍醜。", "此心千里同，豈愧鼻如口。", "更聞隱君子，隨風落巖藪。", "崇朝公事休，嗜好斥杯酒。", "幅巾欵玄談，聪明謝天誘。", "萬象懸目前，軒豁開戶牖。", "坐令黄堂上，觀浄亦成垢。", "維皇急親賢，承庸拔師友。", "丘壑難自娱，巖廊拱文母。", "只恐行賜環，仙去誤雞狗。", "與其羨長生，孰若壽黔首。", "一語君試聽，黄梅未當剖。"]'),
('be754013-8b49-4850-b351-30bcb5953eed','靖節堂分題得重字','鄒浩','宋','宋诗','song-poetry','','[]','儒衣隘綿區，冰炭非一種。',120,'全唐诗/poet.song.69000.json','["儒衣隘綿區，冰炭非一種。", "邂逅心事同，清標揖孤聳。", "駕言仁義涂，相與戒前從。", "廓廓膺肺間，何由納天寵。", "春風入高堂，文字競拳勇。", "妙句窺杜陵，微語傾叔重。", "翹然真四夔，吾道有扶擁。", "遂令斥鷃姿，端爲鐘鼓悚。", "從今日喧妍，勝處宜接踵。", "獨恨韓城君，伶俜泣新壟。"]'),
('39fa047a-853e-4fa4-b8e5-8c78cf7ce717','次韻崔光先見簡作詩催春色','鄒浩','宋','宋诗','song-poetry','','[]','春遊有客忘朝暮，酷似經星好風雨。',128,'全唐诗/poet.song.69000.json','["春遊有客忘朝暮，酷似經星好風雨。", "豈知仲蔚長蓬蒿，寂寂儒宮裁一畝。", "新詩故委黄耳來，舌在驚疑爲頻吐。", "鴻鈞覓運掃轍蹤，萬物終然歸鼓舞。", "去年枯槁欲樵蘇，今已蕃鮮媚農圃。", "我家吹律信参天，苗裔非才閴無睹。", "族寒官冷自離奇，安能仰贊媧皇補。", "廟堂爕理皆少年，佇見囊金罄花塢。"]'),
('7da119c8-5c20-4c0f-889c-5ad45319dc35','送幼安赴澶倉','鄒浩','宋','宋诗','song-poetry','','[]','人生本逆旅，行止良悠悠。',96,'全唐诗/poet.song.69000.json','["人生本逆旅，行止良悠悠。", "試看康荘上，轍跡多成溝。", "公子分閉戶，時來亦何由。", "載書曉遄邁，春令方如秋。", "河濱古城府，稅鞅聊優游。", "青雲捷徑在，氏庾非君優。", "臧孫故有後，斬斬承風流。", "故爲重作惡，日暮猶登樓。"]'),
('a534f0ba-db77-41de-8c6a-d1c2e2c85d0d','仲儒烹密雲龍得烹字','鄒浩','宋','宋诗','song-poetry','','[]','清都密雲龍，遐方久馳名。',120,'全唐诗/poet.song.69000.json','["清都密雲龍，遐方久馳名。", "無因飲天賜，歎息非公卿。", "爾來牛斗間，瑞氣蟠縱横。", "龜書識至寶，近在璧假城。", "物色到君箧，發視凡骨驚。", "君心本鐡石，從此亦變更。", "自言匹夫耳，乃有懷玉聲。", "羣嘲杜潛隙，徑約良友烹。", "伊予豈其人，重以慰平生。", "可憐謝康樂，新詩徒爾鳴。"]'),
('d0958898-3f6e-4787-bf2a-c4f8c8afe2eb','鮮于大受蛻軒','鄒浩','宋','宋诗','song-poetry','','[]','斵輪知讀書，解牛知養生。',156,'全唐诗/poet.song.69000.json','["斵輪知讀書，解牛知養生。", "天下一致耳，冰泮無餘情。", "向來所筌蹄，俄已蜩甲輕。", "豈必吟澤畔，始爲當世清。", "魯堂殆庶幾，居然黜聪明。", "蠢蠢冠屨間，胸中妙難名。", "鼓鑄雖有自，竟脫模範成。", "詩翁既遷去，委蛻今韓城。", "閉門作龍蟄，端俟風雷驚。", "文史聊寄徑，與古将抗衡。", "何以識此心，標牓輝前楹。", "他年付卷舒，會見推善鳴。", "應憐劉季陵，寂寞初無聲。"]'),
('91c9389a-3f7a-41d6-bac8-c09f6f7f7e3b','送鄭祭酒得宮觀還鄉','鄒浩','宋','宋诗','song-poetry','','[]','閩中男子多儒衣，龍驤虎視惟四夔。',384,'全唐诗/poet.song.69000.json','["閩中男子多儒衣，龍驤虎視惟四夔。", "門前蓬藋老風雨，籍籍聲名天下馳。", "爾來半作古人去，亦或霜鬢甘伏雌。", "獨隨日月上星斗，即今先生侍丹墀。", "先生胸次真武庫，無所不有世莫窺。", "早年剖符勤撫字，晚年賜環妙論思。", "朝廷遠覽得治本，務先長育英豪姿。", "凌雲大廈豈一木，要在鉅細皆其宜。", "先生彬彬掲模楷，仰膺帝可端爲師。", "鸞飛鳯舉徧臺閣，辟雍祭酒終不移。", "下帷莊坐對沉燎，諸生自耻専浮詞。", "斯文與天共澄霽，肅駕聖域無多岐。", "他時合抱挽梁棟，論功較德誰高卑。", "先生胡不長風憲，豺狼在念略狐狸。", "坐令飲恨深發喜，簪纓無復藏奸欺。", "先生胡不同翰墨，形容堯仁曉天涯。", "魯官典誥從此復，大哉王言非寄私。", "先生胡不秉樞極，以道揆事如蓍龜。", "河防民役有定論，簡拔賢俊去嫌疑。", "吏員一一底乃績，二虜拜手受指撝。", "東西南北幾萬里，匹夫匹婦違寒饑。", "人言太平亦無象，但見父老同兒嬉。", "胡爲五湖入清夢，忽焉幽興落武夷。", "千鈞一發誰挽得，徑約赤松歌紫芝。"]'),
('bd155852-edcf-4446-969d-703562d42240','元魯侍親還以凡今之人莫如兄弟賦詩送之  其一','鄒浩','宋','宋诗','song-poetry','','[]','秋風卷輕帷，似送東歸帆。',48,'全唐诗/poet.song.69000.json','["秋風卷輕帷，似送東歸帆。", "親心爲惻惻，穀馬馳兩銜。", "吳江渺清冷，吳山鬰巉巖。", "侍行不爾俱，官曹猶治凡。"]'),
('12b0c091-2fb3-41c1-b294-ea321f43d2a0','元魯侍親還以凡今之人莫如兄弟賦詩送之  其二','鄒浩','宋','宋诗','song-poetry','','[]','北去青山門，宰木行森森。',48,'全唐诗/poet.song.69000.json','["北去青山門，宰木行森森。", "吾祖不可見，歲月成古今。", "侍親奠雞酒，應慰久客心。", "爾心故自慰，爾兄涕沾襟。"]'),
('3e6b5392-4ede-4e66-887f-0e9f524a9b88','元魯侍親還以凡今之人莫如兄弟賦詩送之  其三','鄒浩','宋','宋诗','song-poetry','','[]','爾生見天地，較我兩歲遲。',48,'全唐诗/poet.song.69000.json','["爾生見天地，較我兩歲遲。", "兒童作壮夫，恍若旦暮期。", "詩禮久服膺，飛鳴當及時。", "慎勿醉鄉去，志士良耻之。"]'),
('02c191ee-3de3-47ec-bea9-d55aea9783fb','元魯侍親還以凡今之人莫如兄弟賦詩送之  其四','鄒浩','宋','宋诗','song-poetry','','[]','姑蘇一都會，井徑分龍鱗。',48,'全唐诗/poet.song.69000.json','["姑蘇一都會，井徑分龍鱗。", "風俗如鄆城，臧否朝朝新。", "况爾隨侍子，動與嫌疑鄰。", "延篤儻可師，不如陪古人。"]'),
('87179b86-da41-4e60-943e-bb68cfd69543','元魯侍親還以凡今之人莫如兄弟賦詩送之  其五','鄒浩','宋','宋诗','song-poetry','','[]','至遠挽不來，庭竹屢隕籜。',48,'全唐诗/poet.song.69000.json','["至遠挽不來，庭竹屢隕籜。", "剖魚得素書，頗說甘寂寞。", "矯枉勿過正，執中思子莫。", "他年同我心，俯仰無愧怍。"]'),
('dd448e8a-455e-4047-805e-b7c6e9bedfd6','元魯侍親還以凡今之人莫如兄弟賦詩送之  其六','鄒浩','宋','宋诗','song-poetry','','[]','至虚走橋門，所樂在羣居。',48,'全唐诗/poet.song.69000.json','["至虚走橋門，所樂在羣居。", "羣居固可樂，他途亦紛如。", "合抱自毫末，要須慎其初。", "大带有餘否，此語當急書。"]'),
('10414c9d-e9cf-4db0-9f7e-df215221cb10','元魯侍親還以凡今之人莫如兄弟賦詩送之  其七','鄒浩','宋','宋诗','song-poetry','','[]','詹何我師友，文行懸高名。',48,'全唐诗/poet.song.69000.json','["詹何我師友，文行懸高名。", "天命豈易度，棲遲尚柴荆。", "省定餘白晝，相與發大鳴。", "才進非故吾，從此難爲兄。"]'),
('29253f76-a045-4afc-a203-8fc77d5e323d','元魯侍親還以凡今之人莫如兄弟賦詩送之  其八','鄒浩','宋','宋诗','song-poetry','','[]','四人如四支，闕一不成體。',48,'全唐诗/poet.song.69000.json','["四人如四支，闕一不成體。", "故爲各天涯，阻異晨昏禮。", "但願器業成，高陽亦兄弟。", "此意何時窮，潁川方瀰瀰。"]'),
('7c9b13ed-2cc7-43b9-9f6e-41c6a4ac2214','次韵德符夜訪世美','鄒浩','宋','宋诗','song-poetry','','[]','蘇子甫及瓜，装齎動簷楹。',84,'全唐诗/poet.song.69000.json','["蘇子甫及瓜，装齎動簷楹。", "念此不數見，柴門行晝扃。", "幅巾策藜杖，邂逅諸友生。", "涼月委新照，無煩聚飛螢。", "懽然造空洞，卻顧輕簪纓。", "虀鹽未果腹，飽德如楚萍。", "只應他夕來，矯首心盈盈。"]'),
('4a7c780f-4226-48ea-8c4e-a177e2f69a8e','次韻樗年見簡','鄒浩','宋','宋诗','song-poetry','','[]','一身能幾何，首尾復自畏。',72,'全唐诗/poet.song.69000.json','["一身能幾何，首尾復自畏。", "豈知塵表姿，落落惟所值。", "官攡忽相逢，欣悲十年事。", "須知襲人間，舒卷在毋意。", "他時況英聲，曾冠通侯次。", "行矣方坦途，真賢不難繼。"]'),
('ed972c6a-892e-4fe4-a53d-184f557a1a02','用前韻寄鄉中諸長者','鄒浩','宋','宋诗','song-poetry','','[]','鄉邦藹儒冠，後生良可畏。',72,'全唐诗/poet.song.69000.json','["鄉邦藹儒冠，後生良可畏。", "况乃領袖賢，疑與古人值。", "爾來索吾居，南北幾歲事。", "冥鴻雲外心，疲馬風前意。", "遙知松菊間，青編焕鱗次。", "何當返柴車，故步懽然繼。"]'),
('f059fe3a-0172-4058-8582-958eac3f04df','次韻德符過曾園  其一','鄒浩','宋','宋诗','song-poetry','','[]','東方澹殘星，車馬各有之。',72,'全唐诗/poet.song.69000.json','["東方澹殘星，車馬各有之。", "心落聲利間，搖搖無静時。", "幽人獨朝徹，蟾光濯漣漪。", "賦詩鷗鷺邊，妙絕中郎詞。", "青時正相嚮，白駒忽已馳。", "歸來過我談，聞風徒振衣。"]'),
('e9161a6d-c2a3-4735-9f64-cf37a172ef0f','次韻德符過曾園  其二','鄒浩','宋','宋诗','song-poetry','','[]','數子清玉峙，粲粲凌朝輝。',84,'全唐诗/poet.song.69000.json','["數子清玉峙，粲粲凌朝輝。", "持竿謝高風，鉢囊聊自携。", "豈不一趣尚，因緣非兔絲。", "北去得幽圃，相與無町畦。", "白鳥亦忘我，共此天然姿。", "只應太史奏，還在潁水涯。", "九原審難作，幸及同襟期。"]'),
('0d88664d-2dbd-4cdf-9467-2afc35fc3f69','次韻仲孺見督烹小團','鄒浩','宋','宋诗','song-poetry','','[]','世事多好還，往躅端可視。',144,'全唐诗/poet.song.69000.json','["世事多好還，往躅端可視。", "崟巖輝奇功，頗愧文王肆。", "他年焚舟來，幾作塗炭墜。", "駟馬豈及追，我今亦如是。", "狂言編虎鬚，得報逾掐鼻。", "平生儲春芽，美惡初一意。", "濁氛騰墨雲，君舌故歷試。", "小龍落几前，畢竟不知異。", "方欲事烹煎，薑鹽以爲使。", "賴君呼回頭，絲桐識秋思。", "會當掃南軒，石銚沃清泚。", "從此師金人，三緘誠有味。"]'),
('3d7801e3-6594-4bfc-9c2a-632d8b602a94','再酬仲孺','鄒浩','宋','宋诗','song-poetry','','[]','龍團方啓封，數子已驚視。',144,'全唐诗/poet.song.69000.json','["龍團方啓封，數子已驚視。", "端如肖壁人，騎羊入城肆。", "又如金谷姿，不合樓前墜。", "嚢衣本酸寒，茶具無一是。", "紛紛詰鄰家，浪欲學擁鼻。", "秋空輙雲雷，秘惜乃天意。", "未敢還巾車，且集諸生試。", "豈非今年芽，歲月與君異。", "直須如印刓，詩驛趼來使。", "念君才患多，落筆有餘思。", "盈編故可期，河流幾時泚。", "君應嘲馬肝，不食亦知味。"]'),
('3555a451-85b2-4db7-9139-55efafc9cb47','仲孺督烹小團既而非真物也悵然次韻以謝不敏','鄒浩','宋','宋诗','song-poetry','','[]','情僞初難分，飽聞不如視。',144,'全唐诗/poet.song.69000.json','["情僞初難分，飽聞不如視。", "君看求馬時，安得走唐肆。", "此茶亦先聲，入手恐失墜。", "泠然風御還，共飲乃非是。", "坐令竹邊心，追悔如刻鼻。", "故人豈欺予，姑以将遠意。", "由來毁譽間，夫子猶必試。", "八牀志多金，龍斷何足異。", "胡爲不三思，取信輶軒使。", "超超莆陽公，銓量妙清思。", "仰止一喟然，背浹欲流泚。", "尚賴君詩存，高吟忘肉味。"]'),
('5b412e52-2063-42a2-accc-7d015f6b3fa8','戲世美','鄒浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','楊家絕藝十六絃，公卿往往趨賓筵。',160,'全唐诗/poet.song.69000.json','["楊家絕藝十六絃，公卿往往趨賓筵。", "妙齡才子更豪酌，月中醉倒西湖船。", "楚宮殘夢幾春曉，五陵好事猶喧傳。", "只今展江嘗託足，香風带恨留苔錢。", "誰令故人不他寓，朅來亭上仍秋天。", "幽花脉脉鑑清潩，似與當日争蚩妍。", "此心如水亦滉漾，那堪銲撥還鏘然。", "驊騮夜半解歸鐙，青燈烱烱空韋編。", "砧聲漁唱起何許，坐久波面生寒烟。", "故應鷗鷺有深意，忽焉鼓趐鳴窗前。"]'),
('cff017e2-0550-4735-8374-e6eefe0f9a49','十六夜府會湖光亭呈世美','鄒浩','宋','宋诗','song-poetry','','[]','使君終宴先歸休，菱盤藻带妨移舟。',160,'全唐诗/poet.song.69000.json','["使君終宴先歸休，菱盤藻带妨移舟。", "湖邊何處月已到，觀音堂下寒光浮。", "鼎來談笑托新興，沉沉萬籟乾坤幽。", "雲端飛翼弄清靄，波間戲鬛吹輕漚。", "凉飈襲塵了無迹，似動不動蒹葭洲。", "却觀落日倚欄處，天東縹緲横高樓。", "不須要月共形影，吾曺兹焉成獻酬。", "单衣盈露坐忘返，亦忘佳客相與留。", "始知人世惡塵土，生平今夕方中秋。", "昨宵蓮社二三子，借問賞心如此不。"]'),
('8cb039cf-d619-4db1-9d0d-b148ddcc31d8','次韻德符訪世美','鄒浩','宋','宋诗','song-poetry','','[]','秋晨飯香積，舉袂清風生。',84,'全唐诗/poet.song.69000.json','["秋晨飯香積，舉袂清風生。", "朅來展江道，老木森亭亭。", "纖埃不隨步，昨宵寒露零。", "人境兩相值，簡編焕新晴。", "遷固久黄壌，椽筆窺群英。", "崔子獨異趣，一笑鉛槧輕。", "詩成似金籥，爲我開塵扃。"]'),
('f2db085c-9cfd-45e4-8b95-57a0d911b9f4','敬讀仁祖實錄用前韻','鄒浩','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','嘉祐紀庚子，犬馬初冬生。',84,'全唐诗/poet.song.69000.json','["嘉祐紀庚子，犬馬初冬生。", "安知拱堯舜，不事沉香亭。", "爾來百寮底，霏霏清涕零。", "弓劍誰與問，白雲飛晚晴。", "恭聞語乾造，凛如班集英。", "遺恩泰山重，死報鴻毛輕。", "聖孫王纂承，行當叩天扃。"]'),
('8855f09f-c37d-4db1-9bf2-9a69d4aed8b2','送杜君童學士赴闕','鄒浩','宋','宋诗','song-poetry','','[]','西風獵獵鳴旌旗，南陽學士趨丹墀。',224,'全唐诗/poet.song.69000.json','["西風獵獵鳴旌旗，南陽學士趨丹墀。", "南陽父老挽不住，家聲復如東漢時。", "堂堂材具中梁棟，鬢邊寒暑驚駒馳。", "垂衣繼照掲日月，只應一見舒堯眉。", "鸞臺鳳閣有新路，着鞭寧許駑駘知。", "委身報國一心耳，嶷如嵩岱誰能移。", "他時廷尉妙生死，還将此道供論思。", "凌雲大廈肅天宇，千秋萬歲無傾欹。", "焦頭爛額豈足尚，長堤蟻穴今圖之。", "回看蹇淺丈夫子，攫金清旦方沉迷。", "矢來無鄉亦可卹，付與公議分高卑。", "前人得失焕清簡，納公胸次無孑遺。", "願言朝退坐華省，更以反己爲元龜。", "儒冠往往喙三尺，勿令白玉生瑕疵。"]'),
('bad729d8-045d-42e2-86aa-10e82102b042','世美歸侍政府以送君南浦傷如之何作詩送之  其一','鄒浩','宋','宋诗','song-poetry','','[]','汎汎蓮花池，日月幾賓送。',48,'全唐诗/poet.song.69000.json','["汎汎蓮花池，日月幾賓送。", "乳燕辭故窠，征途亦飛鞚。", "會合安可常，萬事驚殘夢。", "何以寛我愁，風流在民衆。"]'),
('9481b8e6-26e3-4310-9d08-47e39ed44258','世美歸侍政府以送君南浦傷如之何作詩送之  其二','鄒浩','宋','宋诗','song-poetry','','[]','妙年公卿子，可人逢此君。',48,'全唐诗/poet.song.69000.json','["妙年公卿子，可人逢此君。", "退然數尺耳，氣節凌青雲。", "從今奉親暇，簡策陪朝曛。", "應憐四傑流，勤勤但空文。"]'),
('f7b47d6a-f215-4167-b477-4193e56909ad','世美歸侍政府以送君南浦傷如之何作詩送之  其三','鄒浩','宋','宋诗','song-poetry','','[]','巖廊拱真人，妙與天地参。',48,'全唐诗/poet.song.69000.json','["巖廊拱真人，妙與天地参。", "政教似寒暑，豈罪樵夫談。", "木鐸久不振，相府方潭潭。", "公子飽見聞，歸獻北斗南。"]'),
('c5838856-8d43-4edc-a79c-caecbf87c61f','世美歸侍政府以送君南浦傷如之何作詩送之  其四','鄒浩','宋','宋诗','song-poetry','','[]','忠孝非兩心，事君如事父。',48,'全唐诗/poet.song.69000.json','["忠孝非兩心，事君如事父。", "事君貴以人，事父孰爲愈。", "真賢絕驊騮，骨相未易取。", "願子繼法真，毋令老江浦。"]'),
('ba9ca6d2-dc1b-414c-88f2-ae96436e95d9','世美歸侍政府以送君南浦傷如之何作詩送之  其五','鄒浩','宋','宋诗','song-poetry','','[]','前年可羅雀，朱幡出濠梁。',48,'全唐诗/poet.song.69000.json','["前年可羅雀，朱幡出濠梁。", "今年可炙手，衮衣登廟堂。", "公家本金玉，何曾變炎凉。", "公子不展眉，端爲斯人傷。"]'),
('6ef582d7-4831-483e-8cb2-0e45623b8c5f','世美歸侍政府以送君南浦傷如之何作詩送之  其六','鄒浩','宋','宋诗','song-poetry','','[]','卞氏稱六龍，公家宛相如。',48,'全唐诗/poet.song.69000.json','["卞氏稱六龍，公家宛相如。", "久作風雨散，于今共詩書。", "山前猶製錦，江上方題輿。", "遙想侍側心，夙夕鴈與魚。"]'),
('58c1e9e5-0d08-4ca3-8258-0fa081516d78','世美歸侍政府以送君南浦傷如之何作詩送之  其七','鄒浩','宋','宋诗','song-poetry','','[]','猶子知幾人，子獨欣白眉。',48,'全唐诗/poet.song.69000.json','["猶子知幾人，子獨欣白眉。", "風霆破春曉，怒翼鳴天池。", "未促南昌行，還爲竹間期。", "儻及馬伏波，一書重示之。"]'),
('a3e78865-46c9-423b-87f5-ae5c0386b5dd','世美歸侍政府以送君南浦傷如之何作詩送之  其八','鄒浩','宋','宋诗','song-poetry','','[]','蕪城兆霜雪，潁川凋芰荷。',48,'全唐诗/poet.song.69000.json','["蕪城兆霜雪，潁川凋芰荷。", "昔别情已矣，今别情奈何。", "英英二三子，行亦車懸𨍋。", "後日知誰同，蝉聲猶暮多。"]'),
('7e6603a3-a4e6-4e98-a966-0b73b853fe1b','送杜堪才以江漢故人少爲韻  其一','鄒浩','宋','宋诗','song-poetry','','[]','與君本南北，作吏同一邦。',48,'全唐诗/poet.song.69000.json','["與君本南北，作吏同一邦。", "詩書雅相好，旨酒空盈缸。", "歲晏賦歸去，冉冉車輪雙。", "我亦非匏瓜，兹焉念松江。"]'),
('bb95751c-8a01-4ba0-a737-36e8b81de853','送杜堪才以江漢故人少爲韻  其二','鄒浩','宋','宋诗','song-poetry','','[]','杜陵世多人，風流自唐漢。',48,'全唐诗/poet.song.69000.json','["杜陵世多人，風流自唐漢。", "振衣入朝廷，玉立争璀璨。", "若人獨何爲，轅下尚羈絆。", "舌在且加餐，慎勿發長歎。"]'),
('937656ad-5d99-40ec-9015-46b51c3050ec','送杜堪才以江漢故人少爲韻  其三','鄒浩','宋','宋诗','song-poetry','','[]','秋來幾何時，送遠驚已屢。',48,'全唐诗/poet.song.69000.json','["秋來幾何時，送遠驚已屢。", "山川澹無情，蒼莽亦非故。", "分與人跡疏，韋編對香霧。", "只應知此心，西陂有鷗鷺。"]'),
('5467360e-c32f-4731-8327-be85b6376bfc','送杜堪才以江漢故人少爲韻  其四','鄒浩','宋','宋诗','song-poetry','','[]','青衫勿自少，委質皆王臣。',48,'全唐诗/poet.song.69000.json','["青衫勿自少，委質皆王臣。", "貴賤物外耳，直道惟其人。", "下惠信先覺，到今如北辰。", "居閒儻未能，君志終當伸。"]'),
('630ceb11-0317-4a5c-b2a7-1f0f488cf9a7','送杜堪才以江漢故人少爲韻  其五','鄒浩','宋','宋诗','song-poetry','','[]','漢水方涸流，梁園正秋杪。',48,'全唐诗/poet.song.69000.json','["漢水方涸流，梁園正秋杪。", "駕言托朝昏，陳事有臺沼。", "他年李杜來，慷慨識者少。", "安得從君遊，一笑今古了。"]'),
('be187405-0722-4d02-a0fa-205f20d8477e','馬叔寶寄種竹詩次其韻','鄒浩','宋','宋诗','song-poetry','','[]','窮年不揮斧，歎息無妙質。',96,'全唐诗/poet.song.69000.json','["窮年不揮斧，歎息無妙質。", "誰知深眇中，環堵以爲室。", "紛筆如萬牛，力挽未曾出。", "論交餘此君，聊爲拂巾櫛。", "人間方好竽，蕭蕭乃鳴瑟。", "兹焉得所投，陳雷信難匹。", "昨來面墻心，舉倡有風日。", "莫似白樂天，殷勤在兜率。"]'),
('822382be-1aa3-4048-8702-746d5553ac71','雪中對竹','鄒浩','宋','宋诗','song-poetry','','[]','飛雪一何情，拜我南軒竹。',120,'全唐诗/poet.song.69000.json','["飛雪一何情，拜我南軒竹。", "駢頭控於地，默默隃信宿。", "寒花本輕揚，叢集乃折軸。", "况此梢雲姿，蕭然異凡木。", "飄風亦狂生，端來助陵蹴。", "似欲揉直柯，繞指惟所欲。", "焉知天與剛，初不愧幽獨。", "罄折雖爾爲，且異望塵辱。", "晨光破沈陰，春色盈兩目。", "風雪安在哉，竹猶故時玉。"]'),
('63b8337c-a785-4e0c-8107-e4bee4970cd8','次韻韓君表雪中感懷','鄒浩','宋','宋诗','song-poetry','','[]','龍衣不解顔，憂民向來急。',120,'全唐诗/poet.song.69000.json','["龍衣不解顔，憂民向來急。", "天高委真符，年豐兆原隰。", "連山水氣昏，過雲鴈聲澀。", "先春凌馬奔，投隙作塵入。", "瀕竹乍蕭蕭，驚風還汲汲。", "頗輕花闘狂，肯共雨争濕。", "夜半回曉光，木杪森鵠立。", "開編適吾心，鼓枻輟清集。", "一飽儻可償，萬事非所及。", "想見秋稼前，腰鐮荷青笠。"]'),
('e040c647-464c-4651-b6cf-ce05a95be16c','用前韻寄德符','鄒浩','宋','宋诗','song-poetry','','[]','叩門無季心，爾來空緩急。',120,'全唐诗/poet.song.69000.json','["叩門無季心，爾來空緩急。", "若人作枯蓬，隨風落遙隰。", "袖書珠玉昏，匣劍蛟龍澀。", "雪花陵春陽，山寒擁扉入。", "孤松初自高，短綆豈易汲。", "伊予不逢年，所嚮驚束濕。", "分携忽歲遷，結念成骨立。", "蕭蕭清潩濱，冉冉白鷗集。", "盟好何當尋，瓜時亦云及。", "東游儻未忘，蘆邊一漁笠。"]'),
('dbddd92f-be1d-48c0-8dec-e8fe140d6b07','次韻仲孺夢與世美諸友同集','鄒浩','宋','宋诗','song-poetry','','[]','簞食凄窮閻，綵衣焕華屋。',120,'全唐诗/poet.song.69000.json','["簞食凄窮閻，綵衣焕華屋。", "公子謝羣居，幾年羊胛熟。", "逢迎紛故人，趣異終疑獨。", "精誠洞虚無，相應比如竹。", "不羡春風前，流鶯囀喬木。", "勤勤通昔心，全勝書一束。", "胡然亦神遊，邂逅同夢鹿。", "夜旦環中來，夢覺更主僕。", "只今所見聞，轉手驚莫復。", "冰釋倘未能，兹焉良可燭。"]'),
('679b260f-16a2-410a-84c7-52ceb71f4f7a','次韻和韓大資湖光亭對雪之什','鄒浩','宋','宋诗','song-poetry','','[]','巖廊未旋歸，故國聊自晦。',84,'全唐诗/poet.song.69000.json','["巖廊未旋歸，故國聊自晦。", "塵表澹崧高，胸中妙天對。", "豐年隨政還，嘉雪徧境內。", "從容陟九層，指顧紛百態。", "經綸動初心，枯槁入長嘅。", "雖陳北海樽，終念東臯耒。", "只應沙路乾，依前符帝賚。"]'),
('84371ea9-41b6-4d35-8969-78ef2402db7a','送曾仲敷赴慶州司戶','鄒浩','宋','宋诗','song-poetry','','[]','棲遲潁水無三年，四見長途事鞍馬。',256,'全唐诗/poet.song.69000.json','["棲遲潁水無三年，四見長途事鞍馬。", "問君胡爲樂驅馳，告我吾非苟然者。", "向來庭闈故當爾，今乃從知古塞下。", "男兒出腹在四方，齪齪南窗吾未暇。", "隻手扛鼎非吾力，百步穿楊非吾射。", "眇然軀幹僅數尺，智略豈分子房亞。", "詩書禮樂工作謀，元帥軒軒更儒雅。", "相知不與今人同，往遊其藩躍如也。", "君言慷慨得我驚，我有私憂爲君寫。", "巍巍法座天中央，萬物生成得陶冶。", "邊塵吹風不見人，麟鳳猶阻遊郊野。", "煩将此意問元帥，何當鐡甲懸高架。", "君家一唯如雷霆，震動乾坤失聾啞。", "願回廬阜異時心，白刃前頭薦瀟灑。", "家風欻從千古還，上策酬恩真土苴。", "口終拂袖兩無言，因送飛鴻不知夜。"]'),
('85fda947-221b-4e0f-b7c9-8d530652df79','次韻仲孺見懷十二韻','鄒浩','宋','宋诗','song-poetry','','[]','江梅飛故枝，桃李日夕更。',144,'全唐诗/poet.song.69000.json','["江梅飛故枝，桃李日夕更。", "宰物初無心，芳菲自奔競。", "幽禽衘真如，歷歷唤不醒。", "東里似得之，與春忘謁請。", "頹然蘧廬中，槃薄天地永。", "交情海漚發，吟興秋翮勁。", "璀璨十二旒，陶謝不獲騁。", "須知雲氣蒸，未害山石硬。", "但君已追風，顧我猶蹇乘。", "試馮作詩光，普照萬物盛。", "物盡照亦空，何許開絕景。", "他時從此來，一眄躐千聖。"]'),
('5cb5dfb0-d06b-4866-970c-5db42f6cecc0','次韻世美見寄','鄒浩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鼻端漫故蝇，心與天地遠。',71,'全唐诗/poet.song.69000.json','["鼻端漫故蝇，心與天地遠。", "聲容天地前，長似西湖晚。", "判合亦何常，從古車輪轉。", "君不見儒衣壌壌趨白頭，幾人管鮑情相收。", "我豈季子難之鄒，行矣同聽黄栗留。"]'),
('be19d28b-6cad-4cd0-8654-302baad45565','與仲孺破兔餅色味皆惡同一絕倒既而述之又烹小團亦兔餅也作詩報世美','鄒浩','宋','宋诗','song-poetry','','[]','爭携懃意烹春風，終焉臧穀同一蹤。',64,'全唐诗/poet.song.69000.json','["爭携懃意烹春風，終焉臧穀同一蹤。", "莫言不落第二月，須知所好非真龍。", "竊香安得青瑣趣，效矉頗慚西子容。", "此言雖小有大喻，馮君轉達裨時雍。"]'),
('5e2851be-cacd-42a6-9002-d85c007f864a','與仲孺文仲述之作詩送仲弓赴籍田以之子于征爲韻分得子字','鄒浩','宋','宋诗','song-poetry','','[]','鳳園佳人孤鳳起，草木無光春披靡。',160,'全唐诗/poet.song.69000.json','["鳳園佳人孤鳳起，草木無光春披靡。", "紅亭碧沼政高深，借問何由駐雙履。", "王涂開泰日月中，玉堂仙翁是知已。", "瀛洲蓬島未横飛，且向籍田聊爾耳。", "北道仲容休說貧，東山太白誰比擬。", "雲汀荷芰供遠凉，遶砌青青更蘭芷。", "丞相上馬臺閣空，長鞭往往城南指。", "君身雖不作羊羶，自然塵表門如蟻。", "清談秀句得豪英，合抱他年欝松梓。", "要須萬口一同聲，文恪風流今有子。"]'),
('2e21bc48-2152-4385-bf56-c8cddc11bbb2','次韻劉元因贈王幼安','鄒浩','宋','宋诗','song-poetry','','[]','真人拱南嚮，羣英紛玉除。',132,'全唐诗/poet.song.69000.json','["真人拱南嚮，羣英紛玉除。", "趯趯動環海，夙懷思遠攄。", "争彈冠上塵，丘壑空故居。", "之子建安裔，少長惟詩書。", "毎笑靖節君，歸來但巾車。", "擬倍萬乘器，璨璨雕璠璵。", "終然怒劍横，銳氣埋憂虞。", "須知夢鏡中，所適難一如。", "倘不達本原，觸事成自誣。", "試焚定慧香，矯首瞻六銖。", "於此發深省，鼓瑟猶吹竽。"]'),
('71331f1e-083a-4b7e-badd-611d1c1aefa6','次韻錢濟明訪定力僧及寄吳行古三首  其一','鄒浩','宋','宋诗','song-poetry','','[]','門前朝市喧，門內山谷寂。',72,'全唐诗/poet.song.69000.json','["門前朝市喧，門內山谷寂。", "昨來有慮心，到此了無迹。", "况復有高僧，炯炯雙眼碧。", "渠今未易親，拄杖鳴百尺。", "知君從之遊，勤我遙相憶。", "安得雙樹傍，題名拂塵壁。"]'),
('dd637883-67cf-46d8-bcc5-5cc82695510c','次韻錢濟明訪定力僧及寄吳行古三首  其二','鄒浩','宋','宋诗','song-poetry','','[]','北闕來新榮，南溪抱初寂。',72,'全唐诗/poet.song.69000.json','["北闕來新榮，南溪抱初寂。", "二子非世交，窮通偶殊迹。", "詩書寄平生，孤雲卷晴碧。", "遙遙天一涯，回首無咫尺。", "伊予亦鄉邦，豈敢煩記憶。", "尚誤分隋珠，宵光動墻壁。"]'),
('92dc0463-2331-4eb7-92ad-d51a566502a1','次韻錢濟明訪定力僧及寄吳行古三首  其三','鄒浩','宋','宋诗','song-poetry','','[]','萬物遞先死，憧憧嘗未寂。',72,'全唐诗/poet.song.69000.json','["萬物遞先死，憧憧嘗未寂。", "中有不動尊，隨方示形迹。", "巨海何曾波，長天自來碧。", "誰令失坦途，認此軀七尺。", "空華初無根，欣厭浪思憶。", "君今倘回光，奚須鑿鄰壁。"]'),
('f381c506-831e-4929-a48d-ca8dff0be5b0','寄題孔先生行歌亭','鄒浩','宋','宋诗','song-poetry','','[]','仁皇御宇作太平，朝廷玉立森賢英。',208,'全唐诗/poet.song.69000.json','["仁皇御宇作太平，朝廷玉立森賢英。", "巖耕溪釣日寂寞，何獨先生歌滍城。", "遭世不比徐孺子，設心不愧司馬承。", "唐虞垂拱豈不盛，巢由亦自非公卿。", "冥冥三聖妙相遇，六爻一半曾吞并。", "倐遺象數入天籟，無聲之中端有聲。", "有時鼓腹散秋步，有時擊壌舒春情。", "他年野叟得不盡，獨與杖屨同縱横。", "故知造物有深意，鳳凰來儀治功成。", "鳳凰飛去定難久，直使先生爲鳳鳴。", "先生道德初不死，先生歌聲猶可聽。", "微風淅瀝動草木，幽禽上下喧陰晴。", "可憐雙耳不到此，龍山滍水空危亭。"]'),
('fab9c4f4-80de-46b0-b3bb-015ddd862d79','送文仲省親','鄒浩','宋','宋诗','song-poetry','','[]','曾參愛孝通神明，樂正子春遊其門。',144,'全唐诗/poet.song.69000.json','["曾參愛孝通神明，樂正子春遊其門。", "下堂傷足不忍出，流光至今覃後昆。", "阿文全似李令伯，更相爲命母與孫。", "母年可懼髪委雪，諸父駢頭埋九原。", "淮山之陽歸未得，飲啜無以供晨昏。", "脫身來寄豈獲己，方寸搖搖旌旆翻。", "飛雲入望且還岫，况乃凱風吹棘薪。", "白水真人挽不住，却垂故槖馳京塵。", "皇天后土識君意，如君勿憂長賤貧。"]'),
('3a3600be-f988-4c74-97e1-a407be3417a7','賦羲皇上人分韻得風字','鄒浩','宋','宋诗','song-poetry','','[]','妙達萬物祖，天地生胸中。',48,'全唐诗/poet.song.69000.json','["妙達萬物祖，天地生胸中。", "坦腹夏日眠，五柳來熏風。", "不絃虞舜琴，不觴唐堯鍾。", "况復羲皇前，豈直将無同。"]'),
('69ba9891-3fba-4179-90aa-a7da72c4b9e0','送大受赴天官','鄒浩','宋','宋诗','song-poetry','','[]','元祐真人初御天，四門穆穆來忠言。',192,'全唐诗/poet.song.69000.json','["元祐真人初御天，四門穆穆來忠言。", "閬風學士望朝野，即日賜環司諌垣。", "當時同列繼登用，獨先朝露歸九原。", "位不酬身在孫子，嶷嶷諸子聲名喧。", "叔也縱横五經內，娱目未始窺家園。", "苟聞某所有賢者，弊車趼僕從之奔。", "甘陵南北正分黨，攘臂其間無怨恩。", "未見其止見其進，會須一指收乾坤。", "素冠俛首琴復御，鵬飛九萬方化鯤。", "于今怙恃只明主，肯與世俗均寒暄。", "早知妙筆三千牘，矧已慟哭論元元。", "韓城父老儻改作，爲報及此高閭門。"]'),
('d287c591-a62a-4fc4-a259-c6f242024eab','雙璧歌寄馬叔寶','鄒浩','宋','宋诗','song-poetry','','[]','君不見朱公託身天地中，四方萬貨常憧憧。',171,'全唐诗/poet.song.69000.json','["君不見朱公託身天地中，四方萬貨常憧憧。", "其間雙璧最奇寶，分明日月生西東。", "問公酬價初幾所，一者千金一半此。", "精神肉好非不同，側視裁差厚薄耳。", "公心夙悟誰得窺，但無故槖無留貲。", "交貧族遠富衣食，高義日與清風馳。", "梁人有獄久不决，君臣相顧空嚬眉。", "公來答問只一語，群疑亟判如蓍龜。", "須知成效異霄壌，頗恨儒冠多失之。", "多失之，胡弗思，他年薄俗待爾移，奈何璧價先自虧。"]'),
('e5e61c9a-1d94-4a8f-8f77-a0f8e04c850e','送表兄華元翰赴四會尉','鄒浩','宋','宋诗','song-poetry','','[]','頤山潁水天西東，四載相望二千里。',256,'全唐诗/poet.song.69000.json','["頤山潁水天西東，四載相望二千里。", "我守枯株未得還，君逐飛蓬忽然至。", "坐令桑梓落眼中，頓覺精神到塵外。", "昔人逃空喜足音，况乃謦欬逢昆弟。", "此會由來天予之，幾日冷風清暑氣。", "君才榮華早馳名，荆國先生曾改視。", "殿前射策失龍頭，仕處波濤起平地。", "胸中萬慮不一施，却作明時嶺南尉。", "太夫人年七十三，諸子半掩黄壚逝。", "蘭陔養志獨賴君，路遠何由復迎侍。", "當思有以慰其心，莫把光陰較榮悴。", "本朝丞相豈不盛，尚輩流人已三歲。", "君今補考裁秋冬，託身民上與之異。", "蕭條官府似僧居，春入梅花更堪醉。", "要須相與無町畦，卷舌爲喑真得計。", "我家宅相世所知，矯首南雲從此俟。"]'),
('f44763bb-04e2-4034-9515-2d38b2533c5a','送章顯父推官改官','鄒浩','宋','宋诗','song-poetry','','[]','高堂夫人九十餘，一子晚方趨仕途。',136,'全唐诗/poet.song.69000.json','["高堂夫人九十餘，一子晚方趨仕途。", "前年封邑非子致，更待子榮新命書。", "子紆墨綬來漢東，百里氣和年屢豐。", "聲名籍籍動羣耳，還似當時詩賦中。", "諸公欲默安得已，争遡日邊飛薦紙。", "拔身左選歸尚書，攄發平生從此始。", "攄發平生從此始，未足爲子增欣喜，所喜榮親有期矣。", "郡邑疏恩壽齯齒，斑衣兒啼奉甘旨。"]'),
('9d7731cd-c295-41a7-bc1f-d56aa02069f4','寄仲弓','鄒浩','宋','宋诗','song-poetry','','[]','道德不與祿位期，富貴自隨時命至。',64,'全唐诗/poet.song.69000.json','["道德不與祿位期，富貴自隨時命至。", "君賓以明故自銷，禦寇於羊知去意。", "城南豈復異墻東，詩句由來勝刺字。", "直作朱游真丈夫，莫使小生敢相吏。"]'),
('1c114385-7dea-459e-a6a4-f46212018ce7','次德符韻六詩 書懷二首 其一','鄒浩','宋','宋诗','song-poetry','','[]','秋容未覺成蕭颯，脩竹疏桐陰四匝。',112,'全唐诗/poet.song.69000.json','["秋容未覺成蕭颯，脩竹疏桐陰四匝。", "先生歸駕挾西風，堕我南堂似凋葉。", "對牀邀月入高談，夢想從來謝三接。", "是非火作正炎空，忍與紛紛競牙頰。", "莫欺鷗鳥不知人，須信天機在眉睫。", "妙哉託處無何鄉，一念能回百千劫。", "君誠有意涉其流，請爲安行具舟楫。"]'),
('91f13d2f-3358-4ad4-b4ab-32fde56424de','次德符韻六詩 書懷二首 其二','鄒浩','宋','宋诗','song-poetry','','[]','木杪秋風鳴颯颯，環步空亭日千匝。',112,'全唐诗/poet.song.69000.json','["木杪秋風鳴颯颯，環步空亭日千匝。", "忽迂征轡入衡門，共看霜輪上雲葉。", "紫煙收盡擬階升，白露漙空欣手接。", "何須清酌浣枯腸，自覺爽氣滋雙頰。", "可憐末路競牛毛，不悟勞生寄蚊睫。", "向非覇處務功成，争得盟時遭智劫。", "西山君故有風期，我亦從今理歸楫。"]'),
('8fb5340f-4a04-4ead-a149-602ef3681602','次德符韻六詩 分韻見簡','鄒浩','宋','宋诗','song-poetry','','[]','幽人寄巖谷，志士從簪纓。',168,'全唐诗/poet.song.69000.json','["幽人寄巖谷，志士從簪纓。", "所尚初不同，出處皆有行。", "夫子胡爲哉，飲露餐秋英。", "和璧以爲質，黄鐘以爲聲。", "皎皎文史中，久作星斗明。", "一見輙心降，端如屈人兵。", "天意亦可料，禍患矧已經。", "豈其禮樂時，而不收珪珽。", "故知阿衡任，便是西山清。", "我豈夫子徒，猥辱藪澤并。", "驅車遠過我，爲我開天庭。", "凡今落松麈，皆昔所未聆。", "念此坐相阻，三十六峰横。", "子言不子隨，猶得座右銘。"]'),
('6a3fced5-37be-4540-b45a-97bedcf01930','次德符韻六詩 與德符仲孺述之宿南堂分得客字','鄒浩','宋','宋诗','song-poetry','','[]','從容白露前，轉盼一歲隔。',48,'全唐诗/poet.song.69000.json','["從容白露前，轉盼一歲隔。", "念我方促装，夫君復來客。", "疏篁生晚音，霽月澹秋色。", "此會豈易諧，未用詢長陌。"]'),
('6d8385fb-6b43-4e59-ac3c-7dd42d48d518','次德符韻六詩 南堂分韻得秋字','鄒浩','宋','宋诗','song-poetry','','[]','大火不東駐，高堂文字秋。',48,'全唐诗/poet.song.69000.json','["大火不東駐，高堂文字秋。", "青蝇付驅除，白日堪遲留。", "雞癰落新烹，瓜疐收輕浮。", "尚有明月在，倘能如故不。"]'),
('5ac2eafa-d069-4c6b-b798-89cfb52e5f6b','次德符韻六詩 曾園分韻得得字','鄒浩','宋','宋诗','song-poetry','','[]','藩城富池塘，所向輙荆棘。',48,'全唐诗/poet.song.69000.json','["藩城富池塘，所向輙荆棘。", "天風初轉西，朋簪共來北。", "暑清隨處幽，蓮高向人默。", "羣鷗安在哉，我今均爾得。"]'),
('7a4e0877-2bdf-460d-bd39-a50a31aa6896','再宿南堂分韻得星字','鄒浩','宋','宋诗','song-poetry','','[]','夕雲不成雨，冉冉東南征。',48,'全唐诗/poet.song.69000.json','["夕雲不成雨，冉冉東南征。", "凉月掛河漢，鮮風起階庭。", "蛩韻響新織，螢光駛流星。", "誰知亦有念，夙駕在青冥。"]'),
('c5a5cdcc-0793-47d3-8a66-430b76db890d','分韻送德符還山得送字','鄒浩','宋','宋诗','song-poetry','','[]','秋風歘來歸，秋事日夕動。',96,'全唐诗/poet.song.69000.json','["秋風歘來歸，秋事日夕動。", "葉淨嵩嶺高，煙空潁川縱。", "茅齋鬰其傍，妙與猿鶴共。", "拂衣問前途，不作河濱夢。", "念君如病松，重以旻天慟。", "未屠朱子龍，且集黄公鳳。", "伊予亦何爲，於此迭賓送。", "慎勿甘自埋，斯文要梁棟。"]'),
('2535af44-2993-42cd-b521-76500ad32aab','送陳志仁赴河州司理','鄒浩','宋','宋诗','song-poetry','','[]','佳人宰木懸秋月，穉子霏霏灑清血。',160,'全唐诗/poet.song.69000.json','["佳人宰木懸秋月，穉子霏霏灑清血。", "枯風冷雨暗長天，借使端居亦心折。", "問君夙駕今何之，萬里關河西復西。", "西州平昔但聞語，不意黄塵隨綠衣。", "将軍雅歌飛玉觴，健兒如鼠馬如羊。", "桁楊生耳卧庭廡，日冀賓僚來畯良。", "雪霜肅殺百草死，孤峰嫋嫋砂磧光。", "城頭笳鼓咽初曉，夢破衾禂皆異鄉。", "情鍾矧復是君輩，只應矛矟攅中腸。", "只應矛矟攅中腸，當思大人在高堂。"]'),
('4961afdc-4119-43fd-b0f1-e88610a2eca4','送羅正之爲兩浙提刑','鄒浩','宋','宋诗','song-poetry','','[]','滄溟可枯山可移，公心獨與天地期。',128,'全唐诗/poet.song.69000.json','["滄溟可枯山可移，公心獨與天地期。", "田間經術入州縣，所至父老均兒嬉。", "明明日月照肝膽，謂言吾民方阻饑。", "回車爲我作豐歲，要令國體無瘡痍。", "買臣郡去不持節，季真逸請非康時。", "幾年夢想在松檟，再拜一觴今得之。", "鄉人擁路識忠孝，雅慰平生良可知。", "恩光到此何以報，行矣二浙如王畿。"]'),
('bde6ed7a-e569-4acd-9fe5-2962396b8f38','送裴仲孺爲太和尉','鄒浩','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','波濤幾千里，洶洶東南注。',120,'全唐诗/poet.song.69000.json','["波濤幾千里，洶洶東南注。", "故人帆北風，絕意蛟龍怒。", "孤州何處城，幾盡長江路。", "鴻鴈方來飛，霜雪且凝沍。", "夜旦耳目中，動與客心忤。", "况乃青雲姿，四十困不遇。", "有室常罄懸，未免折腰去。", "命也天造之，智力豈其預。", "端能一判然，楚越猶跬步。", "崖邊晚分携，君顔湛如故。"]'),
('9332bd85-6930-4b8a-8b10-ce57c968cc56','送李子威致仕還鄉','鄒浩','宋','宋诗','song-poetry','','[]','人間勳業如作詩，先生能詩端自知。',208,'全唐诗/poet.song.69000.json','["人間勳業如作詩，先生能詩端自知。", "人間得喪如奕棋，先生能棋復何疑。", "此身未免人間世，南北東西聊爾耳。", "波濤風際湧丘山，不害江河爲止水。", "今年青春草木青，只有白髪日日新。", "先生一笑謝簪紱，歸作三吳高尚人。", "三吳寒暄幾來去，童時閭井今猶故。", "閭門親舊半成空，往往子孫無託處。", "先生第宅瀕清流，負郭歲有千鍾收。", "揮金買酒醉花月，一局一篇方外遊。", "諸郎森森美且修，名聲相繼徹冕旒。", "斑衣夙夕奉顔色，借問達官誰與儔。", "他年再拜鄉人後，猶能敬爲先生壽。"]'),
('5b8247fd-bb73-4730-93fe-feec2146475c','送散老歸龍井','鄒浩','宋','宋诗','song-poetry','','[]','長安冥冥砂礫飛，道人趼足來何爲。',112,'全唐诗/poet.song.69000.json','["長安冥冥砂礫飛，道人趼足來何爲。", "師恩浹髓未云報，誓求卿相成其碑。", "卿相盈朝成者誰，尚書妙墨侍郎詞。", "二公奔走天下士，士獲一面猶幾希。", "道人願力豈不滿，文字乃今兼得之。", "龍井神龍應護持，杖頭星斗東南垂。", "過門别我自色喜，我愧儒冠多背師。"]'),
('0f6534c4-c8ed-49ba-8dae-811f776ed50e','送榮子邕宰新鄭','鄒浩','宋','宋诗','song-poetry','','[]','子淵陋巷居，子真巖下耕。',84,'全唐诗/poet.song.69000.json','["子淵陋巷居，子真巖下耕。", "窮約一如此，不妨道自行。", "矧君有民社，南面恩光榮。", "問學□經濟，豈不慰高情。", "爾來幾薫風，許洛猶聲名。", "還将模範心，農桑厚羣生。", "行矣輿人歌，國僑相弟兄。"]'),
('a6d447ab-8363-47a7-bd6d-57ec7efbe617','送鄭州吳綬通直北歸','鄒浩','宋','宋诗','song-poetry','','[]','霜雪下群木，江山拱高城。',96,'全唐诗/poet.song.69000.json','["霜雪下群木，江山拱高城。", "曠然爽氣中，幅巾日将迎。", "精神在文史，朋舊皆公卿。", "乃於功最時，冰泮人間情。", "不待髭髪改，乾坤付柴荆。", "虚□本無繫，風御聊爾行。", "此邦鬰多賢，向來集聪明。", "德翁可君心，歸歟助長生。"]'),
('fdb87894-6963-4eaa-9d9f-bf5a4602092d','次韻答交代俞樗年教授見簡之什','鄒浩','宋','宋诗','song-poetry','','[]','吾鄉藹多士，夫子惟英才。',216,'全唐诗/poet.song.69000.json','["吾鄉藹多士，夫子惟英才。", "妙年雙眸清，不爲紛華開。", "飛聲動寰宇，著錄争徘徊。", "論說翕以定，端如匡鼎來。", "著鞭青雲衢，飄飄謝塵埃。", "伯鸞賦五噫，少陵歌七哀。", "豈比太平遇，得志無疑猜。", "朝綱舉天網，陞黜常恢恢。", "胡然落泮宮，猶歉南山臺。", "維今堯舜君，側席方虚懷。", "簡拔到寒谷，未始由梯媒。", "懸知器業成，指日登蓬萊。", "伊予愧樸樕，聿來托高齋。", "與君出處間，一一金石諧。", "峴首鬰蒼莾，江流澹縈廽。", "龍卧縮頭角，騰驤竢春雷。", "君車亦難緩，行矣明詔催。", "逸步從此分，駑駕安能陪。"]'),
('874133ac-5b9e-4fbf-b2c6-308d5babf5a1','知府呂大卿餞别樗年以今我來思雨雪載塗分韻賦詩得雨字','鄒浩','宋','宋诗','song-poetry','','[]','使君出吾鄉，門墻掃塵務。',156,'全唐诗/poet.song.69000.json','["使君出吾鄉，門墻掃塵務。", "諸生擁經來，翕然影響赴。", "維時夫子賢，獨入青眼顧。", "河南拔賈生，千載一高步。", "爾來十五年，終然阻鵷鷺。", "如星不麗天，而乃西南雨。", "晚逢使君車，亦復此邦駐。", "從容平生歡，萬事散朝霧。", "江山飛雪霜，冉冉歲云暮。", "我來踵規模，夫子故長路。", "使君有高情，肅以豆觴寓。", "賓僚集清夜，健筆落佳句。", "行矣勿稽遲，青雲答知遇。"]'),
('334b28ec-72bf-4e8c-93b8-2c55b0cc5475','奉和邢舍人寄望之愚溪朝陽巖  其一','鄒浩','宋','宋诗','song-poetry','','[]','冷風不動水無聲，倒影冲融漾太清。',32,'全唐诗/poet.song.69000.json','["冷風不動水無聲，倒影冲融漾太清。", "公爲少留誰會意，且憑詩句作長城。"]'),
('cca113a3-03bc-490d-ba33-c15bafb8b283','奉和邢舍人寄望之愚溪朝陽巖  其二','鄒浩','宋','宋诗','song-poetry','','[]','我聞紫微公，潤色邁東里。',192,'全唐诗/poet.song.69000.json','["我聞紫微公，潤色邁東里。", "道阻未識面，馳心極雲駛。", "及此襄漢遊，黄堂見名氏。", "乃知吏民上，屹若楚山峙。", "不以外自殊，夙興酬寄委。", "陶瓦焕窮閻，長堤矗江涘。", "陋彼繩墨拘，畏首復畏尾。", "坐令焚溺餘，衣食就安址。", "流澤配羊杜，如水注無底。", "念兹智略成，愚者豈同履。", "胡爲愚溪水，嘯咏送寒晷。", "虚涵萬象幽，清絕一塵滓。", "想公溪上心，所得似夫子。", "歲律方崢嶸，撫事聊爾耳。", "鼓枻得浮沉，觀魚謝竿餌。", "應憐柳司馬，愛身異桐梓。"]'),
('26a916cd-c33b-4607-bcd9-fc15265f41d2','仲益約遊延慶不至作此戲之','鄒浩','宋','宋诗','song-poetry','','[]','出門無他岐，一徑指山麓。',48,'全唐诗/poet.song.69000.json','["出門無他岐，一徑指山麓。", "餘寒弄晴陰，淅瀝散輕玉。", "我僕亦賞心，我馬亦飛肉。", "回首幕中英，文書正拘束。"]'),
('bea4aed7-99de-4ef2-b4b0-ae1086498efd','與節推李師益遊谷隱習池','鄒浩','宋','宋诗','song-poetry','','[]','無心一何求，無垢一何洗。',48,'全唐诗/poet.song.69000.json','["無心一何求，無垢一何洗。", "與子入山來，放脚東風裏。", "巖根初著花，溪冰半流水。", "一笑真偶然，松聲爲誰起。"]'),
('dd70514a-8318-4feb-abca-77c99af4fa74','謝仲益惠蘭','鄒浩','宋','宋诗','song-poetry','','[]','鄰家得蘭惜不得，數本分來好顔色。',128,'全唐诗/poet.song.69000.json','["鄰家得蘭惜不得，數本分來好顔色。", "兒童見之喜欲顛，驚回午夢松江側。", "起隨斤斸聊齋前，面勢欄干相並植。", "氤氲猶帯鳳山雲，彌天道安端我即。", "璧丘亭高秀谷幽，想見僧移動晴碧。", "根深叢迥無他虞，青眼東君方着力。", "影連桂月共扶疏，香入梅風更引翼。", "此心莫逆知誰何，金粟如來在東壁。"]'),
('baf3faad-d2d5-4cd9-8696-2f45d8b05f3f','次韻和端夫遊谷隱','鄒浩','宋','宋诗','song-poetry','','[]','我生泉石中，清賞殊不足。',180,'全唐诗/poet.song.69000.json','["我生泉石中，清賞殊不足。", "得官漢上來，邂逅亦溪谷。", "他時長安塵，用此塵外贖。", "城南百餘里，灑落自風俗。", "招提密相忘，一一儼西竺。", "緬維作者謀，永集荆楚福。", "興國最佳勝，千柱列巖屋。", "前疏白馬泉，後據雙鳳麓。", "衲衣擁雲外，拄杖倚藤竹。", "天龍咫尺耳，入戶體生粟。", "誰爲逢氏迷，不復棖也慾。", "落英無再紅，秀髪豈常綠。", "共将香火心，稽首千手目。", "老僧獨何爲，瞬我掣電速。", "已矣勿重言，良藥反成毒。"]'),
('1623111c-e81d-454d-9f97-60cce435cf0f','次韻端夫聞江北水磨','鄒浩','宋','宋诗','song-poetry','','[]','萬事根本初難明，聲之所發由聲聲。',192,'全唐诗/poet.song.69000.json','["萬事根本初難明，聲之所發由聲聲。", "不有智者抉其□，直如寶劍埋豐城。", "風生風濟孰嘘吸，制作解成琴與筝。", "矧兹江漢瀉荆楚，含桃初熟飛流鶯。", "波濤暗逐歲月長，激激灘際春雷谹。", "白沙湖邊更湍急，五磨因緣資養生。", "城中鞭驢喘欲死，亦或人勞僵自横。", "借令麥破麵浮玉，青蝇遽集争營營。", "迺知此策最長利，朱墨豈復嗤南榮。", "天輪地軸駭晝夜，彷彿颶扇吹蒼瀛。", "遊江夫人儼然坐，蛟龍不動如石鯨。", "只應神物亦持護，我輩何妨雙耳清。"]'),
('31047a9b-0ee8-44d5-bc2a-488eab079521','送望之移帥荆南','鄒浩','宋','宋诗','song-poetry','','[]','荆湖地與蠻獠通，江陵開府節制雄。',160,'全唐诗/poet.song.69000.json','["荆湖地與蠻獠通，江陵開府節制雄。", "勁兵十萬擁羆虎，鼓角聲動波濤風。", "列城如子滿棋面，一一元帥呼吸中。", "陛下鈎簾撫天宇，妙選百辟今屬公。", "楚峰峻拔江漢廣，晴光带影落渚宮。", "懸知黄馘日飽飯，酣歌鼓腹均兒童。", "裕陵松柏老霜露，鍾山杖屨埋蒿蓬。", "自從知已失君相，隼旟熊軾西復東。", "赭袍可想不可見，十年一夢朝來空。", "荆湖雖重豈留處，朝廷百度皆元豐。"]'),
('cc2ff524-202f-472c-8813-4fcbf9577fda','次韵魏道輔教授折梅懷荆帥望之','鄒浩','宋','宋诗','song-poetry','','[]','霜風未放江梅折，似向人間將價索。',96,'全唐诗/poet.song.69000.json','["霜風未放江梅折，似向人間將價索。", "冷然一解冰雪顔，花有天倫此其伯。", "見卵求雞亦非早，只今已覺和羹好。", "殷勤猶是故時香，驛路一枝情淼淼。", "我公所向物皆春，想見新花如漢濱。", "新花故人政如此，欲了此心惟斵輪。"]'),
('c94da80c-605b-42c7-aaed-a8b2337ab698','送察推賈時以通直郎致仕還荆南','鄒浩','宋','宋诗','song-poetry','','[]','秋聲起庭端，索索故時語。',156,'全唐诗/poet.song.69000.json','["秋聲起庭端，索索故時語。", "幾人清鏡中，鬢髪默自許。", "東鄰坐長嘆，曰此非吾所。", "平生困一官，湎若醉醪醑。", "幸今豁然醒，可以事高舉。", "田園熟瓜芋，茅茨庇風雨。", "向來避席人，把臂相爾汝。", "年光雖云暮，猶足送寒暑。", "斯言不浪酬，即日去幕府。", "我惟塵世浮，貴賤等逆旅。", "寛爲百年期，形骸一丘土。", "夫君脫身還，豈不知所處。", "行矣數珠功，青天走龍虎。"]'),
('113cee9a-1b10-4207-b35d-db5eb7ec04ae','戲督潛亨作春羹','鄒浩','宋','宋诗','song-poetry','','[]','先生家□餘玉粒，粉以爲餅陪春羹。',160,'全唐诗/poet.song.69000.json','["先生家□餘玉粒，粉以爲餅陪春羹。", "春羹品物謝時味，江流暖泛園中英。", "晴窗對案忽舉首，徑走長鬚呼友生。", "襄陽大夫腹如鼎，一著九牛猶未盈。", "懽然放筯即過我，自嘆珍庖逾大烹。", "且言初意亦在我，属我府事留西城。", "先生飯不飯俗客，若苦轉眄相倒傾。", "東風雕刻物物好，槎頭縮頸尾不赬。", "藥苗蔬甲破土出，似與芻豢争功名。", "應憐十載痩藜莧，爲我一除饑腸鳴。"]'),
('5f96e21c-30f9-4be4-983b-07d4146fbd73','潛亨既見和再作此贈之','鄒浩','宋','宋诗','song-poetry','','[]','不作苟見如君平，不以禮屈如樊英。',160,'全唐诗/poet.song.69000.json','["不作苟見如君平，不以禮屈如樊英。", "扊扅堅卧三十載，凛凛風聲人自傾。", "墻東墻西過高馬，往往愧汗面發赬。", "豈知嗜欲極豺虎，白晝擇肉無厭盈。", "有時一飯稔奇禍，他年五鼎還遭烹。", "狡兔未滅黄犬在，突兀上蔡空前城。", "先生謝去既飽德，鼓腹之趣終難名。", "更要我輩集匙筯，風雨不變如鷄鳴。", "自憐頭額乏奇表，幾與虀鹽同此生。", "不愁捩手遂傾覆，只愁未至聞戞羹。"]'),
('a9022189-a0fd-4e36-ab47-30c4e03c18d0','次韻仲益解嘲','鄒浩','宋','宋诗','song-poetry','','[]','真宰幹萬物，物物相乘除。',96,'全唐诗/poet.song.69000.json','["真宰幹萬物，物物相乘除。", "童角贖以牙，畢竟均有無。", "江山與絲竹，等爲薦虚徐。", "江山寂寞生，絲竹富貴餘。", "要知謝安石，青史端幾書。", "達人眼目開，洞照無親疏。", "安用欣厭間，浪取爾與余。", "獨喜豐蔀幽，坐獲驪龍珠。"]'),
('3a262b83-14b1-41c9-885c-265abe28b8ea','和歐陽彦立再用仲益前韻','鄒浩','宋','宋诗','song-poetry','','[]','山行迹未掃，倐忽歲已除。',96,'全唐诗/poet.song.69000.json','["山行迹未掃，倐忽歲已除。", "東風從東還，天機動群無。", "自憐藜莧中，遭時謝嚴徐。", "兩曜棲睫端，輝光照三餘。", "爾來知昨非，一笑捐詩書。", "虚堂自朝夕，與世成闊疏。", "胡爲公子賢，賓集亦到余。", "鳴泉春際飛，聊復觀跳珠。"]'),
('5c9b3a6f-ec9d-4adf-91c8-10290a664a42','次韻和知府歐陽叔弼學士禱雨武侯祠','鄒浩','宋','宋诗','song-poetry','','[]','盲風日日吹塵土，謾說有年歌自古。',320,'全唐诗/poet.song.69000.json','["盲風日日吹塵土，謾說有年歌自古。", "紛紛機械空作勞，况乃象龍求致雨。", "黄堂學士極憂心，忍復賓前事懸堵。", "倘助豐穣能出雲，境內山川無不舉。", "丞相威靈凛一方，遠矚祠宮途可取。", "旌旗拂曉動長庚，彷彿飛雲趨兩府。", "精神洞達金石開，此意豫應神已睹。", "况公愛民如愛子，不以斯民供鼎俎。", "居士庵中常默然，田里人人自安處。", "他時刀劍倚市門，往往買牛耕草莽。", "心絕多岐禮義生，和氣氤氲見眉宇。", "惟天至聪下其耳，飽聽歡謠薦佳語。", "故宜神力導休祥，不待牲醪集軒廡。", "胡爲風旱久未寧，行矣斗柄将建午。", "豈煩瑞祝更殷勤，禱處由來似尼父。", "三分天下指掌間，頋此提封才一羽。", "沛爲甘澤定不難，溝澮縱横互吞吐。", "坐令百穀暗郊原，會見腰鐮分勤苦。", "儒宮釡魚端欲生，自笑年來遽如許。", "雖無高廩並坻京，猶得朝昏鳴食鼓。"]'),
('47646d7a-576d-474f-9614-d9e3ad2c7643','嘲仲益','鄒浩','宋','宋诗','song-poetry','','[]','低簷廕茅竹，陋如野人居。',204,'全唐诗/poet.song.69000.json','["低簷廕茅竹，陋如野人居。", "夫子莞爾笑，曰此真吾廬。", "庭前鬰喬木，庭後猶榛蕪。", "芟削隨手净，春蘭植扶疏。", "光影動窗几，馨香襲文書。", "皎然紉佩心，邂逅同三閭。", "爾來基構新，百事凌往初。", "突兀焕華屋，茅竹掃莫餘。", "雙楠庭之珍，斬代殊榮枯。", "要知碧油幢，特立當階除。", "念念入勳業，不與蓬蓽俱。", "蘭雖不生門，安能逭誅鋤。", "剖琴如剖薪，烹鶴如烹魚。", "珠玉抵飛鳥，鎛鐘委洪爐。", "逝矣覆轍存，來車猶此涂。", "尚欲取脩竹，永以娱朝晡。", "問竹竹無言，冷風一虚徐。"]'),
('f10bff93-670d-4860-b6c2-4df3dfc233af','寛夫率同諸公謁大悲寺觀所畫聖像以回向心地初分韻賦詩得初字','鄒浩','宋','宋诗','song-poetry','','[]','襄州城東十里餘，天仙大悲江上居。',128,'全唐诗/poet.song.69000.json','["襄州城東十里餘，天仙大悲江上居。", "白龍盤伏不敢動，澄波如練風前紓。", "飽聞黔首喜相謂，微此妙相吾其魚。", "鼎來巾屨陪作禮，他年假道今題輿。", "毫端願力歘有感，手目縱横隨卷舒。", "高亭短棹青春裏，雲雨曉霽乾坤虚。", "誰将五色染萬物，物物可意難親疏。", "會須指顧發深省，此心長似楚香初。"]'),
('de0cc772-e4fc-4ca1-94a6-2ceca487b0fa','次韻和簽判靳慎微奉議謁武侯祠有作','鄒浩','宋','宋诗','song-poetry','','[]','卧龍得風霆，天宇不難肅。',48,'全唐诗/poet.song.69000.json','["卧龍得風霆，天宇不難肅。", "曆數端何歸，轉昐移禍福。", "廟食凛平生，光靈走川陸。", "欲知庇斯人，綿延視巫祝。"]'),
('e967d710-2698-4430-97dc-576018ec4594','戲示柄','鄒浩','宋','宋诗','song-poetry','','[]','汝爲獅子時，而作獅子吼。',24,'全唐诗/poet.song.69000.json','["汝爲獅子時，而作獅子吼。", "他年毛骨成，一顧百獸走。"]'),
('f4eae0f7-6d0d-4b77-b65e-a8f1180c8036','次韻答詹成老謝密雲龍之什','鄒浩','宋','宋诗','song-poetry','','[]','龍鳳小團分禁戶，往往稱珍減前語。',192,'全唐诗/poet.song.69000.json','["龍鳳小團分禁戶，往往稱珍減前語。", "元豐天子妙風雷，萬古埃塵洒新雨。", "壑源春貢識此心，不比豫州常枲紵。", "卿雲密密擁蜿蜒，御府僅能千百數。", "匪頒臺閣裁幾人，恩逐味增淪骨髓。", "帝鄉仙去鼎湖空，井閟閤門猶玉乳。", "龍髯雖在龍莫形，只有雲留瑞民伍。", "葉家所得最非常，好事殷勤始容取。", "故人分贈不遐遺，憐我哀摧病方瘉。", "莆陽英爽杳難攀，品目縱横誰扞禦。", "仰惟筆削到茶經，亟以将誠歸許與。", "詩來寒谷歘然春，坐覺輝光滿禾黍。"]'),
('3eec2df3-ddb3-4a71-8215-0bcbb85e8c90','次韻和成老謝何伯震','鄒浩','宋','宋诗','song-poetry','','[]','滄溟倒挽供缾罍，少年取醉真豪哉。',128,'全唐诗/poet.song.69000.json','["滄溟倒挽供缾罍，少年取醉真豪哉。", "天旋地轉膽如斗，何獨謫仙方逸才。", "爾來意氣折憂患，霜雪仍從雙鬢催。", "吾師吾友得渾沌，有口不復□□開。", "賓筵竟日但趺坐，竦聽搖犀談玉杯。", "中分魯國兩夫子，道德未逢賢者哀。", "黄鍾大呂相應和，儒風賴以扶傾頹。", "伊予幸甚獲親炙，獨愧不如匡鼎來。"]'),
('53deef63-38ca-45dc-9c42-44677568190d','送石師稷還新昌','鄒浩','宋','宋诗','song-poetry','','[]','官失常丁民破産，僅有流波入春眼。',160,'全唐诗/poet.song.69000.json','["官失常丁民破産，僅有流波入春眼。", "行人不管居人愁，但喜船頭解初綰。", "汀洲夢破白鷗前，歸意崢嶸淨如剗。", "挽君君竟逐風東，瞑立西樓思何限。", "念君心似嶺雲高，卷雨收雷依𡾰嵼。", "弟兄元愷正功名，獨自巢由謝青簡。", "君今杖屨煙雲中，我憶當年寄蕭散。", "情深人合脗天倫，相與宮商真律管。", "可憐燕越阻尋盟，夜壑不留空舊舘。", "只應石佛儼巍巍，爲我旃檀薦誠欵。"]'),
('6512a0db-e345-4b21-b929-f894e18a0764','遊湘西道林寺用沈傳師韻','鄒浩','宋','宋诗','song-poetry','','[]','賜還殊無功可論，放逐復向山前奔。',208,'全唐诗/poet.song.69000.json','["賜還殊無功可論，放逐復向山前奔。", "道人眸子炯如故，邀我累日遊祗園。", "御書新閤插霄漢，祝融嚴拱世所尊。", "恍然身世脫塵垢，矯若鴻鵠辭籠樊。", "是時秋老雨脚斷，晴光萬里凌朝昏。", "北辰直下望天闕，紛紛郁郁卿雲屯。", "綵衣蘭膳奉顔色，想見協氣還閨門。", "鴈飛不到竟何許，日冀□□除瘢痕。", "四年之中兩到此，易搖難立憐孤根。", "方寸倐忽叢百感，湘源白鶴空盈樽。", "道人顧我亦無語，但指幡從風際翻。", "由來否泰反其類，况逢主聖同羲軒。", "而今而後戒覆轍，長記崇寧初紀元。"]'),
('bb777aa8-1f3f-4504-b3cf-1b5ba184591f','謁女貞何氏祠','鄒浩','宋','宋诗','song-poetry','','[]','正月一日雨不休，朝來四望陰雲收。',288,'全唐诗/poet.song.69000.json','["正月一日雨不休，朝來四望陰雲收。", "衆陽扶導日輪出，輝光倐忽盈九州。", "欣欣草木動新意，鸞鳳鼓翅翔天遊。", "高山託處将半載，真人風韻長凝眸。", "精神澡雪亦已久，懽言夙駕南岡頭。", "仙居樓閣拱形象，祥煙瑞靄簷間浮。", "焚香再拜適我願，想見王母同優游。", "蟠桃不老春更永，人間變化知幾秋。", "輪囷重盖擁車馬，氣勢赫赫移山丘。", "萬方有口莫敢議，勳勞自以爲伊周。", "門墻旦暮祝遐筭，長守富貴無與儔。", "于今掃蕩一何有，白楊影裏令人愁。", "丈夫祈嚮乃如此，孰爲女子能清脩。", "功成直上紫霄去，遺蹤猶向瀟湘留。", "我來不及叩真訣，真訣固在冥心求。", "五行八卦自流轉，生天生地生物稠。", "騎龍跨虎越宇宙，豈但洗滌無愆尤。", "他年誰作□仙傳，□入高仙吾姓鄒。"]'),
('ca55d303-c8af-4a96-975a-de9b4be30e96','醉飲','鄒浩','宋','宋诗','song-poetry','','[]','我生不嗜酒，斷來仍十年。',144,'全唐诗/poet.song.69000.json','["我生不嗜酒，斷來仍十年。", "前年竄嶺表，去年斥湖邊。", "欲以禦瘴濕，乃復酒至前。", "一杯復一杯，朝暮常醺然。", "因之醉鄉遊，别是一山川。", "日月不相促，萬物同暄妍。", "眼界絕塵汙，耳根遺俗譞。", "心平氣自和，妙與天地全。", "歠糟而餔醨，信以昔人賢。", "琴外陶靖節，詩中李謫仙。", "聲利挽不回，昏昏長醉眠。", "有師誰得之，我奉以周旋。"]'),
('fab550bd-6440-4464-a596-830aa81c8b30','謝衡州花光寺仲仁長老寄作鏡湖曹娥墨景枕屏','鄒浩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','道人秀骨生何許，若耶溪邊清氣聚。',320,'全唐诗/poet.song.69000.json','["道人秀骨生何許，若耶溪邊清氣聚。", "不從章甫事功名，遊歷諸方參佛祖。", "祝融峰下忽擡頭，覷破虚空笑而舞。", "折脚木牀二十年，門外草深無寸土。", "偶然消息落人間，挽出花光照今古。", "我舟邂逅泊山前，霧捲雲開見眉宇。", "更知我自浙東來，曾擁旌旗塵督府。", "千巗萬壑繞罇罍，夢斷卧龍誰是主。", "爲将池墨灑鮫綃，故國封疆歸擇取。", "曹娥江接賀家湖，環以峰巒暝烟雨。", "森森喬木動樵風，廟貌崢嶸閟神禹。", "碑留遺刻蔡邕題，注目端爲楊主簿。", "子猷興盡季真亡，彷彿棹聲迴遠浦。", "乾端坤倪渺莫窮，咫尺并包入庭戶。", "坐令鄉思滿瀟湘，恨不歸飛插雙羽。", "蒼梧洞庭南北中，氣象縱横随步武。", "祗緣流放阻君親，入眼雖奇若無睹。", "道人方便巧施爲，乃以家山慰心腑。", "舊愆猶冀獲湔除，恩錫餘年返農圃。", "青鞋布襪謝塵埃，肯使高蹤慚杜甫。"]'),
('a0101bb1-07dd-4ef5-8a7c-b5ac32af8469','除名','鄒浩','宋','宋诗','song-poetry','','[]','前年除名竄新州，今年除名竄昭州。',128,'全唐诗/poet.song.69000.json','["前年除名竄新州，今年除名竄昭州。", "我名無實浪自得，坐此人間多怨讐。", "恩深天地貸斧鉞，除之又除名不留。", "雖然未即聽逐便，已覺此身民是儔。", "裂冠毁冕散車馬，幅巾杖屨西南陬。", "行者爭道舍爭席，所向爾汝紛應酬。", "洞山有語久弗契，忽然一笑知來由。", "我追我隨非我患，那用避如韓伯休。"]'),
('e788b55e-039f-4ca8-b3a4-7d823dd58e8c','别零陵','鄒浩','宋','宋诗','song-poetry','','[]','零陵詎中邦，道阻五千里。',120,'全唐诗/poet.song.69000.json','["零陵詎中邦，道阻五千里。", "我以放逐來，本非心樂只。", "身止高山巔，忽忽彌半禩。", "人情久自親，况復多可喜。", "坐使故鄉念，如火沃之水。", "罪大不得留，今兹動行李。", "昭州雖嶺南，流寓盖均耳。", "倘未還庭闈，在彼猶在此。", "胡然當作離，耿耿殊不已。", "物我要兼忘，咄哉從此始。"]'),
('c212084a-e597-41ad-ae45-aa5eaca0a882','将往昭州示柄','鄒浩','宋','宋诗','song-poetry','','[]','與汝暫相别，南作昭州行。',180,'全唐诗/poet.song.69000.json','["與汝暫相别，南作昭州行。", "昭州距零陵，坦坦十日程。", "音信昜來往，勿動異鄉情。", "但自勤讀書，思索厥義精。", "聖賢如日月，爲汝出光明。", "脩身識根本，力踐以其誠。", "發爲文字間，筆墨自縱横。", "零陵豪傑士，張鄧尤高名。", "汝其師事之，北面聽指令。", "分陰古所惜，况乃汝後生。", "省定汝母外，謹勿他事縈。", "皇恩極天地，我罪終從輕。", "還家知有時，欣見汝向成。", "用爲祖母壽，慰叔及弟兄。", "携汝返鄉國，重增門戶榮。"]'),
('99d60901-1abc-44cf-8662-b8505906b032','飲桂州酒示柄','鄒浩','宋','宋诗','song-poetry','','[]','好酒如好人，雖久略不變。',48,'全唐诗/poet.song.69000.json','["好酒如好人，雖久略不變。", "炎凉互推移，氣味愈可見。", "豈若茅柴漿，多爲衆所賤。", "舉杯吾得師，足以警閒燕。"]'),
('6c5f9a7b-830d-4f26-9444-e423aac38cc9','題義明定慧庵','鄒浩','宋','宋诗','song-poetry','','[]','結草依山名定慧，於此冥心第一義。',32,'全唐诗/poet.song.69000.json','["結草依山名定慧，於此冥心第一義。", "罏香深炷席簾垂，老僧不見庵外事。"]'),
('7a3dc946-df3c-479d-9c6d-be34214f4b28','答曾敷文有書見寄','鄒浩','宋','宋诗','song-poetry','','[]','客寓天地間，本無南北異。',24,'全唐诗/poet.song.69000.json','["客寓天地間，本無南北異。", "此語安從生，却成相鈍置。"]'),
('5a2bc16a-c075-41bf-ac9a-183031066598','戲作','鄒浩','宋','宋诗','song-poetry','','[]','作自我作，止自我止。',20,'全唐诗/poet.song.69000.json','["作自我作，止自我止。", "莫被傍人，推倒扶起。"]'),
('67b7e6a6-059c-477f-98d7-19d20f16ca51','詠路','鄒浩','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u6292\u6000", "\u548f\u7269", "\u611f\u6168"]','赤路如龍蛇，不知幾千丈。',36,'全唐诗/poet.song.69000.json','["赤路如龍蛇，不知幾千丈。", "出沒山水間，一下復一上。", "伊予獨何爲，與之同俯仰。"]'),
('e18244e4-66ae-402a-808e-a8b8572e9b1a','一切諸佛子','鄒浩','宋','宋诗','song-poetry','','[]','我心如虚空，無物可倫比。',84,'全唐诗/poet.song.69000.json','["我心如虚空，無物可倫比。", "湖南與嶺南，誰行復誰止。", "寶山得樓居，屹枕樂川水。", "森森青琅玕，卻暑幾千里。", "團蒲叠雙趺，爐烟凝然起。", "圎覺首楞嚴，遮眼聊爾耳。", "幽禽忽來鳴，一切諸佛子。"]'),
('1af7ad1a-a261-42d4-97b3-b7cbc3cb73cd','榴花','鄒浩','宋','宋诗','song-poetry','','[]','閣東閣西安石榴，兩株相映花枝稠。',96,'全唐诗/poet.song.69000.json','["閣東閣西安石榴，兩株相映花枝稠。", "山高江闊萬木葉，獨此爛熳開不休。", "有如牙門集纓紱，碧油幢外紅光浮。", "又如青天駐羲御，火龍鱗鬛驚人眸。", "朝朝莫莫看愈好，直若有意寛離憂。", "無窮歸念姑且置，欄邊取醉商聲謳。"]'),
('10d53f51-4c1d-40b3-946c-1463904c2296','仙宮嶺','鄒浩','宋','宋诗','song-poetry','','[]','曉雲生嶺端，遮日成清陰。',288,'全唐诗/poet.song.69000.json','["曉雲生嶺端，遮日成清陰。", "炎氛遽辟易，興逸安能禁。", "仙宮風塵表，高高百千尋。", "石路上曲折，健足猶難任。", "綽約兩仙子，雙鬟坐沉吟。", "巫覡意何許，門窗藤蔓深。", "樵叟向我言，自古傳至今。", "去州五十里，有峒鬰森森。", "陶家李家女，年各勝巾衿。", "恍惚若逢遇，相與登崎崯。", "一朝作蟬脱，英魂不墜沉。", "鄉人共祠之，彷彿來顧歆。", "水旱禱輙應，民吏同所欽。", "此宮乃行宮，春秋薦誠諶。", "言已叟仙去，四望祛煩襟。", "滎山直南聳，龍嶽山朝壬。", "越王連佛子，密山秀孤岑。", "回環萬峰巒，插雲皆玉簪。", "滔滔兩川流，會合通梧潯。", "漁舟糝木葉，城郭幾突黔。", "虚徐韻長松，飛鳴集珍禽。", "須臾烟靄青，遐邇浮祲祲。", "變化紛見門，飲酒時一斟。", "我罪貸五鼎，我軀重千金。"]'),
('1129995a-2d30-4578-9186-fb05bca1451b','送子發還零陵','鄒浩','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我自罪大當投荒，君胡爲乎亦遑遑。',224,'全唐诗/poet.song.69000.json','["我自罪大當投荒，君胡爲乎亦遑遑。", "馬蹄舟楫困川陸，省定違離萱草堂。", "由來孤操絕流俗，屹與巨鎮遙相望。", "洞庭以南渺無際，氣象突兀收湖湘。", "平時事事不入眼，惟恐有愧如毫芒。", "色難直到古人處，以其緒餘均四旁。", "餘波邂逅亦及我，使我方寸失感傷。", "我親白髪照閭里，我身跼蹐瘴癘鄉。", "兩兒隨母仍舊寄，骨肉星散知幾方。", "乾坤子初無薄厚，恩爲雨露威雪霜。", "二柄交持不偏用，萬彙生成如審量。", "我雖棄擲五嶺外，亦必有日蒙恩光。", "故人亭邊是歸路，尚得握手輸中腸。", "将分無可爲君語，獨有高義無時忘。"]'),
('1ee712bd-3b2c-47f2-82f6-060796449269','有感','鄒浩','宋','宋诗','song-poetry','','[]','雲回雨歇天欲晴，鵓鳩唤婦皆和聲。',64,'全唐诗/poet.song.69000.json','["雲回雨歇天欲晴，鵓鳩唤婦皆和聲。", "山南山北樹陰裏，懽然相趁争飛鳴。", "伊予流竄止平樂，妻孥尚寄瀟湘城。", "五嶺横空唤不聞，不如鵓鳩猶有情。"]'),
('2c678595-71ee-40f9-93ae-bef7b92463fb','聞彦和過桂州  其一','鄒浩','宋','宋诗','song-poetry','','[]','人臣難有己，况復顧其家。',120,'全唐诗/poet.song.69000.json','["人臣難有己，况復顧其家。", "忘家以狥國，致主爲勛華。", "割愛非不仁，成功詎能加。", "御史殿中傑，指摘生疵瑕。", "昔如鵠矯雲，今如兔罹罝。", "省符到房陵，驅逐殊喧譁。", "即日出門去，形影自天涯。", "羈皇携衆雛，驚散随風沙。", "渺漭失處所，何由書報嘉。", "君心固已定，聞者空傷嗟。"]'),
('864c4963-0614-44f6-b813-d84d299c00a3','聞彦和過桂州  其二','鄒浩','宋','宋诗','song-poetry','','[]','削迹投炎荒，有吏督其後。',120,'全唐诗/poet.song.69000.json','["削迹投炎荒，有吏督其後。", "一州一易之，稍緩輙訾詬。", "所歷多官僚，豈無親且舊。", "前車覆未遙，不敢略回脰。", "誰謂桂嶺僧，於君獨勤厚。", "沐浴君髪膚，澣濯君領袖。", "使君霜柏姿，凛凛出塵霧。", "真風絕顧瞻，高義激頽仆。", "乃知世外情，非復世間構。", "嗚呼君何憂，時命不終繆。"]'),
('26ccfd39-e767-40ea-afa6-00f1adfa6959','自警','鄒浩','宋','宋诗','song-poetry','','[]','看書勿苦多，多看目力眊。',168,'全唐诗/poet.song.69000.json','["看書勿苦多，多看目力眊。", "作文勿苦多，多作心力糟。", "初雖莫覺悟，久乃成悔懊。", "維心神所居，惟目神所造。", "開闔出入間，神傷氣亦暴。", "所以古真人，丁寧有深告。", "平時當勤行，况復處炎燠。", "况復病初愈，力始勝巾帽。", "老母在鄉邦，倚門望佳報。", "尤宜决擇精，全神以自好。", "收目以內視，冥心以存奥。", "氣舒形康強，外務一除掃。", "生理保安完，天恩垂覆幬。", "歸看老萊衣，歡欣長舞蹈。"]'),
('908b1a05-89e6-4915-aa38-7d2391b74d86','感歎','鄒浩','宋','宋诗','song-poetry','','[]','一犬捕執将祭神，羣犬隨之號極聲。',96,'全唐诗/poet.song.69000.json','["一犬捕執将祭神，羣犬隨之號極聲。", "惡傷其類乃如此，雖至苟賤亦有情。", "人於天地最爲貴，詩書禮樂開聪明。", "推恩尚欲極萬物，而况等列皆簪纓。", "奈何心忍所不忍，相殘相賊争功名。", "因知微畜反可尚，使我感歎無由平。"]'),
('1002d868-f62d-4cc0-a2a6-7a42466d5d6e','送李師聃祖道長官赴衡州耒陽令','鄒浩','宋','宋诗','song-poetry','','[]','視國如視家，愛民如爱子。',192,'全唐诗/poet.song.69000.json','["視國如視家，愛民如爱子。", "秉心金石堅，古人概如此。", "今人亦古人，但患物轉徙。", "遑遑聲利間，自不明本已。", "安能使元元，一以父母比。", "問其所居位，廣分國百里。", "問其所食祿，盡出民骨髓。", "奈何莫之思，顛倒以爲是。", "祖道於今古，問學妙窮理。", "內重外物輕，識者久歎美。", "宰制得耒陽，何啻牛刀委。", "導達聖主恩，千仞决谿水。", "雨暘隨指呼，絲穀飫鄰鄙。", "明神實聽之，日夜介福祉。", "君雖不求通，軒冕自難已。", "工部有英靈，吾知爲君喜。"]'),
('51a42c58-2c79-4fb6-85e2-e8e26a05e5b7','示徐道人','鄒浩','宋','宋诗','song-poetry','','[]','道人千里來，觸熱廢寝膳。',120,'全唐诗/poet.song.69000.json','["道人千里來，觸熱廢寝膳。", "問其何所爲，但云求識面。", "南方諸公門，二年走略徧。", "亦有苦苦留，諸事頗安便。", "念未見侍郎，跋涉遂忘倦。", "皇帝與天同，深恩滿州縣。", "瘴鄉寧久留，行復侍金殿。", "賣藥至京師，禮數隔貴賤。", "姓名且難通，况敢冀垂盼。", "汝言豈吾知，答之一笑倩。"]'),
('482d1640-2f46-42ba-8a8f-899e0f56a1e0','諭徐道人少唱喏','鄒浩','宋','宋诗','song-poetry','','[]','孔明拜牀下，德公初不止。',48,'全唐诗/poet.song.69000.json','["孔明拜牀下，德公初不止。", "道人必見喏，我令勿復爾。", "道人非孔明，喏拜不相似。", "維我德公心，寥寥無彼此。"]'),
('027362de-9830-4d10-bc23-b936ddee3904','詠菊','鄒浩','宋','宋诗','song-poetry','','[]','菊，菊。',70,'全唐诗/poet.song.69000.json','["菊，菊。", "叢叢，簇簇。", "種階除，脱巖谷。", "玉幹碧鮮，金英黄郁。", "争妍無小桃，結好有修竹。", "滿泛醇酒千杯，高簪道巾一幅。", "庭前子美休作詩，籬外淵明自留目。"]'),
('914552dc-2487-4eae-9606-ab243bd450ad','詠竹','鄒浩','宋','宋诗','song-poetry','','[]','竹，竹。',70,'全唐诗/poet.song.69000.json','["竹，竹。", "瀕江，遶屋。", "聲泠泠，影矗矗。", "霜雪難侵，塵埃莫瀆。", "梢雲齊老松，带日映寒菊。", "籜置頂上高冠，葉成樽中美祿。", "行看威鳳飽相從，不但子猷情最熟。"]'),
('41e48b6c-339f-4797-9d85-c2392bdf5b91','有所嘆','鄒浩','宋','宋诗','song-poetry','','[]','親者如路人，故者如世讐。',120,'全唐诗/poet.song.69000.json','["親者如路人，故者如世讐。", "路人與世讐，反與親故侔。", "無日不同處，無事不同謀。", "自謂腹心托，長久逾千秋。", "不知禍有孕，有識所深憂。", "一旦乘間作，四顧誰依投。", "往往捨之去，掉臂不回頭。", "却思故與親，大寒索衣裘。", "聪明天資高，反已亦易求。", "及此早覺悟，厥疾猶可瘳。"]'),
('2a439284-62eb-4e2d-94bc-cf57aa91bd9f','莫釣磯','鄒浩','宋','宋诗','song-poetry','','[]','飯罷何所之，曳履江之湄。',96,'全唐诗/poet.song.69000.json','["飯罷何所之，曳履江之湄。", "粼潾白石間，得石殊瓌奇。", "瑩然如紫玉，屹立平不欹。", "振衣坐其上，聊以垂綸絲。", "吾鈎既不曲，吾餌亦不施。", "持釣非有釣，與魚均莫爲。", "魚樂吾已得，吾意魚豈知。", "投竿歸去來，晨昏以爲期。"]'),
('01469f77-0a43-4a8f-b912-3cbd6fcba5ef','下鷗臺','鄒浩','宋','宋诗','song-poetry','','[]','此心久已灰，入鳥無驚猜。',96,'全唐诗/poet.song.69000.json','["此心久已灰，入鳥無驚猜。", "輕鷗翔集處，邀我相徘徊。", "方圓十丈許，疑是天所開。", "鏘金兩灘瀬，簪玉千崔嵬。", "耳目肝肺中，何由着纖埃。", "鷗雖不解飲，屢舞勸我杯。", "清狂與酒狂，似此知幾回。", "我歸有日矣，鷗飛安在哉。"]'),
('08a1d95c-161c-49cc-b26d-ae512b12222d','讀頤卦','鄒浩','宋','宋诗','song-poetry','','[]','靈龜不語亦不食，深之又深乃其息。',64,'全唐诗/poet.song.69000.json','["靈龜不語亦不食，深之又深乃其息。", "清泠淵中能事畢，天長地久無終極。", "朵頤自朵非自得，何暇外觀惟汝即。", "吾言易行休更惑，抱一故爲天下式。"]'),
('31ada9ab-e825-4cc3-9ae8-9e76693d06b6','九日對菊','鄒浩','宋','宋诗','song-poetry','','[]','不雨江亦乾，草木翳塵土。',96,'全唐诗/poet.song.69000.json','["不雨江亦乾，草木翳塵土。", "重陽到眼前，菊蘃猶未吐。", "鄰家一株來，高才尺四五。", "種之小庭中，亦自足風矩。", "摘葉以當花，茱萸可爲伍。", "泛我流霞杯，喜色動眉宇。", "頹然逍遙遊，妙處有誰睹。", "淵明何人斯，東籬傲今古。"]'),
('c7a0ac31-dc5a-4e2c-b006-60d7c2823523','道鄉歌','鄒浩','宋','宋诗','song-poetry','','[]','要識道鄉去處，只在微塵裏許。',168,'全唐诗/poet.song.69000.json','["要識道鄉去處，只在微塵裏許。", "不立四至封疆，不問二儀寒暑。", "日月常放光明，鳥獸率同歌舞。", "其俗無舉無非，其民無喜無怒。", "别是一種乾坤，全異九州風土。", "師曠傾耳莫聞，離婁拭目莫睹。", "誰知有箇冥蒙，踏着從來門戶。", "入也不動脚跟，居也不記年所。", "行住坐卧虚徐，色聲香味愚魯。", "偶然成矩成規，未嘗爲鼠爲虎。", "任他卜度縱横，迥脫機關取與。", "人間天上無明，可謂自今自古。"]'),
('77cbf3d5-5260-4efe-a1b0-30a112db907b','夢臣惠潘谷墨  其一','鄒浩','宋','宋诗','song-poetry','','[]','老潘飛躡烟霞去，墨寶流傳能幾許。',342,'全唐诗/poet.song.69000.json','["老潘飛躡烟霞去，墨寶流傳能幾許。", "尚方猶以比庭珪，况復人間故人處。", "夫君好事追前賢，巾襲深藏二十年。", "雨暘燥濕莫知數，畢竟挺然金石堅。", "一朝酒發南箕舌，信在言前可中輟。", "有如印弄掌握間，稜角雖刓終一决。", "著書天禄垂無期，雲将掉頭吾弗知。", "但欣厚意厚若此，來仙閣上信雙眉。", "我有歙州韞玉石，琢成高秋遠天碧。", "平時長自水流珠，未省呼童助涓滴。", "我有常州飽霜毫，千錢一管價不高。", "真行隸草字百萬，勁鋒凛凛方遒豪。", "絳人陳元乃其伍，相得懽甚誰能禦。", "心灰緣此亦復然，和我精神動寰宇。", "便滌硯，便操筆，便啓軒窗磨此墨。", "敲冰佳紙適及門，羅列千張耀晴日。", "也吟詩，也作文，也把黄庭模右軍。", "并包萬類入方寸，倐忽變化生乾坤。", "君不見老子絕學故能學，君不見孔子捐書故能書。", "因君起我書且學，我書且學孔老俱。", "孔老俱，竟何如，寫我長句酬勤渠。"]'),
('6d5bddc8-7a9e-4eb9-89ab-b5d57efecdad','夢臣惠潘谷墨  其二','鄒浩','宋','宋诗','song-poetry','','[]','潘谷賣墨時，呂翁嘗過之。',168,'全唐诗/poet.song.69000.json','["潘谷賣墨時，呂翁嘗過之。", "指授長生訣，舉世那能窺。", "但稱衆墨中，谷墨最珍奇。", "一旦內藥成，解去逃喧卑。", "忽忽期月後，來與丹元期。", "夜飲曉分手，丹元初不知。", "仍留墨數片，屬元付其兒。", "有兒旋其門，頂白元驚疑。", "細詰所以然，始知谷如斯。", "谷仙今幾年，谷墨今在兹。", "静言人間世，舟壑常密移。", "朱顔兀槁木，綠髪垂素絲。", "借令富貴極，畢竟将奚爲。", "谷乎真可人，得墨吾得師。"]'),
('b06d5904-7f49-45b7-b2b9-1980338e2ebf','夢臣再以墨來','鄒浩','宋','宋诗','song-poetry','','[]','孫郎文史外，所好墨而已。',240,'全唐诗/poet.song.69000.json','["孫郎文史外，所好墨而已。", "龜玉藏櫝中，涓辰乃開視。", "未嘗輕示人，毎戒卞和耻。", "謂予心事同，分惠真可喜。", "磨去五之一，餘者恰盈咫。", "印弄稜角刓，前言戲之耳。", "蒼頭忽踵門，喘汗殊不止。", "恍疑皂囊藥，無因至於此。", "亟取啓緘封，入眼勝雙鯉。", "其長應天數，其光動晴晷。", "當暑尚挾纊，豈但什襲比。", "且云此不刓，品色尤更美。", "始知雅意來，要以補前毁。", "想初聞語時，廢書頻拊髀。", "兵法善致人，所致必如指。", "一朝下兩城，曾不費一矢。", "坐令鼎足心，成轍亂旗靡。", "堂堂莫我過，勢若建瓴水。", "墨果多乎哉，一一是孤壘。", "齊城七十二，受降從此始。"]'),
('0a25c409-64fc-4220-9fc4-f43299ab4ca0','别昭平','鄒浩','宋','宋诗','song-poetry','','[]','江山本無情，别去亦何語。',48,'全唐诗/poet.song.69000.json','["江山本無情，别去亦何語。", "向來爽氣中，食息三月許。", "來非吾所求，去非吾所禦。", "回首謝江山，吾今若輕舉。"]'),
('cd7939f6-eb56-4c10-b5ad-a6c4176dd214','留别張雲立立之','鄒浩','宋','宋诗','song-poetry','','[]','來遷夢破知何處，今君歸去仙宮路。',160,'全唐诗/poet.song.69000.json','["來遷夢破知何處，今君歸去仙宮路。", "江頭舟楫嶺頭雲，曾許乘風邀月住。", "翛然三載與君同，信我此心惟白鷺。", "白鷺忘情亦有情，君更情多無量數。", "天繪亭前不忍分，遠送我來欣進步。", "霜凋萬木見孤松，顔色青青獨如故。", "湘南湘北舊光陰，從此回頭但烟霧。", "得志軒前藕未花，梅率小桃先已露。", "與君同醉復同醒，千頃池塘渺新霔。", "好随魚躍趁風雷，飛上青天休反顧。"]'),
('6b72d2f0-6509-4c3f-bd17-01999fd72562','桂州紫極觀主求亭名名曰轉斗而示此句','鄒浩','宋','宋诗','song-poetry','','[]','轉降適斗藏初九，上清密語誰知有。',32,'全唐诗/poet.song.69000.json','["轉降適斗藏初九，上清密語誰知有。", "七星峰頂紫霞前，占得輝光長不朽。"]'),
('12c2b1a7-0f0a-4f90-bd48-fd7923bbb6b6','信中以詩來因次其韻送之','鄒浩','宋','宋诗','song-poetry','','[]','道言誰復書諸紳，瀟湘江上逢斯人。',128,'全唐诗/poet.song.69000.json','["道言誰復書諸紳，瀟湘江上逢斯人。", "向來濱死入魑魅，胸腹洞然無甲鱗。", "炎氛吹風作旗靡，玉樓倒影明蒿里。", "孤心還逐冷雲飛，歷歷長亭不知幾。", "聖王開了睹天庭，妙脱筌蹄合喙鳴。", "箇中無可無不可，智者亦迷何處名。", "渾沌兼忘儵與忽，有口鼻如欣莫咄。", "北山之北草堂深，怨鶴驚猿它自物。"]'),
('9b921362-c7d8-47da-9723-6451afb5b9e9','送李方幾仲司戶','鄒浩','宋','宋诗','song-poetry','','[]','我遷漢陽居，君爲建陽掾。',120,'全唐诗/poet.song.69000.json','["我遷漢陽居，君爲建陽掾。", "江山幾千里，何當重會面。", "身世波上萍，歲月弦上箭。", "自古以嘆嗟，不古乃獨見。", "爲仁豈由人，弘道道該徧。", "萬生無終窮，同我一方便。", "壑源春焙香，黄鸝静中囀。", "簡書有光陰，歸坐亦可燕。", "此事入高明，了了爲君見。", "舟車暫西東，勿受離情轉。"]'),
('b25ad528-e363-48d3-847f-93c35d68ac8e','題蒋彦回緋桃軒','鄒浩','宋','宋诗','song-poetry','','[]','何仙饑食王母桃，王母唤去瑤臺高。',192,'全唐诗/poet.song.69000.json','["何仙饑食王母桃，王母唤去瑤臺高。", "懷中核乃長生種，付與東君誰適遭。", "蒋侯本是神仙族，楊州騎鶴飛遊遨。", "回也不愚愚故道，不肯釣海連六鼇。", "變鄧家田作藍田，産玉成芝天所褒。", "柳将眼覷竟何睹，花着心覓空自勞。", "東風莫逆花柳外，洞然啓盡扃鐍牢。", "鋪張雲霞駐遲日，暖紅牽夢春陶陶。", "恍疑何仙只春是，衣繡還鄉導旗旄。", "蒲萄浪兀弄明月，寧比倒着宮錦袍。", "從今結就千年實，食之工力逾圭刀。", "聞說揚州鶴知得，鼓翼已先鳴九臯。"]'),
('5536aade-a5aa-4cfb-baa0-113b087aa896','題成立道飛香閣','鄒浩','宋','宋诗','song-poetry','','[]','碧池千畝紅蓮花，勅書樓下醇儒家。',128,'全唐诗/poet.song.69000.json','["碧池千畝紅蓮花，勅書樓下醇儒家。", "躋民仁壽逢主聖，欣與萬邦無歎嗟。", "六經變化天地闊，何處不可爲生涯。", "只今耆域在庭戶，信手掇取皆靈芽。", "氣運回環助調爕，各正性命逾塵沙。", "是渠病愈我亦愈，紅蓮影裏薫風斜。", "陰功乘香飛北極，上帝首肯羣仙誇。", "贈之丹桂一千尺，攀條直上凌蒼霞。"]'),
('0fc86de2-db70-4727-81a6-29daf810d82b','少隱惠所盡瀟湘雪景  其一','鄒浩','宋','宋诗','song-poetry','','[]','永州城北十五里，二水初同爲一水。',32,'全唐诗/poet.song.69000.json','["永州城北十五里，二水初同爲一水。", "天花開玉滿前飛，人在故人亭子裏。"]'),
('e09a4c19-9794-4fe5-a8ac-eb5ff315dd38','少隱惠所盡瀟湘雪景  其二','鄒浩','宋','宋诗','song-poetry','','[]','前年深冬一丈雪，巖擁朝陽渡黄葉。',32,'全唐诗/poet.song.69000.json','["前年深冬一丈雪，巖擁朝陽渡黄葉。", "鸕鷀插頸夢圓時，天作高山付雙睫。"]'),
('ede90b18-8bd5-4fb0-90f6-cf2f6152d1c7','少隱惠所盡瀟湘雪景  其三','鄒浩','宋','宋诗','song-poetry','','[]','将謂雪消無覓處，元來只在毫端住。',32,'全唐诗/poet.song.69000.json','["将謂雪消無覓處，元來只在毫端住。", "爲余展出凍雲天，一片瀟湘宛如故。"]'),
('b840cc27-5e58-4e2f-8e1a-50ca81f6252c','戲浯溪長老伯新','鄒浩','宋','宋诗','song-poetry','','[]','永州懷素精草書，毫端萬象紛卷舒。',260,'全唐诗/poet.song.69000.json','["永州懷素精草書，毫端萬象紛卷舒。", "渾身是眼看不破，一筆至今藏物初。", "浯溪得之不自用，却要他人書作圖。", "驀然打箇筋斗去，覓紙覓絹一物無。", "急将床上被來拆，手忙脚亂縱横鋪。", "五雲和尚巧言語，掃盡六幅裁須臾。", "叠了又開開又叠，喜歡勝獲衣內珠。", "二三子笑幾絕倒，左右僮僕咸驚呼。", "寧比酸寒杜陵老，海圖拆應家人須。", "脫巾漉酒解龜當，表裏空曠真丈夫。", "吾行天下何啻半，常恨眼前無此徒。", "那知興發乃方外，與彼嗜好同根株。", "小中現大大可睹，跳出規矩渠非愚。", "他時風雪夜參半，灰爐冰冷燈影孤。", "坐披破絮似魚網，數挽不揜皴肌膚。", "只應侍者隔壁私自語，我師爲誰說法聲嗚嗚。"]'),
('e7ec9d1c-3c40-4d52-bee7-5f8d76df505a','觀華光長老仲仁墨梅','鄒浩','宋','宋诗','song-poetry','','[]','我從梅花海裏來，驚此兩枝堂上開。',96,'全唐诗/poet.song.69000.json','["我從梅花海裏來，驚此兩枝堂上開。", "不由天降非地出，道人作麽生栽培。", "無縫塔子通一線，放光照醒陳根荄。", "玊蟾銀漢雨初霽，半啓瓊室通瑤臺。", "香雲漠漠護顔色，世眼欲睹誠難哉。", "不如取酒共春醉，一盃一盃復一盃。"]'),
('b73b9fde-95a5-41b7-8d45-be019bab4be6','次韻和范信中同遊花藥有作','鄒浩','宋','宋诗','song-poetry','','[]','花藥山去來，難遇此天日。',72,'全唐诗/poet.song.69000.json','["花藥山去來，難遇此天日。", "深衣書眼青，摩衲禪眼碧。", "鴈峰相與高，可以同我適。", "浮雲當面開，千里見叢蓽。", "况紫盖祝融，插天日未夕。", "正爾無能名，僧來乞題石。"]'),
('2b70c7bc-8202-4f2c-8a00-2cf027d4b0d4','湘陰鄧氏翠微洞','鄒浩','宋','宋诗','song-poetry','','[]','卧雲雲無心，聽松松有韻。',24,'全唐诗/poet.song.69000.json','["卧雲雲無心，聽松松有韻。", "快哉耳目中，吾今亦同分。"]'),
('7e30b787-5574-4445-93f8-04178b4fffe1','送成老赴西安','鄒浩','宋','宋诗','song-poetry','','[]','先生出逢堯舜時，自當勳業追臯夔。',160,'全唐诗/poet.song.69000.json','["先生出逢堯舜時，自當勳業追臯夔。", "胸中廊廟乃州縣，雪霜次骨西安馳。", "旁觀往往屢興歎，色初不變心希夷。", "但云将聖世所大，乘田委吏皆嘗爲。", "道通爲一無不可，等君事耳何高卑。", "高齋高居萬物表，清獻清風天下師。", "此心妙與此公契，莫或遑處今其誰。", "民歌仁恩到天耳，天須默薦君王知。", "坐令四海歸一握，陰陽變化隨設施。", "行即騐矣姑且置，聊引花前金屈巵。"]'),
('d14499db-8ac6-4cae-bd23-9d18d1f0d9e8','偶書','鄒浩','宋','宋诗','song-poetry','','[]','朝讀一卷經，暮讀一卷書。',48,'全唐诗/poet.song.69000.json','["朝讀一卷經，暮讀一卷書。", "一卷復一卷，三藏與五車。", "儒釋本不異，昧者自親疏。", "昧者不足道，明者當何如。"]'),
('4d616dca-6f2c-4203-90e0-31cee3fa484e','送陳公晦','鄒浩','宋','宋诗','song-poetry','','[]','寂不聞鳳鳴，雙耳聾已久。',48,'全唐诗/poet.song.69000.json','["寂不聞鳳鳴，雙耳聾已久。", "聿來丹山子，一旦驚戶牖。", "舊聽歘我還，喜氣薄牛斗。", "簫韶方九成，飛勿衆禽後。"]'),
('c489b17a-01aa-44d7-9a69-7547b429f2d5','吳公蔚将還滁陽出所集述德堂詩作此送之','鄒浩','宋','宋诗','song-poetry','','[]','述德高堂在何許，述德高人欣可睹。',160,'全唐诗/poet.song.69000.json','["述德高堂在何許，述德高人欣可睹。", "彭州夢破知幾年，遺愛遠追曾大父。", "至今民數舊邦君，毎及吳公歌且舞。", "述而行之德莫窮，定可周流浹天宇。", "誰令千里便歸休，炯炯此心元自古。", "四百六十五甲子，貌若巖松傲風雨。", "胸中何啻法界寛，普集塵沙諸佛祖。", "一如一切悉皆如，迥脱拘攣不踰矩。", "從横肉眼詎能窺，但見鼻間常栩栩。", "只應高與老人星，長現昇平瑞明主。"]'),
('3b9665c9-efe4-4a9c-bd1a-5540cc23a913','詠張公奭廬墓有芝三本','鄒浩','宋','宋诗','song-poetry','','[]','此芝初無根，生自孝誠裏。',120,'全唐诗/poet.song.69000.json','["此芝初無根，生自孝誠裏。", "孝哉本於誠，非緣利心起。", "無芝非所怍，有芝非所喜。", "不期芝有無，秀出乃如此。", "養志勤色難，送終極哀毁。", "既葬不忍歸，結廬獨留止。", "孺慕秋復春，淚接九泉水。", "比鄰或未知，天已知之矣。", "因芝示邦人，邦人争贊美。", "會逢當路賢，薦此八行始。"]'),
('fb0bf420-c80e-4998-909d-2bf26c2751c6','書公孫卷末','鄒浩','宋','宋诗','song-poetry','','[]','韓范天下賢，褒貶不妄出。',96,'全唐诗/poet.song.69000.json','["韓范天下賢，褒貶不妄出。", "舌端有春秋，所與惟其實。", "一舉十五喪，富貴所難必。", "公孫賤且貧，兹事乃能畢。", "心追古人高，迹付今人述。", "二老首形容，昭勸無終日。", "伊予特後聞，歎恨頗自失。", "東望天山平，風松正蕭瑟。"]'),
('ee9f3c52-7055-4119-9d0d-443911a37938','代書寄清老','鄒浩','宋','宋诗','song-poetry','','[]','從來遊戲常三昧，出語縱横無忌諱。',32,'全唐诗/poet.song.69000.json','["從來遊戲常三昧，出語縱横無忌諱。", "老聃全與釋迦同，人畏猶云亦當畏。"]'),
('13e5653c-eb85-47c5-84e0-59155fb79829','題雙芝軒','鄒浩','宋','宋诗','song-poetry','','[]','難弟難兄強氏子，太學聲名聳多士。',128,'全唐诗/poet.song.69000.json','["難弟難兄強氏子，太學聲名聳多士。", "同時流輩久公卿，猶傍短檠業文史。", "今年鑒拔貢辟廱，伯仲皆升從此起。", "集英春曉拱天臨，龍頭妙絕人間喜。", "鸞臺鳳閣便騰騫，况乃吾鄉有前比。", "向來胸中宇宙寛，包盡華夷無復委。", "發爲勳業助堯仁，肯令元凱常専美。", "倘如不信視雙芝，端不虚生漫黄紫。"]'),
('7b33f30a-03bd-4d11-831e-b95dd6e4a157','和路主簿思雨','鄒浩','宋','宋诗','song-poetry','','[]','造物初無欠與餘，盈虛消息自洪罏。',64,'全唐诗/poet.song.69000.json','["造物初無欠與餘，盈虛消息自洪罏。", "晴空已見雲如火，秋穫難期米似珠。", "劇邑君宜形遠慮，泮宮我亦念羣枯。", "若爲驚起蒼龍睡，賴有新詩勝大雩。"]'),
('9ec0f073-7bfd-44e3-8f5d-46581caaabf8','獨坐偶書','鄒浩','宋','宋诗','song-poetry','','[]','梧桐沐雨響玲瓏，簾幕陰陰颺晚風。',32,'全唐诗/poet.song.69000.json','["梧桐沐雨響玲瓏，簾幕陰陰颺晚風。", "講誦乍聞人語息，滿床書史興何窮。"]'),
('2516082f-7928-4b0e-aed5-2440f76203b2','寄濠州陶戶曹','鄒浩','宋','宋诗','song-poetry','','[]','臺枕長淮聳半空，登臨應得古人風。',32,'全唐诗/poet.song.69000.json','["臺枕長淮聳半空，登臨應得古人風。", "水天上下碧無際，莫獲觀魚與子同。"]'),
('d97f0931-6846-4c46-acc1-7d2eb7351868','勉畢元明','鄒浩','宋','宋诗','song-poetry','','[]','男兒數偶奇，不必苦嗟咨。',48,'全唐诗/poet.song.69000.json','["男兒數偶奇，不必苦嗟咨。", "顔子猶簞食，荘生亦布衣。", "百年容易老，萬卷卒難窺。", "致力宜爲者，騰驤自有時。"]'),
('9e0af961-abbb-4cf7-bb47-4233d0b68127','謝羅朝奉惠柏栽','鄒浩','宋','宋诗','song-poetry','','[]','惠我柏雖小，觀君意實深。',48,'全唐诗/poet.song.69000.json','["惠我柏雖小，觀君意實深。", "欲令儒服者，同此歲寒心。", "月映庭雕玉，風來韻響金。", "公車已馳節，不及待清陰。"]'),
('d4e7a0f5-7e2d-4aa3-87cb-599c7a57e0f2','和錢簽判贈胡都曹','鄒浩','宋','宋诗','song-poetry','','[]','公餘來訪習家池，楚楚王孫桂一枝。',32,'全唐诗/poet.song.69000.json','["公餘來訪習家池，楚楚王孫桂一枝。", "九十春光未過半，倒罍尤喜有前期。"]'),
('1eb28589-f87e-46bd-a63e-2521be264ad3','和路主簿喜罷役法并酬范奉議見寄','鄒浩','宋','宋诗','song-poetry','','[]','因革紛然豈用情，由來消息與時行。',64,'全唐诗/poet.song.69000.json','["因革紛然豈用情，由來消息與時行。", "奏封直指財并力，造法當期實應名。", "可使華夷漸潤澤，不煩衡石自均平。", "将明况是憂民者，即見熙熙百室盈。"]'),
('e109a51f-835c-4217-a68a-263e721672bb','酬黄秀才見寄','鄒浩','宋','宋诗','song-poetry','','[]','自期謀道不謀身，不逐輕狂戲此春。',64,'全唐诗/poet.song.69000.json','["自期謀道不謀身，不逐輕狂戲此春。", "讀史窮經求在我，攀龍附鳳彼何人。", "一言逢主未如志，百結成衣肯歎貧。", "早晚病除堪屬思，新詩莫厭起予頻。"]'),
('fffcc6c9-f693-46f4-990b-4e29654c8068','偶書','鄒浩','宋','宋诗','song-poetry','','[]','底事爰絲不自高，傾心劇孟久遊遨。',32,'全唐诗/poet.song.69000.json','["底事爰絲不自高，傾心劇孟久遊遨。", "元來緩急叩門處，狥義忘軀勝我曹。"]'),
('3161e97f-daa9-46aa-8cc2-928c0bc089dc','和郡主簿絕句九絕  其一','鄒浩','宋','宋诗','song-poetry','','[]','管鮑當年志，風霜固自如。',24,'全唐诗/poet.song.69000.json','["管鮑當年志，風霜固自如。", "信衰緣嗜慾，豈在數行書。"]'),
('b91731cf-d310-44ac-9494-e09fd92f5635','和郡主簿絕句九絕  其二','鄒浩','宋','宋诗','song-poetry','','[]','俗論長紛若，微言僅夢如。',24,'全唐诗/poet.song.69000.json','["俗論長紛若，微言僅夢如。", "逢君揮玉麈，勝讀十年書。"]'),
('70e89bce-1e89-4d96-840c-07966f5297e0','和郡主簿絕句九絕  其三','鄒浩','宋','宋诗','song-poetry','','[]','肘後虚金印，梅仙職偶如。',24,'全唐诗/poet.song.69000.json','["肘後虚金印，梅仙職偶如。", "升高元自下，功業異時書。"]'),
('6ceb5dd5-96e9-4337-b366-43b038d6704d','和郡主簿絕句九絕  其四','鄒浩','宋','宋诗','song-poetry','','[]','塞北亢喉地，并門子所如。',24,'全唐诗/poet.song.69000.json','["塞北亢喉地，并門子所如。", "六花無處用，卻縠自詩書。"]'),
('63deb800-e772-47fe-89d1-9ca7c849ea77','和郡主簿絕句九絕  其五','鄒浩','宋','宋诗','song-poetry','','[]','能詩唐太白，善賦漢相如。',24,'全唐诗/poet.song.69000.json','["能詩唐太白，善賦漢相如。", "元帥真文舉，應先薦禰書。"]'),
('15527e2c-809e-4dcf-bcc0-12f4e6277a01','和郡主簿絕句九絕  其六','鄒浩','宋','宋诗','song-poetry','','[]','取友能無怍，初終貴一如。',24,'全唐诗/poet.song.69000.json','["取友能無怍，初終貴一如。", "陳張遺轍在，試展馬遷書。"]'),
('ed57acec-7cf1-4bf6-b115-0a545a5601ae','和郡主簿絕句九絕  其七','鄒浩','宋','宋诗','song-poetry','','[]','咳唾成珠玉，吾儕孰子如。',24,'全唐诗/poet.song.69000.json','["咳唾成珠玉，吾儕孰子如。", "更勤潘氏學，豈愧樂尚書。"]'),
('f2bce861-d808-4eae-a106-d829a5459082','和郡主簿絕句九絕  其八','鄒浩','宋','宋诗','song-poetry','','[]','提履歸何處，觀花笑自如。',24,'全唐诗/poet.song.69000.json','["提履歸何處，觀花笑自如。", "期君求向上，糟粕古人書。"]'),
('4159af82-95f9-436e-be58-bed12045bc9d','和郡主簿絕句九絕  其九','鄒浩','宋','宋诗','song-poetry','','[]','春風暗楊柳，相見意何如。',24,'全唐诗/poet.song.69000.json','["春風暗楊柳，相見意何如。", "雖愧江淹筆，狂言爲子書。"]'),
('a862781a-12fe-4169-98c7-0f5af96c881e','送詩卷還參寥','鄒浩','宋','宋诗','song-poetry','','[]','盈軸新詩字字清，彌天元不愧聲名。',32,'全唐诗/poet.song.69000.json','["盈軸新詩字字清，彌天元不愧聲名。", "茂陵消渇無醫處，賴有醍醐得細傾。"]'),
('cdd05b6d-64d5-45f9-a61d-277f62a9984f','和路子高微雨中至山光寺','鄒浩','宋','宋诗','song-poetry','','[]','野闊天低四望賒，霏微膏雨兆休嘉。',64,'全唐诗/poet.song.69000.json','["野闊天低四望賒，霏微膏雨兆休嘉。", "早鐘鬰鬰穿雲斷，官柳垂垂夾道斜。", "邂逅庭前方指柏，逡巡木末已棲鴉。", "楊朱易服歸來處，荷笠收車幾萬家。"]'),
('21ad5358-6fde-4880-9eac-cf550511fff1','送監作院潘供備  其一','鄒浩','宋','宋诗','song-poetry','','[]','盟府功臣奕世孫，低回筦庫尚隨羣。',64,'全唐诗/poet.song.69000.json','["盟府功臣奕世孫，低回筦庫尚隨羣。", "干戈分職名雖武，詩酒忘懷格自文。", "傾盖二年嗟往事，贏糧一日指行雲。", "江梅欺雪南枝發，如綍新除定此聞。"]'),
('30c8120f-a52b-4502-9dd0-dd61d4d44c3a','送監作院潘供備  其二','鄒浩','宋','宋诗','song-poetry','','[]','飄飄雅致孰如君，旋闢西軒置酒樽。',64,'全唐诗/poet.song.69000.json','["飄飄雅致孰如君，旋闢西軒置酒樽。", "振木豈惟聞白雪，斷纓仍許醉黄昏。", "長亭風順已言别，小圃春迴空自繁。", "惆悵潛齋不知處，何年携手却重論。"]'),
('fe3c2fb0-5329-4ad1-845a-d5e04f394c31','簡王正父覓酒','鄒浩','宋','宋诗','song-poetry','','[]','甕面蛆浮玉，槽頭水滴珠。',24,'全唐诗/poet.song.69000.json','["甕面蛆浮玉，槽頭水滴珠。", "未能如茂世，聊與義城俱。"]'),
('daa023ef-a793-4ed9-aba5-077ab1045d05','寄周彦亷','鄒浩','宋','宋诗','song-poetry','','[]','楚水不風魚逝遠，霜天初月鴈飛高。',32,'全唐诗/poet.song.69000.json','["楚水不風魚逝遠，霜天初月鴈飛高。", "履穿袍敝渾無暇，目斷心馳祗自勞。"]'),
('8dc494d7-0267-4294-aa58-b586b16a1ad6','和劉知錄見寄并簡陽先生','鄒浩','宋','宋诗','song-poetry','','[]','劉郎爽氣曉霜晴，陽子高懷寶鑑明。',64,'全唐诗/poet.song.69000.json','["劉郎爽氣曉霜晴，陽子高懷寶鑑明。", "雖幸竹林容入會，每慚布鼓獨無聲。", "一杯葵藿真佳趣，五鼎牛羊謾宰生。", "廊廟他年調爕手，不妨潛室且和羮。"]'),
('480e8025-316f-4249-866b-5c8401fd15d5','和陽先生見贈','鄒浩','宋','宋诗','song-poetry','','[]','萬卷藏書肯自閒，沉涵聖道欲晞顔。',64,'全唐诗/poet.song.69000.json','["萬卷藏書肯自閒，沉涵聖道欲晞顔。", "片心既與人寰遠，逸駕寧容俗士攀。", "嗟我曳裾膠擾處，荷君置榻寂寥間。", "藜羮玉麈清何限，每到斜陽不忍還。"]'),
('969bf9a2-fb9d-4473-9f3a-cb1f420ffbaf','求劉知錄澄泥香爐','鄒浩','宋','宋诗','song-poetry','','[]','千卷新書三叠琴，青燈炯炯夜沉沉。',32,'全唐诗/poet.song.69000.json','["千卷新書三叠琴，青燈炯炯夜沉沉。", "野人此外無餘好，只欠澄泥一炷深。"]'),
('6734d1e3-4301-4578-a7d0-29eb48fdbf90','大雨中接憲使因成小詩呈陽先生','鄒浩','宋','宋诗','song-poetry','','[]','霜風折木雨如傾，歛板泥中厮役并。',32,'全唐诗/poet.song.69000.json','["霜風折木雨如傾，歛板泥中厮役并。", "遙想先生鼓琴罷，觀書正傍短燈檠。"]'),
('5c9844dc-bd93-45f9-bd8d-fb0be67e85b3','次韻盛長官覓酒','鄒浩','宋','宋诗','song-poetry','','[]','九萬鵬程戢怒飛，驅愁却歎酒無威。',32,'全唐诗/poet.song.69000.json','["九萬鵬程戢怒飛，驅愁却歎酒無威。", "頖宮官冷非文舉，一斗何能醉十圍。"]'),
('e483c90b-ced7-4ac7-9afe-6afbf4c23b18','次韻胡秀才遺桃花','鄒浩','宋','宋诗','song-poetry','','[]','灼灼桃源數朵紅，青禽傳到蓽門中。',64,'全唐诗/poet.song.69000.json','["灼灼桃源數朵紅，青禽傳到蓽門中。", "傍人只喜窺春色，達士元來寄祖風。", "謾說幾經千歲賞，會須一笑萬緣空。", "沉香散處圓蒲穩，花自蕃鮮體自同。"]'),
('a302ef1c-be17-455c-866c-820fe3b15c5e','次韻俞秀老建隆道中','鄒浩','宋','宋诗','song-poetry','','[]','道人不獨是詩豪，曾把滄溟注一毛。',32,'全唐诗/poet.song.69000.json','["道人不獨是詩豪，曾把滄溟注一毛。", "破曉聯鑣訪孤寂，致身如在太山高。"]'),
('ef7c4c6e-0682-445b-b2a2-e9e2a7da895d','次韻慕公實','鄒浩','宋','宋诗','song-poetry','','[]','從來文史足三冬，何事明時作退翁。',64,'全唐诗/poet.song.69000.json','["從來文史足三冬，何事明時作退翁。", "刺口豈能論擾擾，冥心直欲似空空。", "半軒蒼莽雨初霽，一釣清泠月正朧。", "好把晨昏付香火，箇中真樂更無窮。"]'),
('e4ad21fc-acba-4bb7-9315-2bac1932a35d','次韻錢𡵒雪中','鄒浩','宋','宋诗','song-poetry','','[]','六出飛瓊玖，雲愁正臘天。',48,'全唐诗/poet.song.69000.json','["六出飛瓊玖，雲愁正臘天。", "寒聲生密竹，爽氣徹純綿。", "故苑風初静，重樓月向圓。", "何當酬此景，蘸甲引金船。"]'),
('db6625ce-2c93-454f-a149-203878053025','次韻王賢良贈陽先生  其一','鄒浩','宋','宋诗','song-poetry','','[]','脩塗幾閲歲終窮，鶴唳猿啼蕙帳空。',32,'全唐诗/poet.song.69000.json','["脩塗幾閲歲終窮，鶴唳猿啼蕙帳空。", "杖屨何當歸舊隱，静看五柳颺春風。"]'),
('5a7f2cfc-4faf-4052-afb9-f3c4667c9a32','次韻王賢良贈陽先生  其二','鄒浩','宋','宋诗','song-poetry','','[]','囂囂所樂本非窮，曾向真乘悟色空。',32,'全唐诗/poet.song.69000.json','["囂囂所樂本非窮，曾向真乘悟色空。", "聞說近添方外友，清談應得晋人風。"]'),
('4f3d6a30-c6ff-487b-821b-8c9eef258c6c','二月十五日朝拜建隆橋上偶作','鄒浩','宋','宋诗','song-poetry','','[]','單衣迎犯曉風清，斗柄回南月尚明。',32,'全唐诗/poet.song.69000.json','["單衣迎犯曉風清，斗柄回南月尚明。", "柳密行人看不見，輪蹄相屬但聞聲。"]'),
('949c0f6f-f63d-4b5f-98bb-b4d013b8e1ce','清明日遊大明道中','鄒浩','宋','宋诗','song-poetry','','[]','春風蕩漾遍天涯，縱步郊原事事嘉。',32,'全唐诗/poet.song.69000.json','["春風蕩漾遍天涯，縱步郊原事事嘉。", "不許遊人同所得，竹林深處試龍茶。"]');
